  function toggleSeriesCustomInterval() {
    var val = document.querySelector('input[name="series-interval"]:checked').value;
    document.getElementById('series-custom-interval-wrap').style.display = val === 'custom' ? 'flex' : 'none';
  }

  function updateSeriesPreview() {
    clearTimeout(_seriesPreviewDebounce);
    _seriesPreviewDebounce = setTimeout(_renderSeriesPreview, 100);
  }

  function _generateSeriesDates(startDate, count, interval, customDays) {
    var dates = [];
    var cur = new Date(startDate + 'T00:00:00');
    for (var i = 0; i < count; i++) {
      if (interval === 'weekday') {
        while (cur.getDay() === 0 || cur.getDay() === 6) cur.setDate(cur.getDate() + 1);
      }
      var ds = cur.getFullYear() + '-' + String(cur.getMonth()+1).padStart(2,'0') + '-' + String(cur.getDate()).padStart(2,'0');
      dates.push({ date: ds, dayOfWeek: cur.getDay() });
      if (interval === 'daily') {
        cur.setDate(cur.getDate() + 1);
      } else if (interval === 'weekday') {
        cur.setDate(cur.getDate() + 1);
      } else if (interval === 'custom') {
        cur.setDate(cur.getDate() + (customDays || 1));
      }
    }
    return dates;
  }

  function _renderSeriesPreview() {
    var startEp = parseInt(document.getElementById('series-start-ep').value) || 1;
    var endEp = parseInt(document.getElementById('series-end-ep').value) || 1;
    var startDate = document.getElementById('series-start-date').value;
    var seriesType = document.querySelector('input[name="series-type"]:checked').value;
    var interval = document.querySelector('input[name="series-interval"]:checked').value;
    var customDays = parseInt(document.getElementById('series-custom-days').value) || 1;

    var validationEl = document.getElementById('series-validation-msg');
    var saveBtn = document.getElementById('series-save-btn');
    var saveLabel = document.getElementById('series-save-label');
    var previewList = document.getElementById('series-preview-list');
    var previewCount = document.getElementById('series-preview-count');

    // Validation
    if (!startDate) {
      validationEl.textContent = '시작 날짜를 선택해주세요.';
      validationEl.style.display = 'block';
      saveBtn.disabled = true;
      previewList.innerHTML = '<div class="text-xs text-slate-400 text-center py-6">시작 날짜를 선택해주세요</div>';
      previewCount.textContent = '';
      return;
    }
    if (startEp > endEp) {
      validationEl.textContent = '시작 화가 끝 화보다 클 수 없어요.';
      validationEl.style.display = 'block';
      saveBtn.disabled = true;
      previewList.innerHTML = '<div class="text-xs text-slate-400 text-center py-6">시작 화 ≤ 끝 화</div>';
      previewCount.textContent = '';
      return;
    }
    var totalCount = endEp - startEp + 1;
    if (totalCount > 500) {
      validationEl.textContent = '최대 500개까지 가능해요. (현재 ' + totalCount + '개)';
      validationEl.style.display = 'block';
      saveBtn.disabled = true;
      previewList.innerHTML = '<div class="text-xs text-red-400 text-center py-6">최대 500개 제한 초과</div>';
      previewCount.textContent = totalCount + '개';
      return;
    }
    if (interval === 'custom' && customDays < 1) {
      validationEl.textContent = '간격은 1일 이상이어야 해요.';
      validationEl.style.display = 'block';
      saveBtn.disabled = true;
      return;
    }
    validationEl.style.display = 'none';

    var dates = _generateSeriesDates(startDate, totalCount, interval, customDays);
    var holidays = {};
    var yearsNeeded = {};
    dates.forEach(function(d) { yearsNeeded[d.date.substring(0, 4)] = true; });
    Object.keys(yearsNeeded).forEach(function(y) {
      var h = getKoreanHolidays(parseInt(y));
      Object.keys(h).forEach(function(k) { holidays[k] = h[k]; });
    });

    var dayNames = ['일','월','화','수','목','금','토'];
    var html = '';
    for (var i = 0; i < dates.length; i++) {
      var ep = startEp + i;
      var title = seriesType === 'draft' ? (ep + '화') : (ep + '화 퇴고');
      var d = dates[i];
      var isWeekend = d.dayOfWeek === 0 || d.dayOfWeek === 6;
      var holidayName = holidays[d.date] || '';
      var dayName = dayNames[d.dayOfWeek];

      var rowClass = 'px-4 py-2 text-xs border-b border-slate-100 flex items-center justify-between';
      if (isWeekend) rowClass += ' bg-red-50';
      else if (holidayName) rowClass += ' bg-orange-50';

      var dateLabel = d.date + ' (' + dayName + ')';
      var extra = '';
      if (isWeekend) extra = '<span class="text-red-400 font-bold">' + (d.dayOfWeek === 0 ? '일' : '토') + '</span>';
      if (holidayName) extra = '<span class="text-orange-500 font-bold flex items-center gap-0.5"><span style="font-size: var(--font-size-micro)">&#x1F6A9;</span> ' + holidayName + '</span>';

      html += '<div class="' + rowClass + '">';
      html += '<span class="font-medium text-slate-600">' + dateLabel + ' — <strong class="text-slate-800">' + title + '</strong></span>';
      if (extra) html += extra;
      html += '</div>';
    }

    previewList.innerHTML = html || '<div class="text-xs text-slate-400 text-center py-6">항목 없음</div>';
    previewCount.textContent = '총 ' + totalCount + '개 항목';
    saveBtn.disabled = false;
    saveLabel.textContent = totalCount + '개 일정 추가';
  }

  async function saveSeriesEntries() {
    var btn = document.getElementById('series-save-btn');
    var saveLabel = document.getElementById('series-save-label');
    btn.disabled = true;
    saveLabel.textContent = '저장 중...';

    var startEp = parseInt(document.getElementById('series-start-ep').value) || 1;
    var endEp = parseInt(document.getElementById('series-end-ep').value) || 1;
    var startDate = document.getElementById('series-start-date').value;
    var seriesType = document.querySelector('input[name="series-type"]:checked').value;
    var interval = document.querySelector('input[name="series-interval"]:checked').value;
    var customDays = parseInt(document.getElementById('series-custom-days').value) || 1;
    var category = document.getElementById('series-category').value;

    var totalCount = endEp - startEp + 1;
    if (totalCount < 1 || totalCount > 500 || !startDate) {
      saveLabel.textContent = '입력값 오류';
      btn.disabled = false;
      return;
    }

    var dates = _generateSeriesDates(startDate, totalCount, interval, customDays);
    var seriesId = 'series_' + startDate.replace(/-/g, '') + '_' + Math.random().toString(36).substring(2, 8);
    var color = CAT_COLOR[category] || 'sky';
    var seriesInfo = {
      type: seriesType,
      startEpisode: startEp,
      endEpisode: endEp,
      totalCount: totalCount,
      interval: interval,
      intervalDays: interval === 'custom' ? customDays : 1
    };

    try {
      var batch = db.batch();
      var newRows = [];

      for (var i = 0; i < dates.length; i++) {
        var ep = startEp + i;
        var title = seriesType === 'draft' ? (ep + '화') : (ep + '화 퇴고');
        var row = [dates[i].date, title, category, color, '', '', ''];
        var obj = rowToObj('planner', row);
        obj.seriesId = seriesId;
        obj.seriesInfo = seriesInfo;
        obj._createdAt = firebase.firestore.FieldValue.serverTimestamp();

        var ref = db.collection('planner').doc();
        batch.set(ref, obj);
        newRows.push({ row: row, ref: ref });
      }

      await batch.commit();

      // Add to in-memory plannerData
      for (var j = 0; j < newRows.length; j++) {
        var r = newRows[j].row.concat([newRows[j].ref.id]);
        plannerData.push(r);
        // Sync to matrix
        try { await syncPlannerToMatrix(newRows[j].row); } catch(e) {}
      }

      renderCalendar();
      updatePlannerTracks();
      try { renderMatrixTable(); updateLeaveTracker(); } catch(e) {}
      closeSeriesModal();
      showPlannerToast('시리즈 ' + totalCount + '개 항목 추가 완료!');
    } catch(err) {
      console.error('Series save error:', err);
      alert('시리즈 저장에 실패했어요. 다시 시도해주세요.\n' + err.message);
    } finally {
      btn.disabled = false;
      saveLabel.textContent = '일정 추가';
    }
  }

