  async function saveScheduleInline() {
    var div = document.querySelector('.schedule-inline-add');
    if (!div) return;
    var time = document.getElementById('sched-add-time').value.trim();
    var endTime = document.getElementById('sched-add-end-time').value.trim();
    var title = document.getElementById('sched-add-title').value.trim();
    var desc = document.getElementById('sched-add-desc').value.trim();
    var cityInputEl = document.getElementById('sched-add-city');
    var cityInput = cityInputEl ? cityInputEl.value.trim() : '';
    if (!title) { alert('일정 제목을 입력해줘!'); return; }
    // city: 사용자가 입력했으면 그 값(당일치기), 아니면 숙박 도시 기본값
    var cityFinal = cityInput || div.dataset.city || '';
    var resChk = document.getElementById('sched-add-reserve');
    var indChk = document.getElementById('sched-add-indoor');
    var clsInp = document.getElementById('sched-add-closed');
    var obj = { trip_id: currentTripId, type:'일정', date:div.dataset.date, time:time, end_time:endTime, city:cityFinal, title:title, description:desc,
      reservation: !!(resChk && resChk.checked), indoor: !!(indChk && indChk.checked), closed: (clsInp && clsInp.value.trim()) || '' };
    applyPickedCoords(obj, document.getElementById('sched-add-title')); // ★ 자동완성 좌표
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      div.remove();
      renderDayView();
    } catch(e) { alert('저장 실패'); }
  }

  // ===== SUNRISE/SUNSET 자동 추가 =====
  var _sunAttempt = {};
  async function autoAddSunriseSunset(cityName, dateStr) {
    if (!cityName || !dateStr || !currentTripId) return;
    var key = currentTripId + ':' + cityName + ':' + dateStr;
    if (_sunAttempt[key]) return;
    _sunAttempt[key] = true;

    var existing = journeyData.filter(function(d){
      return d.type==='일정' && d.date===dateStr && d.trip_id===currentTripId;
    });
    var hasSunrise = existing.some(function(d){
      var t = (d.title||'').toUpperCase();
      return t.indexOf('SUNRISE')>=0 || (d.title||'').indexOf('일출')>=0 || d.auto_sun==='sunrise';
    });
    var hasSunset = existing.some(function(d){
      var t = (d.title||'').toUpperCase();
      return t.indexOf('SUNSET')>=0 || (d.title||'').indexOf('일몰')>=0 || d.auto_sun==='sunset';
    });
    if (hasSunrise && hasSunset) return;

    var geo = await geocodeCity(cityName);
    if (!geo) { console.warn('[sun] geocode failed:', cityName); return; }

    try {
      // 16일 이내는 forecast, 그 이상은 archive(작년 같은 날짜)로 fallback
      var today = new Date();
      var target = new Date(dateStr + 'T00:00:00');
      var diffDays = Math.round((target - today) / (1000*60*60*24));
      var fetchDate = dateStr;
      var url;
      if (diffDays >= -2 && diffDays <= 15) {
        url = 'https://api.open-meteo.com/v1/forecast?latitude=' + geo.lat + '&longitude=' + geo.lng +
          '&daily=sunrise,sunset&timezone=auto&start_date=' + dateStr + '&end_date=' + dateStr;
      } else if (diffDays < -2) {
        url = 'https://archive-api.open-meteo.com/v1/archive?latitude=' + geo.lat + '&longitude=' + geo.lng +
          '&daily=sunrise,sunset&timezone=auto&start_date=' + dateStr + '&end_date=' + dateStr;
      } else {
        // 미래(16일 이후): 작년 같은 날짜 사용
        var ly = new Date(target); ly.setFullYear(ly.getFullYear() - 1);
        fetchDate = ly.getFullYear()+'-'+String(ly.getMonth()+1).padStart(2,'0')+'-'+String(ly.getDate()).padStart(2,'0');
        url = 'https://archive-api.open-meteo.com/v1/archive?latitude=' + geo.lat + '&longitude=' + geo.lng +
          '&daily=sunrise,sunset&timezone=auto&start_date=' + fetchDate + '&end_date=' + fetchDate;
      }
      var res = await fetch(url);
      var data = await res.json();
      if (!data.daily || !data.daily.sunrise || !data.daily.sunrise[0]) {
        console.warn('[sun] no data for', cityName, dateStr, 'fetchDate=', fetchDate, data);
        return;
      }
      var srTime = (data.daily.sunrise[0].split('T')[1] || '').substring(0,5);
      var ssTime = (data.daily.sunset[0].split('T')[1] || '').substring(0,5);
      console.log('[sun]', cityName, dateStr, '→', srTime, '/', ssTime);

      var added = false;
      if (!hasSunrise && srTime) {
        var srObj = { trip_id: currentTripId, type:'일정', date: dateStr, time: srTime, city: cityName, title:'🌄 일출 (Sunrise)', description:'', auto_sun:'sunrise' };
        var srSaved = await fbAdd('journey', srObj);
        journeyData.push(srSaved);
        added = true;
      }
      if (!hasSunset && ssTime) {
        var ssObj = { trip_id: currentTripId, type:'일정', date: dateStr, time: ssTime, city: cityName, title:'🌇 일몰 (Sunset)', description:'', auto_sun:'sunset' };
        var ssSaved = await fbAdd('journey', ssObj);
        journeyData.push(ssSaved);
        added = true;
      }
      if (added) {
        // 현재 보고 있는 날짜라면 다시 렌더
        var dayMap = getDayMap();
        var cur = dayMap[currentDayIndex];
        if (cur && cur.date === dateStr) renderDayView();
      }
    } catch(e) { console.warn('Sunrise/sunset failed:', e); }
  }

