  // ===== 숙소명 Google Places Autocomplete =====
  var _stayAutocomplete = null;
  function initStayPlacesAutocomplete() {
    var input = document.getElementById('stay-name');
    if (!input || typeof google === 'undefined' || typeof google.maps === 'undefined' || typeof google.maps.places === 'undefined') return;
    if (_stayAutocomplete) { try { google.maps.event.clearInstanceListeners(_stayAutocomplete); } catch(e){} _stayAutocomplete = null; }
    _stayAutocomplete = new google.maps.places.Autocomplete(input, {
      types: ['lodging'],
      fields: ['name', 'formatted_address', 'formatted_phone_number', 'international_phone_number', 'address_components'],
    });
    _stayAutocomplete.addListener('place_changed', function() {
      var place = _stayAutocomplete.getPlace();
      console.log('[Stay Places] Selected:', place);
      if (!place) return;
      // 숙소명
      if (place.name) input.value = place.name;
      // 주소
      var addrEl = document.getElementById('stay-address');
      if (addrEl && place.formatted_address) addrEl.value = place.formatted_address;
      // 전화번호
      var phoneEl = document.getElementById('stay-phone');
      if (phoneEl) {
        var phone = place.formatted_phone_number || place.international_phone_number || '';
        if (phone) phoneEl.value = phone;
      }
      // 도시 추출
      var cityEl = document.getElementById('stay-city');
      if (cityEl && place.address_components) {
        var cityName = '';
        for (var i = 0; i < place.address_components.length; i++) {
          var comp = place.address_components[i];
          if (comp.types.indexOf('locality') >= 0) { cityName = comp.long_name; break; }
          if (comp.types.indexOf('administrative_area_level_1') >= 0 && !cityName) { cityName = comp.long_name; }
        }
        if (cityName) cityEl.value = cityName;
      }
    });
    setTimeout(function(){ var pacs = document.querySelectorAll('.pac-container'); pacs.forEach(function(p){ p.style.zIndex = '99999'; }); }, 300);
  }
  // 페이지 로드 후 초기화 (여행 페이지 진입 시)
  setTimeout(initStayPlacesAutocomplete, 500);

