    if (dl) dl.innerHTML = (citiesData||[]).map(function(c){ return '<option value="'+c.name+'">'; }).join('');

    // 필드 채우기
    var setV = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || ''; };
    setV('stay-edit-city', item.city);
    setV('stay-edit-name', item.title);
    setV('stay-edit-address', item.address);
    setV('stay-edit-phone', item.phone);
