  async function saveStayEdit() {
    if (_stayEditIdx === null) return;
    var item = journeyData[_stayEditIdx];
    if (!item) return;
    var name = document.getElementById('stay-edit-name').value.trim();
    if (!name) { alert('숙소명을 입력해주세요'); return; }
    var updates = {
      city: document.getElementById('stay-edit-city').value.trim(),
      title: name,
      address: document.getElementById('stay-edit-address').value.trim(),
      phone: document.getElementById('stay-edit-phone').value.trim(),
      payment_date: document.getElementById('stay-edit-payment-date').value,
      date: document.getElementById('stay-edit-checkin-date').value,
      checkout_date: document.getElementById('stay-edit-checkout-date').value,
      checkin: document.getElementById('stay-edit-checkin-time').value.trim(),
      checkout: document.getElementById('stay-edit-checkout-time').value.trim(),
      cancel: _stayEditCancel,
      cancel_date: document.getElementById('stay-edit-cancel-date').value,
      amount: document.getElementById('stay-edit-price').value.replace(/,/g,''),
      notes: (document.getElementById('stay-edit-notes')||{}).value || '',
      // ★ (2026-07-23) 객실/조식/인원 — 카드 메타 행에 표시되는 additive 필드
      room_type: ((document.getElementById('stay-edit-room-type')||{}).value || '').trim(),
      breakfast: ((document.getElementById('stay-edit-breakfast')||{}).value || '').trim(),
      guests: ((document.getElementById('stay-edit-guests')||{}).value || '').trim(),
      payment_status: _stayEditPayStatus || '',
      description: _stayEditType === 'Airbnb' ? 'Airbnb' : ''
    };
    try {
      await fbUpdate('journey', item._id, updates);
      Object.assign(journeyData[_stayEditIdx], updates);
      await syncJourneyToFinance(journeyData[_stayEditIdx]);
      closeTravelModal('stay-edit-modal-wrap');
      renderJourneyLodging();
      updateJourneyCost();
      updateTravelMiniSummary();
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 숙소 수정 완료');
    } catch(e) { alert('저장 실패: ' + e.message); }
  }

