  // localStorage 기반 기념품 관리
  var LS_SOUVENIR_KEY = 'atelier_souvenirs';

  function getSouvenirData() {
    var stored = localStorage.getItem(LS_SOUVENIR_KEY);
    if (stored) return JSON.parse(stored);
    // 최초: 기본값 복사
    var data = SOUVENIR_DEFAULTS.map(function(d, i) {
      return { id: 'sv_' + i, title: d.title, description: d.description, city: d.city, amount: d.amount, checked: false };
    });
    localStorage.setItem(LS_SOUVENIR_KEY, JSON.stringify(data));
    return data;
  }

  function saveSouvenirData(data) {
    localStorage.setItem(LS_SOUVENIR_KEY, JSON.stringify(data));
  }

  function toggleSouvenirLocal(idx) {
    var data = getSouvenirData();
    data[idx].checked = !data[idx].checked;
    saveSouvenirData(data);
    renderJourneySouvenir();
  }

  function deleteSouvenirLocal(idx) {
    if (!confirm('이 기념품을 삭제할까요?')) return;
    var data = getSouvenirData();
    data.splice(idx, 1);
    saveSouvenirData(data);
    renderJourneySouvenir();
  }

  function souvenirInlineEdit(td, idx, field) {
    inlineEditTd(td, function(val) {
      var data = getSouvenirData();
      data[idx][field] = val;
      saveSouvenirData(data);
      renderJourneySouvenir();
    });
  }

  var _editSouvenirIdx = null;

  function openSouvenirEditModal(idx) {
    _editSouvenirIdx = idx;
    var data = getSouvenirData();
    var item = data[idx];
    document.getElementById('sv-edit-title').value = item.title;
    document.getElementById('sv-edit-desc').value = item.description;
    document.getElementById('sv-edit-city').value = item.city;
    document.getElementById('sv-edit-amount').value = item.amount;
    document.getElementById('souvenir-edit-modal').style.cssText = 'display:flex!important';
  }

  function closeSouvenirEditModal() {
    document.getElementById('souvenir-edit-modal').style.cssText = 'display:none!important';
    _editSouvenirIdx = null;
  }

  function saveSouvenirEdit() {
    if (_editSouvenirIdx === null) return;
    var data = getSouvenirData();
    data[_editSouvenirIdx].title = document.getElementById('sv-edit-title').value.trim();
    data[_editSouvenirIdx].description = document.getElementById('sv-edit-desc').value.trim();
    data[_editSouvenirIdx].city = document.getElementById('sv-edit-city').value.trim();
    data[_editSouvenirIdx].amount = document.getElementById('sv-edit-amount').value.trim();
    saveSouvenirData(data);
    closeSouvenirEditModal();
    renderJourneySouvenir();
  }

  async function seedTripDefaults() {
    if (!currentTripId) return;
    var trip = tripsData.find(function(t){ return t._id === currentTripId; });
    if (!isSeedTrip()) return;

    // 도시 시드
    if (citiesData.length === 0) {
      for (var i = 0; i < CITY_DEFAULTS.length; i++) {
        var c = CITY_DEFAULTS[i];
        var nights = Math.max(0, Math.round((new Date(c.end_date) - new Date(c.start_date)) / (1000*60*60*24)));
        var obj = { trip_id: currentTripId, name: c.name, start_date: c.start_date, end_date: c.end_date, nights: nights, desc: c.desc, order: c.start_date };
        var saved = await fbAdd('trip_cities', obj);
        citiesData.push(saved);
      }
      citiesData.sort(function(a,b){ return (a.start_date||'').localeCompare(b.start_date||''); });
      saveCityCache(currentTripId, citiesData);
    } else {
      // 기존 도시에 날짜/설명 없으면 CITY_DEFAULTS에서 백필
      citiesData.forEach(function(city) {
        var def = CITY_DEFAULTS.find(function(d){ return d.name === city.name; });
        if (!def) return;
        var updates = {};
        if (!city.start_date && def.start_date) { city.start_date = def.start_date; updates.start_date = def.start_date; }
        if (!city.end_date && def.end_date) { city.end_date = def.end_date; updates.end_date = def.end_date; }
        if (!city.desc && def.desc) { city.desc = def.desc; updates.desc = def.desc; }
        if (!city.nights && def.start_date && def.end_date) {
          city.nights = Math.max(0, Math.round((new Date(def.end_date) - new Date(def.start_date)) / (1000*60*60*24)));
          updates.nights = city.nights;
        }
        if (Object.keys(updates).length > 0 && city._id) {
          fbUpdate('trip_cities', city._id, updates).catch(function(){});
        }
      });
      saveCityCache(currentTripId, citiesData);
    }

    // 일정 시드
    var schedules = journeyData.filter(function(d){ return d.type === '일정'; });
    if (schedules.length === 0) {
      for (var j = 0; j < SCHEDULE_DEFAULTS.length; j++) {
        var s = SCHEDULE_DEFAULTS[j];
        var obj2 = { trip_id: currentTripId, type: '일정', date: s.date, time: s.time, city: s.city, title: s.title, description: s.description || '' };
        var saved2 = await fbAdd('journey', obj2);
        journeyData.push(saved2);
      }
    }

  }

