  async function saveFixedRow(el, type) {
    var tr = el.closest('tr');
    var obj = { trip_id: currentTripId, type: type };
    var hasValue = false;
    tr.querySelectorAll('[data-f]').forEach(function(inp) {
      var key = inp.dataset.f;
      if (key === 'type') return;
      if (key === 'lodge_type') { obj.address = inp.value; return; }
      var v = inp.value||'';
      if (v) hasValue = true;
      obj[key] = v;
    });
    if (!hasValue) return;
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      if (type==='항공편') renderJourneyFlights();
      else if (type==='숙소') renderJourneyLodging();
      else if (type==='이동수단') { renderJourneyTransport(); renderDayView(); }
      else if (type==='기념품') renderJourneySouvenir();
      updateJourneyCost();
    } catch(e) { alert('저장에 실패했어요.'); }
  }

