  function airlineIataFor(name, flightNum) {
    var s = String(name || '').toLowerCase().trim();
    if (s) {
      // 우선 정확히 일치, 그다음 포함 검사
      if (AIRLINE_IATA[s]) return AIRLINE_IATA[s];
      for (var k in AIRLINE_IATA) {
        if (s.indexOf(k) >= 0) return AIRLINE_IATA[k];
      }
    }
    // fallback: 편명 2글자 prefix (TW403 → TW)
    var fn = String(flightNum || '').toUpperCase();
    var m2 = fn.match(/^([A-Z]{2})\d/);
    if (m2) return m2[1];
    return '';
  }
  function airlineLogoHTML(name, flightNum) {
    var iata = airlineIataFor(name, flightNum);
    if (!iata) return '<span class="material-symbols-outlined">flight_takeoff</span>';
    var url = 'https://www.gstatic.com/flights/airline_logos/70px/' + iata + '.png';
    // 로드 실패 시 비행기 아이콘으로 폴백
    return '<img src="' + url + '" alt="' + (name||iata) + '" style="width:38px;height:38px;object-fit:contain;border-radius: var(--radius-sm);background:#fff" onerror="this.outerHTML=\'<span class=\\\'material-symbols-outlined\\\'>flight_takeoff</span>\'"/>';
  }

  function flightCard(f, deleteHtml) {
    var routeParts = (f.route||f.description||'').split('→').map(function(s){return s.trim();});
    var depCode = routeParts[0] ? routeParts[0].match(/\(([A-Z]{3})\)/)||[] : [];
    var arrCode = routeParts[1] ? routeParts[1].match(/\(([A-Z]{3})\)/)||[] : [];
    var depIata = depCode[1]||routeParts[0]||'';
    var arrIata = arrCode[1]||routeParts[1]||'';
    var code = f.flight || f.city || '';
    var airline = f.airline || f.title || '';
    var isPast = !!(f.date && /^\d{4}-\d{2}-\d{2}$/.test(f.date) && f.date < new Date().toISOString().split('T')[0]);
    var actionsSt = String(deleteHtml || '')
      .replace(/class="p-2 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors text-slate-600"/g, 'class="rec-abtn"')
      .replace(/class="p-2 rounded-xl bg-slate-50 hover:bg-rose-100 transition-colors text-slate-400 hover:text-rose-500"/g, 'class="rec-abtn danger"')
      .replace(/text-xl/g, '');
    var seatLabel = '';
    if (f.seat_class) seatLabel = f.seat_class;
    if (f.seat_number) seatLabel = (seatLabel ? seatLabel + ' · ' : '') + f.seat_number;
    // 하단 3열 그리드 — 있는 필드만
    var cells = [];
    var cell = function(l, v, accent) {
      return '<div><p class="rec-micro">' + l + '</p><p class="rec-fl-foot-v' + (accent ? ' is-accent' : '') + '">' + v + '</p></div>';
    };
    if (airline && airline !== code) cells.push(cell('Airline', airline));
    if (f.passenger) cells.push(cell('Passenger', f.passenger));
    if (seatLabel) cells.push(cell('Seat', seatLabel));
    if (f.pnr) cells.push(cell('PNR', f.pnr, true));
    if (f.fare_type) cells.push(cell('Fare', f.fare_type));
    if (f.baggage) cells.push(cell('Baggage', f.baggage));
    // 결제 상태 — payment_date 기준 파생 (예산 장부와 동일 규칙).
    // 파생 문구에 이미 날짜가 들어간 '결제 예정 (MM/DD)'이면 날짜를 또 붙이지 않는다
    var fPay = _trvPayStatus(f);
    var fPayDate = (f.payment_date && fPay.indexOf('(') < 0) ? ' · ' + f.payment_date : '';
    if (fPay || f.payment_date) cells.push(cell('Payment', fPay + fPayDate));
    if (f.price && f.price !== '—') cells.push(cell('Price', _trvAmtHtml(f.price)));
    // ★ (2026-07-23) 다크 헤더 좌측 항공사 로고 — 실패 시 기존 아이콘+편명 레이아웃 그대로
    var flLogo = _airlineLogoHtml(_airlineIata(f));
    return '<div class="rec-fl-card' + (isPast ? ' is-past' : '') + '">' +
      '<div class="rec-fl-head">' +
        flLogo +
        '<span class="rec-fl-code">' + (code || airline || '—') + '</span>' +
        '<span class="material-symbols-outlined rec-fl-headico">flight</span>' +
        '<span class="rec-fl-route">' + depIata + (arrIata ? ' → ' + arrIata : '') + '</span>' +
        (actionsSt ? '<div class="rec-actions">' + actionsSt + '</div>' : '') +
      '</div>' +
      '<div class="rec-fl-body">' +
        '<div class="rec-fl-leg">' +
          '<p class="rec-micro">Departure</p>' +
          '<p class="rec-fl-time">' + (f.depart || f.time || '—') + '</p>' +
          '<p class="rec-fl-date">' + (f.date || '') + '</p>' +
        '</div>' +
        '<div class="rec-fl-mid">' +
          '<div class="rec-fl-mid-line"><span class="material-symbols-outlined">flight</span></div>' +
          (f.duration ? '<p class="rec-fl-mid-dur">' + f.duration + '</p>' : '') +
        '</div>' +
        '<div class="rec-fl-leg is-arr">' +
          '<p class="rec-micro">Arrival</p>' +
          '<p class="rec-fl-time">' + (f.arrive || '—') + '</p>' +
          '<p class="rec-fl-date">&nbsp;</p>' +
        '</div>' +
      '</div>' +
      (cells.length ? '<div class="rec-fl-foot">' + cells.join('') + '</div>' : '') +
      (typeof window.trvAttachRowHtml === 'function' ? window.trvAttachRowHtml(f) : '') +
    '</div>';
  }

  // 시드 데이터를 Firebase로 마이그레이션 후 수정/삭제
  async function migrateSeedAndEdit(type, seedIdx) {
    var defaults = type === '항공편' ? FLIGHT_DEFAULTS : TRANSPORT_DEFAULTS;
    var d = defaults[seedIdx];
    if (!d) return;
    var obj = { trip_id: currentTripId, type: type };
    if (type === '항공편') {
      obj.title = d.airline||d.flight; obj.description = d.route; obj.city = d.flight;
      obj.date = d.date; obj.time = d.depart; obj.arrive = d.arrive;
      obj.duration = d.duration; obj.baggage = d.baggage; obj.amount = String(d.priceKRW||'');
    } else {
      obj.title = d.title; obj.description = d.description; obj.date = d.date;
      obj.time = d.time; obj.arrive = d.arrive; obj.amount = d.amount; obj.status = d.status;
    }
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      var realIdx = journeyData.length - 1;
      editJourneyItem(realIdx);
      if (type === '항공편') renderJourneyFlights(); else renderJourneyTransport();
    } catch(e) { alert('오류 발생'); }
  }

  async function migrateSeedAndDelete(type, seedIdx) {
    var defaults = type === '항공편' ? FLIGHT_DEFAULTS : TRANSPORT_DEFAULTS;
    var d = defaults[seedIdx];
    if (!d) return;
    // Firebase에 같은 항목이 있으면 삭제, 없으면 시드 배열에서 제거 (UI만)
    var obj = { trip_id: currentTripId, type: type };
    if (type === '항공편') {
      obj.title = d.airline||d.flight; obj.description = d.route; obj.city = d.flight;
      obj.date = d.date; obj.time = d.depart; obj.amount = String(d.priceKRW||'');
    } else {
      obj.title = d.title; obj.description = d.description; obj.date = d.date;
      obj.time = d.time; obj.amount = d.amount;
    }
    // Firebase에 복사 후 즉시 삭제 (시드에서 제거 효과)
    try {
      var saved = await fbAdd('journey', obj);
      await fbDelete('journey', saved._id);
      // 시드 defaults에서 마킹 (fbKeys에 추가되어 렌더링 시 제외)
      if (type === '항공편') { defaults[seedIdx]._deleted = true; renderJourneyFlights(); }
      else { defaults[seedIdx]._deleted = true; renderJourneyTransport(); }
    } catch(e) { alert('삭제 실패'); }
  }

