  // 검색 사이트별 URL 생성
  function _googleFlightsUrl(from, to, date) {
    // YYYY-MM-DD 그대로 사용
    var q = encodeURIComponent('Flights from ' + from + ' to ' + to + ' on ' + date);
    return 'https://www.google.com/travel/flights?q=' + q;
  }
  function _skyscannerUrl(from, to, date) {
    // YYMMDD 형식 (예: 270512)
    var d = date.replace(/-/g, '').substring(2);
    return 'https://www.skyscanner.co.kr/transport/flights/' + from.toLowerCase() + '/' + to.toLowerCase() + '/' + d + '/?adultsv2=1';
  }
  function _tripcomFlightUrl(from, to, date) {
    return 'https://kr.trip.com/flights/showfaresearch?dcity=' + from.toLowerCase() +
      '&acity=' + to.toLowerCase() + '&ddate=' + date + '&class=y&adult=1&allianceid=14887&sid=1621818';
  }

  function _renderFlightRecs() {
    var el = document.getElementById('journey-flight-recs');
    if (!el) return;
    var trip = tripsData.find(function(t){ return t._id === currentTripId; });
    if (!trip) { el.style.display = 'none'; return; }
    var recs = _FLIGHT_RECS[trip.name];
    if (!recs) { el.style.display = 'none'; return; }

    var html = '<div style="background:linear-gradient(135deg,#f0f9ff,#dbeafe);border:1px solid #bfdbfe;border-radius:18px;padding: var(--space-5) var(--space-5-5);margin-bottom: var(--space-6)">' +
      '<div style="display:flex;align-items:center;gap: var(--space-2-5);margin-bottom: var(--space-3-5);flex-wrap:wrap">' +
        '<span class="material-symbols-outlined" style="color:#0369a1;font-size: var(--font-size-h1)">flight</span>' +
        '<h4 style="font-family:var(--j-font-h,Manrope);font-size: var(--font-size-body);font-weight:800;color:#075985;letter-spacing:-0.01em;margin:0">항공편 추천 큐레이션</h4>' +
        '<span style="font-size: var(--font-size-tiny);font-weight:600;color:#0284c7;background:#fff;padding: var(--space-0-5) var(--space-2);border-radius: var(--radius-full)">Google Flights · Skyscanner · Trip.com</span>' +
      '</div>' +
      '<p style="font-size: var(--font-size-micro);color:#0369a1;margin:0 0 16px;font-style:italic">가격은 평균 시세 기준 (시즌·예약 시점에 따라 변동). 출국 60-90일 전 예약 추천.</p>';

    ['outbound', 'ret'].forEach(function(key) {
      var leg = recs[key];
      if (!leg) return;
      html += '<div style="margin-bottom: var(--space-4-5)">';
      html += '<div style="display:flex;align-items:center;gap: var(--space-2);margin-bottom: var(--space-2-5);flex-wrap:wrap">' +
        '<span style="font-family:var(--j-font-h,Manrope);font-size: var(--font-size-body-sm);font-weight:800;color:#0c4a6e">' + leg.label + '</span>' +
        '<span style="font-size: var(--font-size-tiny);font-weight:700;color:#0284c7;background:rgba(2,132,199,0.1);padding: var(--space-0-5) 7px;border-radius: var(--radius-full)">' + leg.date.substring(5).replace('-','/') + '</span>' +
      '</div>';
      html += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(290px,1fr));gap: var(--space-2-5)">';
      leg.options.forEach(function(opt, oi) {
        var rankBadge = oi === 0 ? '<span style="position:absolute;top:8px;right:10px;background:linear-gradient(135deg,#0369a1,#0284c7);color:#fff;font-size: var(--font-size-nano);font-weight:800;padding: var(--space-0-5) 7px;border-radius: var(--radius-full);letter-spacing:0.05em">⭐ 1순위</span>' : '';
        var gflUrl = _googleFlightsUrl(leg.from, leg.to, leg.date);
        var skyUrl = _skyscannerUrl(leg.from, leg.to, leg.date);
        var tripUrl = _tripcomFlightUrl(leg.from, leg.to, leg.date);
        html += '<div style="position:relative;background:#fff;border:1px solid #bfdbfe;border-radius: var(--radius-lg);padding:13px 14px 11px;transition:transform 0.15s, box-shadow 0.15s" onmouseover="this.style.transform=\'translateY(-1px)\';this.style.boxShadow=\'0 8px 20px rgba(2,132,199,0.12)\'" onmouseout="this.style.transform=\'\';this.style.boxShadow=\'\'">' +
          rankBadge +
          '<div style="display:flex;align-items:baseline;gap: var(--space-1-5);margin-bottom: var(--space-1);padding-right:' + (oi === 0 ? '70px' : '0') + '">' +
            '<h5 style="font-family:var(--j-font-h,Manrope);font-size: var(--font-size-body-sm);font-weight:700;color:#0c4a6e;margin:0;flex:1">' + opt.airline + (opt.flightNo ? ' · ' + opt.flightNo : '') + '</h5>' +
          '</div>' +
          '<div style="display:flex;align-items:center;gap: var(--space-1-5);margin-bottom: var(--space-1-5);flex-wrap:wrap">' +
            '<span style="font-size: var(--font-size-tiny);font-weight:600;color:#0284c7">' + opt.type + '</span>' +
            '<span style="font-size: var(--font-size-tiny);color:#9ca3af">·</span>' +
            '<span style="font-size: var(--font-size-micro);font-weight:700;color:#0f172a">' + opt.duration + '</span>' +
            '<span style="font-size: var(--font-size-tiny);color:#9ca3af">·</span>' +
            '<span style="font-size: var(--font-size-micro);font-weight:700;color:#0c4a6e">' + _spotPriceHtml(opt.price) + '</span>' +
          '</div>' +
          '<p style="font-size: var(--font-size-micro);color:#64748b;margin:0 0 4px;font-family:ui-monospace,Menlo,monospace;font-weight:600">' + opt.schedule + '</p>' +
          '<p style="font-size: var(--font-size-micro);color:#475569;line-height:1.55;margin:0 0 10px">' + opt.why + '</p>' +
          '<div style="display:flex;gap:5px;flex-wrap:wrap">' +
            '<a href="' + gflUrl + '" target="_blank" rel="noopener" title="Google Flights에서 검색" style="flex:1;min-width:80px;background:linear-gradient(135deg,#0369a1,#0284c7);color:#fff;font-size: var(--font-size-tiny);font-weight:700;padding: var(--space-1-5) var(--space-2);border-radius: var(--radius-md);text-align:center;text-decoration:none;display:flex;align-items:center;justify-content:center;gap: var(--space-1)"><span class="material-symbols-outlined" style="font-size: var(--font-size-meta)">flight</span>Google</a>' +
            '<a href="' + skyUrl + '" target="_blank" rel="noopener" title="Skyscanner에서 검색" style="flex:1;min-width:80px;background:#fff;border:1px solid #bfdbfe;color:#0369a1;font-size: var(--font-size-tiny);font-weight:700;padding: var(--space-1-5) var(--space-2);border-radius: var(--radius-md);text-decoration:none;display:flex;align-items:center;justify-content:center;gap: var(--space-1)"><span class="material-symbols-outlined" style="font-size: var(--font-size-meta)">search</span>Skyscanner</a>' +
            '<a href="' + tripUrl + '" target="_blank" rel="noopener" title="Trip.com에서 검색" style="background:#fff;border:1px solid #bfdbfe;color:#0369a1;font-size: var(--font-size-tiny);font-weight:700;padding: var(--space-1-5) var(--space-2);border-radius: var(--radius-md);text-decoration:none;display:flex;align-items:center;gap:3px"><span class="material-symbols-outlined" style="font-size: var(--font-size-meta)">open_in_new</span>Trip</a>' +
          '</div>' +
        '</div>';
      });
      html += '</div>';
      html += '</div>';
    });

    html += '</div>';
    el.innerHTML = html;
    el.style.display = '';
  }

  function renderJourneyFlights() {
    // 항공편 추천 섹션 (큐레이션 있는 trip만 표시)
    _renderFlightRecs();

    var container = document.getElementById('journey-flight-list');
    var totalEl = document.getElementById('journey-flight-total');
    if (!container) return;

    var defaults = isSeedTrip() ? FLIGHT_DEFAULTS : [];
    var fbFlights = journeyData.filter(function(d){ return d.type === '항공편'; });
    var fbKeys = {};
    fbFlights.forEach(function(f){ fbKeys[f.title||''] = true; });

    var totalKRW = 0;
    var extraPrice = '';

    // 시드 + Firebase 합쳐서 날짜 정렬
    var allFlights = [];
    defaults.filter(function(f){ return !fbKeys[f.flight]; }).forEach(function(f, si) {
      allFlights.push({ data: f, isSeed: true, seedIdx: si });
    });
    fbFlights.forEach(function(f) {
      allFlights.push({ data: f, isSeed: false, fbIdx: journeyData.indexOf(f) });
    });
    allFlights.sort(function(a, b) {
      var da = a.data.date||'', db = b.data.date||'';
      if (!da && db) return 1; if (da && !db) return -1;
      return da.localeCompare(db) || (a.data.depart||a.data.time||'').localeCompare(b.data.depart||b.data.time||'');
    });

    var html = allFlights.map(function(entry) {
      if (entry.isSeed) {
        var f = entry.data, si = entry.seedIdx;
        totalKRW += f.priceKRW;
        if (f.price.indexOf('$') >= 0) extraPrice = f.price;
        var seedBtns = '' +
          '<button onclick="migrateSeedAndEdit(\'항공편\','+si+')" class="p-2 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors text-slate-600"><span class="material-symbols-outlined text-xl">edit_square</span></button>' +
          '<button onclick="migrateSeedAndDelete(\'항공편\','+si+')" class="p-2 rounded-xl bg-slate-50 hover:bg-rose-100 transition-colors text-slate-400 hover:text-rose-500"><span class="material-symbols-outlined text-xl">delete</span></button>';
        return flightCard(f, seedBtns);
      }
      var f = entry.data, realIdx = entry.fbIdx;
      var amt = parseFloat(f.amount) || 0;
      totalKRW += amt;
      var actionBtns = '' +
        '<button onclick="editJourneyItem('+realIdx+')" class="p-2 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors text-slate-600"><span class="material-symbols-outlined text-xl">edit_square</span></button>' +
        '<button onclick="deleteJourneyRow('+realIdx+')" class="p-2 rounded-xl bg-slate-50 hover:bg-rose-100 transition-colors text-slate-400 hover:text-rose-500"><span class="material-symbols-outlined text-xl">delete</span></button>';
      return flightCard({
        airline:f.title, route:f.description, flight:f.city, date:f.date,
        depart:f.time, arrive:f.arrive||'', duration:f.duration||'', baggage:f.baggage||'',
        price:amt?'₩'+amt.toLocaleString('ko-KR'):'—',
        pnr:f.pnr, passenger:f.passenger, seat_class:f.seat_class, seat_number:f.seat_number,
        fare_type:f.fare_type, payment_date:f.payment_date, payment_status:f.payment_status, unpaid:f.unpaid,
        _id:f._id, attachments:f.attachments
      }, actionBtns);
    }).join('');

    container.innerHTML = html || '<p class="text-center text-xs text-slate-400 py-6">항공편을 추가해봐!</p>';
    if (totalEl && totalKRW > 0) {
      totalEl.innerHTML = '<div class="bg-slate-100 rounded-2xl px-6 py-4 flex items-center gap-4">' +
        '<span class="text-[10px] font-bold uppercase tracking-widest text-slate-400">총 항공권</span>' +
        '<span class="text-xl font-black text-slate-800 font-headline">₩' + totalKRW.toLocaleString('ko-KR') + '</span>' +
        (extraPrice ? '<span class="text-[10px] text-slate-400 font-medium">+ ' + extraPrice + '</span>' : '') +
      '</div>';
    } else if (totalEl) { totalEl.innerHTML = ''; }
  }

  var _flightEditIdx = null;

  function openFlightEditModal(idx) {
    _flightEditIdx = idx;
    var item = journeyData[idx];
    // route 파싱: "인천(ICN) → 이스탄불(IST)" → dep="인천(ICN)", arr="이스탄불(IST)"
    var routeParts = (item.description||'').split('→').map(function(s){return s.trim();});
    var setV = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || ''; };
    setV('fe-airline', item.title);
    setV('fe-code', item.city);
    setV('fe-dep', routeParts[0]);
    setV('fe-arr', routeParts[1]);
    setV('fe-date', item.date);
    setV('fe-time', item.time);
    setV('fe-arrive', item.arrive);
    setV('fe-duration', item.duration);
    setV('fe-baggage', item.baggage);
    setV('fe-seat-class', item.seat_class);
    setV('fe-seat-number', item.seat_number);
    setV('fe-fare-type', item.fare_type);
    setV('fe-pnr', item.pnr);
    setV('fe-passenger', item.passenger);
    setV('fe-payment-date', item.payment_date);
    setV('fe-payment-status', item.payment_status);
    setV('fe-price', item.amount ? Number(String(item.amount).replace(/[^0-9.]/g,'')).toLocaleString('ko-KR') : '');
    document.getElementById('flight-edit-modal').style.cssText = 'display:flex!important';
  }

  function closeFlightEditModal() {
    document.getElementById('flight-edit-modal').style.cssText = 'display:none!important';
    _flightEditIdx = null;
  }

  async function saveFlightEdit() {
    if (_flightEditIdx === null) return;
    var item = journeyData[_flightEditIdx];
    var id = item._id;
    var getV = function(elId) { var el = document.getElementById(elId); return el ? (el.value||'').trim() : ''; };
    var update = {
      title: getV('fe-airline'),
      description: getV('fe-dep') + ' → ' + getV('fe-arr'),
      city: getV('fe-code'),
      date: document.getElementById('fe-date').value,
      time: getV('fe-time'),
      arrive: getV('fe-arrive'),
      duration: getV('fe-duration'),
      baggage: getV('fe-baggage'),
      seat_class: getV('fe-seat-class'),
      seat_number: getV('fe-seat-number'),
      fare_type: getV('fe-fare-type'),
      pnr: getV('fe-pnr'),
      passenger: getV('fe-passenger'),
      payment_date: document.getElementById('fe-payment-date').value,
      payment_status: getV('fe-payment-status'),
      amount: document.getElementById('fe-price').value.replace(/[^0-9]/g,'')
    };
    try {
      await fbUpdate('journey', id, update);
      Object.assign(item, update);
      await syncJourneyToFinance(item);
      renderJourneyFlights();
      updateJourneyCost();
      if (typeof updateTravelMiniSummary === 'function') updateTravelMiniSummary();
      closeFlightEditModal();
    } catch(err) { alert('저장에 실패했어요.'); }
  }

  async function saveFlightForm() {
    var getV = function(elId) { var el = document.getElementById(elId); return el ? (el.value||'').trim() : ''; };
    var obj = {
      trip_id: currentTripId, type: '항공편',
      title: getV('flt-airline'),
      description: getV('flt-dep') + ' → ' + getV('flt-arr'),
      city: getV('flt-code'),
      date: document.getElementById('flt-date').value,
      time: getV('flt-time'),
      arrive: getV('flt-arrive'),
      duration: getV('flt-duration'),
      baggage: getV('flt-baggage'),
      seat_class: getV('flt-seat-class'),
      seat_number: getV('flt-seat-number'),
      fare_type: getV('flt-fare-type'),
      pnr: getV('flt-pnr'),
      passenger: getV('flt-passenger'),
      payment_date: document.getElementById('flt-payment-date').value,
      payment_status: getV('flt-payment-status'),
      amount: document.getElementById('flt-price').value.replace(/[^0-9]/g,'')
    };
    if (!obj.title) { alert('항공사를 입력해줘!'); return; }
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      await syncJourneyToFinance(saved);
      if (typeof trvConsumeScanAttach === 'function') trvConsumeScanAttach(saved._id);
      ['flt-airline','flt-code','flt-dep','flt-arr','flt-date','flt-time','flt-arrive','flt-duration','flt-baggage','flt-seat-class','flt-seat-number','flt-fare-type','flt-pnr','flt-passenger','flt-payment-date','flt-payment-status','flt-price'].forEach(function(id){var el=document.getElementById(id); if(el) el.value='';});
      renderJourneyFlights();
    } catch(e) { alert('저장 실패'); }
  }

  async function saveInlineSouvenir() {
    var title = document.getElementById('sv-recipient').value.trim();
    var desc = document.getElementById('sv-item').value.trim();
    if (!title && !desc) { alert('대상 또는 품목을 입력해줘!'); return; }
    var obj = {
      trip_id: currentTripId, type: '기념품',
      title: title, description: desc,
      city: document.getElementById('sv-city').value.trim(),
      amount: document.getElementById('sv-price').value.replace(/,/g,''),
      status: ''
    };
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      renderJourneySouvenir();
      ['sv-recipient','sv-item','sv-city','sv-price'].forEach(function(id){ document.getElementById(id).value=''; });
    } catch(err) { alert('저장에 실패했어요.'); }
  }

  function svRow(title, desc, city, amount, checked, checkFn, deleteFn, dblClickFn, editFn) {
    var dotCls = checked ? 'bg-indigo-500' : 'bg-slate-300';
    var statusHtml = checked
      ? '<div class="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center text-white cursor-pointer" onclick="' + checkFn + '"><span class="material-symbols-outlined text-[14px]" style="font-variation-settings:\'FILL\' 1;">check</span></div>'
      : '<div class="w-6 h-6 rounded-full border-2 border-slate-300 cursor-pointer hover:border-indigo-400 transition-colors" onclick="' + checkFn + '"></div>';
    return '<div class="bg-white rounded-2xl p-3 hover:bg-slate-50 transition-colors group" style="box-shadow: var(--shadow-card-sm);border-left:3px solid var(--lavender-deep);">' +
      '<div class="grid grid-cols-12 items-start gap-2">' +
        '<div class="col-span-3 flex items-center gap-2">' +
          '<div class="w-2 h-2 rounded-full ' + dotCls + '"></div>' +
          '<span class="text-sm font-semibold text-slate-800 truncate ' + (checked?'line-through opacity-50':'') + '"' + (dblClickFn ? ' ondblclick="' + dblClickFn.replace('%FIELD%','title') + '"' : '') + '>' + (title||'—') + '</span>' +
        '</div>' +
        '<div class="col-span-3 min-w-0">' +
          (function(){
            var parts = (desc||'—').split('\n');
            var main = parts[0];
            var note = parts.slice(1).join(' ');
            var html = '<span class="block text-sm text-slate-700 font-medium truncate ' + (checked?'line-through opacity-50':'') + '"' + (dblClickFn ? ' ondblclick="' + dblClickFn.replace('%FIELD%','description') + '"' : '') + '>' + main + '</span>';
            if (note) html += '<span class="block text-[11px] text-slate-400 mt-0.5 leading-snug" style="word-break:keep-all;overflow-wrap:break-word;white-space:normal">' + note + '</span>';
            return html;
          })() +
        '</div>' +
        '<div class="col-span-2">' +
          '<span class="text-xs text-slate-400 font-medium truncate"' + (dblClickFn ? ' ondblclick="' + dblClickFn.replace('%FIELD%','city') + '"' : '') + '>' + (city||'—') + '</span>' +
        '</div>' +
        '<div class="col-span-2 text-right">' +
          '<span class="text-xs font-headline font-bold text-indigo-600"' + (dblClickFn ? ' ondblclick="' + dblClickFn.replace('%FIELD%','amount') + '"' : '') + '>' + (amount ? '€'+amount : '—') + '</span>' +
        '</div>' +
        '<div class="col-span-2 flex justify-end items-center gap-1">' +
          statusHtml +
          (editFn ? '<button onclick="' + editFn + '" class="p-1.5 rounded-lg bg-slate-50 hover:bg-slate-100 transition-colors text-slate-600"><span class="material-symbols-outlined" style="font-size: var(--font-size-h3)">edit_square</span></button>' : '') +
          '<button onclick="' + deleteFn + '" class="p-1.5 rounded-lg bg-slate-50 hover:bg-rose-100 transition-colors text-slate-400 hover:text-rose-500"><span class="material-symbols-outlined" style="font-size: var(--font-size-h3)">delete</span></button>' +
        '</div>' +
      '</div>' +
    '</div>';
  }

  // 도시 → 국기/국가 추론
  function _souvenirCountry(city) {
    var c = (city || '').toLowerCase();
    if (!c) return { flag:'🌍', name:'기타', kr:'기타' };
    if (/독일|german|frankfurt|berlin|dresden|munich|münchen|hamburg|stuttgart|bavaria|köln|cologne/.test(c)) return { flag:'🇩🇪', name:'GERMANY', kr:'독일' };
    if (/이탈리아|italy|italia|pienza|rome|roma|florence|firenze|milan|milano|venice|venezia|naples|napoli|siena|tuscany|toscana/.test(c)) return { flag:'🇮🇹', name:'ITALY', kr:'이탈리아' };
    if (/일본|japan|tokyo|kyoto|osaka|fukuoka|sapporo|hokkaido|hiroshima/.test(c)) return { flag:'🇯🇵', name:'JAPAN', kr:'일본' };
    if (/프랑스|france|paris|lyon|marseille|nice|normandy|brittany/.test(c)) return { flag:'🇫🇷', name:'FRANCE', kr:'프랑스' };
    if (/영국|uk|britain|london|edinburgh|manchester|england/.test(c)) return { flag:'🇬🇧', name:'UNITED KINGDOM', kr:'영국' };
    if (/스페인|spain|madrid|barcelona|seville|mallorca|valencia/.test(c)) return { flag:'🇪🇸', name:'SPAIN', kr:'스페인' };
    if (/체코|czech|prague|praha|olomouc|krumlov/.test(c)) return { flag:'🇨🇿', name:'CZECHIA', kr:'체코' };
    if (/폴란드|poland|warsaw|krakow|kraków|gdansk|oświęcim/.test(c)) return { flag:'🇵🇱', name:'POLAND', kr:'폴란드' };
    if (/오스트리아|austria|vienna|wien|salzburg/.test(c)) return { flag:'🇦🇹', name:'AUSTRIA', kr:'오스트리아' };
    if (/크로아티아|croatia|dubrovnik|zagreb|split/.test(c)) return { flag:'🇭🇷', name:'CROATIA', kr:'크로아티아' };
    if (/덴마크|denmark|copenhagen|aarhus|skagen/.test(c)) return { flag:'🇩🇰', name:'DENMARK', kr:'덴마크' };
    if (/스웨덴|sweden|stockholm|gothenburg|malmö|malmo/.test(c)) return { flag:'🇸🇪', name:'SWEDEN', kr:'스웨덴' };
    if (/노르웨이|norway|oslo|bergen|tromsø|tromso|lofoten/.test(c)) return { flag:'🇳🇴', name:'NORWAY', kr:'노르웨이' };
    if (/핀란드|finland|helsinki|tampere/.test(c)) return { flag:'🇫🇮', name:'FINLAND', kr:'핀란드' };
    if (/아이슬란드|iceland|reykjavik|reykjavík|vík|akureyri/.test(c)) return { flag:'🇮🇸', name:'ICELAND', kr:'아이슬란드' };
    if (/아일랜드|ireland|dublin|galway|cork|kilkenny|belfast/.test(c)) return { flag:'🇮🇪', name:'IRELAND', kr:'아일랜드' };
    if (/포르투갈|portugal|lisbon|lisboa|porto/.test(c)) return { flag:'🇵🇹', name:'PORTUGAL', kr:'포르투갈' };
    if (/캐나다|canada|montréal|montreal|toronto|québec|quebec|ottawa|halifax/.test(c)) return { flag:'🇨🇦', name:'CANADA', kr:'캐나다' };
    if (/미국|usa|america|new york|los angeles|san diego|san francisco|chicago|seattle/.test(c)) return { flag:'🇺🇸', name:'USA', kr:'미국' };
    if (/호주|australia|sydney|melbourne|hobart|adelaide|brisbane/.test(c)) return { flag:'🇦🇺', name:'AUSTRALIA', kr:'호주' };
    if (/뉴질랜드|new zealand|auckland|queenstown|wellington/.test(c)) return { flag:'🇳🇿', name:'NEW ZEALAND', kr:'뉴질랜드' };
    if (/말타|malta|valletta/.test(c)) return { flag:'🇲🇹', name:'MALTA', kr:'말타' };
    if (/슬로베니아|slovenia|ljubljana|bled/.test(c)) return { flag:'🇸🇮', name:'SLOVENIA', kr:'슬로베니아' };
    if (/스위스|switzerland|zurich|geneva|bern/.test(c)) return { flag:'🇨🇭', name:'SWITZERLAND', kr:'스위스' };
    return { flag:'🌍', name:(city || '기타').toUpperCase(), kr: city || '기타' };
  }

  // ★ (2026-07-23) description을 품목(제목) / 설명(부연)으로 분리
  //   "Apfelwein 사과주 (Possmann) — 프랑크푸르트 특산 사과 와인" → name / note
  //   구분자: " — "(em dash) · " – "(en dash) · " - "(하이픈). 없으면 전체가 품목.
  function _svSplitDesc(desc) {
    var lines = String(desc == null ? '' : desc).split('\n');
    var head = String(lines[0] || '').trim();
    var rest = lines.slice(1).join(' ').trim();
    var m = head.match(/^([\s\S]*?)\s+[—–-]\s+([\s\S]+)$/);
    var name = m ? m[1].trim() : head;
    var note = m ? m[2].trim() : '';
    if (rest) note = note ? (note + ' · ' + rest) : rest;
    return { name: name, note: note };
  }

  // 분리 편집한 조각을 다시 한 필드(description)로 합치기 — 여러 줄은 2번째 줄부터 보존
  function _svMergeDesc(orig, part, val) {
    var lines = String(orig == null ? '' : orig).split('\n');
    var head = String(lines[0] || '').trim();
    var m = head.match(/^([\s\S]*?)\s+[—–-]\s+([\s\S]+)$/);
    var name = m ? m[1].trim() : head;
    var note = m ? m[2].trim() : '';
    if (part === 'note') note = String(val || '').trim();
    else name = String(val || '').trim();
    var merged = name + (note ? ' — ' + note : '');
    return [merged].concat(lines.slice(1)).join('\n');
  }

  // 품목/설명 인라인 편집 — 조각만 고쳐도 description 원본은 합쳐서 저장 (정보 손실 방지)
  function svPartEdit(el, idx, part, mode) {
    inlineEditTd(el, function(val) {
      if (mode === 'seed') {
        var data = getSouvenirData();
        if (!data[idx]) return;
        data[idx].description = _svMergeDesc(data[idx].description, part, val);
        saveSouvenirData(data);
        renderJourneySouvenir();
        return;
      }
      var it = journeyData[idx];
      if (!it) return;
      it.description = _svMergeDesc(it.description, part, val);
      fbUpdate('journey', it._id, { description: it.description })
        .then(function() { renderJourneySouvenir(); })
        .catch(function() { alert('저장 실패'); renderJourneySouvenir(); });
    });
  }

  // ═══ ★ (2026-07-24) 기념품 썸네일 ═══
  //   글자만 있어 뭘 사는 건지 안 와닿는다는 피드백. 제품 사진을 위키피디아(무료·키 불필요·CORS)에서
  //   가져오고, 못 찾으면 품목 종류 이모지 칩으로 대체한다.
  //   ★ 틀린 사진 > 사진 없음 이므로 판정을 빡세게: 페이지 제목에 브랜드 토큰이 있어야 하고,
  //     Wikidata 설명이 '사람'이거나 목록 문서면 버린다 (Marvis→복서, Savini→소설가 오매칭 사례).
  var _SV_KIND = [
    [/치약|toothpaste/i,                       '🪥'],
    [/커피|에스프레소|coffee|espresso|모카/i,   '☕'],
    [/초콜릿|쇼콜라|choco/i,                    '🍫'],
    [/젤리|구미|haribo/i,                       '🍬'],
    [/과자|쿠키|비스킷|진저브레드|마지팬|빵/i,   '🍪'],
    [/와인|사과주|wine|프로세코|스푸만테/i,      '🍷'],
    [/맥주|beer/i,                              '🍺'],
    [/그라파|리큐르|아마로|위스키|술/i,          '🥃'],
    [/차\b|티백|tea/i,                          '🍵'],
    [/치즈|cheese|페코리노|파르미지아노/i,       '🧀'],
    [/소금|오일|식초|조미료|트러플|발사믹/i,     '🧂'],
    [/파스타|면|리조또|쌀/i,                     '🍝'],
    [/잼|꿀|honey|스프레드/i,                    '🍯'],
    [/향신료|허브|사프란|후추/i,                 '🌿'],
    [/신발|샌들|슈즈|shoe|sandal|버켄|birkenstock/i, '👟'],
    [/가방|백팩|파우치|지갑|bag/i,               '👜'],
    [/향수|퍼퓸|perfume|디퓨저|캔들/i,           '🕯️'],
    [/크림|로션|화장품|비누|샴푸/i,              '🧴'],
    [/문구|펜|노트|연필|스티커|엽서/i,           '✏️'],
    [/그릇|컵|잔|주방|냄비|포트|커틀러리|도마/i, '🍽️'],
    [/옷|셔츠|니트|양말|스카프|모자/i,           '🧣'],
    [/책|화보|도록/i,                            '📖'],
    [/레고|장난감|피규어/i,                      '🧸']
  ];
  function _svEmoji(item) {
    var hay = ((item && item.description) || '') + ' ' + ((item && item.title) || '');
    for (var i = 0; i < _SV_KIND.length; i++) if (_SV_KIND[i][0].test(hay)) return _SV_KIND[i][1];
    return '🎁';
  }
  // 검색어: 라틴 문자 덩어리 우선(괄호 안까지 훑음). 한글만 있으면 검색 포기.
  function _svImgQuery(item) {
    var name = _svSplitDesc(item.description).name || '';
    var cands = [];
    var paren = name.match(/\(([^)]*)\)/g) || [];
    var outside = name.replace(/\([^)]*\)/g, ' ');
    var pick = function(s) {
      var m = String(s).replace(/[·+*/,]/g, ' ').match(/[A-Za-zÀ-ÿ][A-Za-zÀ-ÿ'’\-]*(?:\s+[A-Za-zÀ-ÿ][A-Za-zÀ-ÿ'’\-]*)?/);
      if (!m) return '';
      var q = m[0].trim();
      return q.length >= 3 ? q : '';
    };
    var a = pick(outside); if (a) cands.push(a);
    paren.forEach(function(p) { var b = pick(p.slice(1, -1)); if (b && cands.indexOf(b) < 0) cands.push(b); });
    return cands;
  }
  // 사람/목록 문서 배제 — Wikidata 설명 기준
  var _SV_REJECT = /(boxer|minister|writer|scrittor|footballer|calciator|politic|actor|attore|attrice|singer|cantante|painter|pittor|Schriftsteller|Fußball|Politiker|Schauspieler|Sänger|Maler|musician|musicista|regista|director|player|giocator|storico|historian|\(\d{4}|\d{4}\s*[–\-]\s*\d{4})/i;
  // ★ (2026-07-24) 지명·행정구역 문서도 배제 — 실측 오매칭: 사프란→마을 깃발, Meissen 도자기→도시 성당
  var _SV_REJECT_PLACE = /(comune|citt[aà]|\bcity\b|\btown\b|Stadt|Gemeinde|municipalit|village|commune|\bfrazione\b|castle|Burg\b|cathedral|Dom\b|Landkreis|distret|district|\bregion|provincia|province|\bisland\b|\briver\b|mountain|Berg\b)/i;
  // 깃발·문장·지도 파일도 제품 사진이 아님
  var _SV_REJECT_FILE = /(bandiera|wappen|stemma|flag[_-]of|coat[_-]of[_-]arms|karte|map[_-]of|_map\.|location|locator|\bblason\b)/i;
  function _svWikiPhoto(q, lang, cb) {
    var token = String(q).split(/\s+/)[0].toLowerCase();
    var url = 'https://' + lang + '.wikipedia.org/w/api.php?action=query&generator=search' +
      '&gsrsearch=' + encodeURIComponent(q) + '&gsrlimit=1' +
      '&prop=pageimages|pageterms&piprop=thumbnail&pithumbsize=200&wbptterms=description' +
      '&format=json&origin=*';
    fetch(url).then(function(r){ return r.json(); }).then(function(d) {
      var pages = (d && d.query && d.query.pages) || {};
      var keys = Object.keys(pages);
      if (!keys.length) return cb(null);
      var v = pages[keys[0]];
      var title = String(v.title || '');
      var thumb = v.thumbnail && v.thumbnail.source;
      if (!thumb) return cb(null);
      if (title.toLowerCase().indexOf(token) < 0) return cb(null);           // 브랜드 토큰 불일치
      if (/^(List of|Liste |Lista )/i.test(title)) return cb(null);          // 목록 문서
      var desc = ((v.terms && v.terms.description) || [''])[0];
      if (_SV_REJECT.test(desc)) return cb(null);                            // 사람 문서
      if (_SV_REJECT_PLACE.test(desc)) return cb(null);                      // 도시·마을 등 지명 문서
      if (_SV_REJECT_FILE.test(decodeURIComponent(thumb))) return cb(null);  // 깃발·문장·지도 이미지
      cb(thumb);
    }).catch(function(){ cb(null); });
  }
  // 국가별 우선 언어 → 영어 순으로 시도
  function _svPhotoFor(item, cb) {
    var ctry = _souvenirCountry(item.city || '');
    var langs = ({ 'GERMANY':['de','en'], 'ITALY':['it','en'], 'FRANCE':['fr','en'], 'SPAIN':['es','en'],
      'JAPAN':['ja','en'], 'CZECHIA':['cs','en'], 'AUSTRIA':['de','en'], 'DENMARK':['da','en'],
      'SWEDEN':['sv','en'] })[ctry.name] || ['en'];
    var qs = _svImgQuery(item);
    if (!qs.length) return cb(null);
    var jobs = [];
    qs.forEach(function(q) { langs.forEach(function(l) { jobs.push([q, l]); }); });
    (function next(i) {
      if (i >= jobs.length) return cb(null);
      _svWikiPhoto(jobs[i][0], jobs[i][1], function(url) {
        if (url) return cb(url);
        setTimeout(function(){ next(i + 1); }, 120);
      });
    })(0);
  }
  // 일괄 채우기 — 순차 실행, 버튼에 진행 표시. 못 찾은 건 photo_none으로 표시해 재시도 대상에서 제외
  window.fillSouvenirPhotos = function() {
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var targets = jd.filter(function(d) { return d.type === '기념품' && d._id && !d.photo_url && !d.photo_none; });
    var btn = document.getElementById('sv-photo-fill-btn');
    if (!targets.length) { if (btn) btn.style.display = 'none'; return; }
    if (btn && btn.getAttribute('data-running')) return;
    if (btn) { btn.setAttribute('data-running', '1'); btn.disabled = true; }
    var ok = 0;
    (function step(i) {
      if (i >= targets.length) {
        if (btn) { btn.removeAttribute('data-running'); btn.disabled = false; }
        try { renderJourneySouvenir(); } catch(e) {}
        if (typeof showSyncToast === 'function') showSyncToast('🎁 기념품 사진 ' + ok + '/' + targets.length + '건 찾았어! (못 찾은 건 이모지로 표시)');
        return;
      }
      if (btn) btn.innerHTML = '<span class="material-symbols-outlined">image</span> ' + (i + 1) + '/' + targets.length + ' 찾는 중…';
      var it = targets[i];
      _svPhotoFor(it, function(url) {
        var patch = url ? { photo_url: url } : { photo_none: true };
        if (url) ok++;
        fbUpdate('journey', it._id, patch).then(function() {
          Object.assign(it, patch);
          try { renderJourneySouvenir(); } catch(e) {}
        }).catch(function(){});
        setTimeout(function(){ step(i + 1); }, 260);
      });
    })(0);
  };
  // 썸네일 셀 — 사진 있으면 이미지, 없으면 종류 이모지. 더블클릭으로 이미지 주소 직접 편집
  function _svThumbHtml(item, realIdx, scope) {
    var dbl = (realIdx != null && scope === 'fb')
      ? ' ondblclick="event.stopPropagation();fbInlineEdit(this,' + realIdx + ',\'photo_url\',\'기념품\')" title="더블클릭하여 이미지 주소 입력/삭제"'
      : '';
    if (item.photo_url) {
      return '<div class="sv-thumb"' + dbl + '>' +
        '<img src="' + String(item.photo_url).replace(/"/g, '&quot;') + '" alt="" loading="lazy" referrerpolicy="no-referrer" ' +
        'onerror="this.parentNode.classList.add(\'is-fallback\');this.parentNode.innerHTML=\'' + _svEmoji(item) + '\'">' +
      '</div>';
    }
    return '<div class="sv-thumb is-fallback"' + dbl + '>' + _svEmoji(item) + '</div>';
  }

  // stitch souvenir row — 해어라인 리스트 행 (.sv-*)
  // ★ (2026-07-23) 품목/설명 2단 분리 + 중복 메타(대상·도시) 제거 — 대상은 그룹 헤더, 도시는 도시 헤더에 이미 있음
  //   partFn: 'svPartEdit(this,IDX,\'%PART%\',\'fb|seed\')' — 품목/설명 조각 편집용
  function svRowSt(item, checked, checkFn, deleteFn, editFn, dblClickFn, partFn, realIdx, scope) {
    var title = (item.title || '').replace(/</g,'&lt;'); // 대상 (가족/동료/나)
    var city = (item.city || '').replace(/</g,'&lt;');
    var amount = item.amount;
    var split = _svSplitDesc(item.description);
    var nameTxt = split.name.replace(/</g,'&lt;');
    var noteTxt = split.note.replace(/</g,'&lt;');
    var checkInner = checked ? '<span class="material-symbols-outlined">check</span>' : '';
    var nameLinked = nameTxt && nameTxt !== '—' ? _trvMapsLink(nameTxt, city) : (nameTxt || '—');
    // 그룹핑에 안 쓰이는 추가 정보만 유지 (구체 매장·장소)
    var loc = String(item.location || '').trim().replace(/</g,'&lt;');
    var nameDbl = partFn ? partFn.replace('%PART%','name') : (dblClickFn ? dblClickFn.replace('%FIELD%','description') : '');
    var noteDbl = partFn ? partFn.replace('%PART%','note') : (dblClickFn ? dblClickFn.replace('%FIELD%','description') : '');
    var krw = amount ? _eurKrwOnly(String(amount)) : '';
    return '<div class="sv-row' + (checked ? ' is-done' : '') + '">' +
      '<div class="sv-check' + (checked ? ' is-checked' : '') + '" onclick="' + checkFn + '">' + checkInner + '</div>' +
      _svThumbHtml(item, realIdx, scope) +
      '<div class="sv-main">' +
        '<h5 class="sv-name"' + (nameDbl ? ' ondblclick="' + nameDbl + '"' : '') + '>' + nameLinked + '</h5>' +
        (noteTxt ? '<p class="sv-desc"' + (noteDbl ? ' ondblclick="' + noteDbl + '"' : '') + '>' + noteTxt + '</p>' : '') +
        (loc ? '<p class="sv-extra">📍 ' + _trvMapsLink(loc, city) + '</p>' : '') +
        // 대상·도시는 헤더와 중복이라 평소엔 숨김 — 행에 마우스를 올렸을 때만 편집용으로 노출
        (dblClickFn ? '<p class="sv-edit"><span ondblclick="' + dblClickFn.replace('%FIELD%','title') + '">' + (title || '대상') + '</span>' +
          (city ? '<span ondblclick="' + dblClickFn.replace('%FIELD%','city') + '">' + city + '</span>' : '') +
          '<em>더블클릭 편집</em></p>' : '') +
      '</div>' +
      '<div class="sv-right">' +
        '<div class="sv-price"' + (dblClickFn ? ' ondblclick="' + dblClickFn.replace('%FIELD%','amount') + '"' : '') + '>' + (amount ? '€' + String(amount).replace(/^\s*€\s*/, '') : '—') + '</div>' +
        (krw ? '<div class="sv-krw">' + krw + '</div>' : '') +
      '</div>' +
      '<div class="sv-actions">' +
        (editFn ? '<button onclick="' + editFn + '"><span class="material-symbols-outlined">edit_square</span></button>' : '') +
        '<button class="danger" onclick="' + deleteFn + '"><span class="material-symbols-outlined">delete</span></button>' +
      '</div>' +
    '</div>';
  }

  // 국가 컬럼 1개 HTML (헤더 + 도시 + 카테고리 그룹) — rowFn: item → 행 HTML
  function _svCountryBlockHtml(g, rowFn) {
    var cities = _groupSouvenirsByCity(g.items);
    var citiesHtml = cities.map(function(cityGroup) {
      var subs = _groupSouvenirsByCategory(cityGroup.items);
      var subsHtml = subs.map(function(sub) {
        var rowsHtml = sub.items.map(rowFn).join('');
        return '<div class="sv-cat">' +
          '<div class="sv-cat-h">' +
            '<span class="sv-cat-label">' + sub.cat + '</span>' +
            '<span class="sv-cat-count">' + sub.items.length + '</span>' +
          '</div>' +
          '<div class="sv-list">' + rowsHtml + '</div>' +
        '</div>';
      }).join('');
      var orderLabel = (cityGroup.rank < 9999) ? ('STOP ' + (cityGroup.rank + 1)) : '';
      return '<div class="sv-city">' +
        '<div class="sv-city-h">' +
          '<div class="sv-city-h-l">' +
            (orderLabel ? '<span class="sv-stop">' + orderLabel + '</span>' : '') +
            '<span class="sv-city-name">' + cityGroup.city + '</span>' +
          '</div>' +
          '<span class="sv-city-count">' + cityGroup.items.length + ' items</span>' +
        '</div>' +
        subsHtml +
      '</div>';
    }).join('');
    return '<div class="sv-country">' +
      '<div class="sv-country-h">' +
        '<div class="sv-country-title">' +
          '<span class="sv-flag">' + g.country.flag + '</span>' +
          '<h3>' + g.country.name + '</h3>' +
        '</div>' +
        '<p class="sv-country-sub">' + g.country.kr + ' • ' + g.items.length + ' items</p>' +
      '</div>' +
      citiesHtml +
    '</div>';
  }

  // 카테고리(대상) 우선순위 — 찐친 → 후배 → 동료 → 직장 → 가족 → 나 → 집 → 소장 → 디자이너 → 편집 → ...
  var SOUVENIR_CAT_ORDER = ['찐친','후배','동료','직장','가족','나','집','소장','디자이너','편집','음료','기타'];
  function _souvenirCatRank(title) {
    var t = String(title || '');
    for (var i = 0; i < SOUVENIR_CAT_ORDER.length; i++) {
      if (t.indexOf(SOUVENIR_CAT_ORDER[i]) >= 0) return i;
    }
    return 999;
  }
  // primary 카테고리 키 (sub-group 묶음용) — title에서 첫 매칭 키워드
  function _souvenirPrimaryCat(title) {
    var t = String(title || '');
    for (var i = 0; i < SOUVENIR_CAT_ORDER.length; i++) {
      if (t.indexOf(SOUVENIR_CAT_ORDER[i]) >= 0) return SOUVENIR_CAT_ORDER[i];
    }
    return '기타';
  }
  // 같은 카테고리 items을 sub-group으로 묶기 (이미 정렬된 배열을 받음)
  function _groupSouvenirsByCategory(sortedItems) {
    var subs = [];
    var cur = null;
    sortedItems.forEach(function(it) {
      var cat = _souvenirPrimaryCat(it.title);
      if (!cur || cur.cat !== cat) {
        cur = { cat: cat, items: [] };
        subs.push(cur);
      }
      cur.items.push(it);
    });
    return subs;
  }

  // 도시별로 그룹화 + 국가 추론 + 그룹 안 카테고리 순 정렬
  function _groupSouvenirsByCountry(items) {
    var groups = {};
    var order = [];
    items.forEach(function(it) {
      var country = _souvenirCountry(it.city || '');
      var key = country.flag + country.name;
      if (!groups[key]) {
        groups[key] = { country: country, items: [] };
        order.push(key);
      }
      groups[key].items.push(it);
    });
    // 각 그룹 안에서 카테고리 우선순위 → 같은 카테고리 안에서 title 알파벳/가나다
    order.forEach(function(k) {
      groups[k].items.sort(function(a, b) {
        var ra = _souvenirCatRank(a.title), rb = _souvenirCatRank(b.title);
        if (ra !== rb) return ra - rb;
        return String(a.title || '').localeCompare(String(b.title || ''), 'ko');
      });
    });
    return order.map(function(k) { return groups[k]; });
  }

  // 여행 도시 순서 (citiesData 순서) 기반 city 우선순위
  function _souvenirCityRank(city) {
    if (!city) return 9999;
    var c = (typeof citiesData !== 'undefined' && citiesData) ? citiesData : [];
    var nc = _normCityKey(city);
    for (var i = 0; i < c.length; i++) {
      var n = _normCityKey(c[i].name || '');
      if (!n || !nc) continue;
      if (n === nc || n.indexOf(nc) >= 0 || nc.indexOf(n) >= 0) return i;
    }
    return 9999;
  }
  // ★ (2026-07-23) 도시별 실제 체류 기간 — citiesData start_date/end_date → "10/05~10/08"
  //   여행에 없는 도시(당일치기 목적지 등)는 '' 반환 → 호출부에서 날짜 생략
  // ★ (2026-07-23) 숙박 도시 매칭 행 — 날짜 텍스트/원본 ISO를 둘 다 쓰려고 분리
  function _cityStayHit(city) {
    if (!city) return null;
    var c = (typeof citiesData !== 'undefined' && citiesData) ? citiesData : [];
    var nc = _normCityKey(city);
    if (!nc) return null;
    for (var i = 0; i < c.length; i++) {
      var n = _normCityKey(c[i].name || '');
      if (!n) continue;
      if (n === nc || n.indexOf(nc) >= 0 || nc.indexOf(n) >= 0) return c[i];
    }
    return null;
  }
  function _cityStayRange(city) {
    var hit = _cityStayHit(city);
    if (!hit || !hit.start_date) return '';
    var md = function(ds) {
      var m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(String(ds || ''));
      return m ? (+m[2]) + '/' + (+m[3]) : '';
    };
    var s = md(hit.start_date), e = md(hit.end_date);
    if (!s) return '';
    return (e && e !== s) ? (s + '~' + e) : s;
  }
  // ★ (2026-07-23) 당일치기 도시 날짜 — citiesData(숙박)에 없으면 journey 일정에서 최소~최대 날짜
  //   반환: { text:'10/9' | '10/9~10/10' | '', kind:'stay' | 'daytrip' | '' }
  //   ★ (2026-07-23 보강) 일정의 city가 비어있거나 제목이 한글이라 문자열 매칭이 0건이던 문제
  //     (Bagno Vignoni · Montalcino 등) — 좌표 매칭과 한↔영 도시명 표를 폴백으로 추가
  var _CITY_KO_ALIAS = {
    'Montalcino': '몬탈치노',
    'Montepulciano': '몬테풀차노',
    'Bagno Vignoni': '바뇨 비뇨니',
    "Castiglione d'Orcia": '카스틸리오네',
    'Orvieto': '오르비에토',
    'Pienza': '피엔차',
    'Siena': '시에나',
    "San Quirico d'Orcia": '산 퀴리코',
    'Berlin': '베를린',
    'Frankfurt am Main': '프랑크푸르트',
    'Rome': '로마', 'Roma': '로마', 'Florence': '피렌체', 'Firenze': '피렌체',
    'Milan': '밀라노', 'Milano': '밀라노', 'Venice': '베네치아', 'Venezia': '베네치아',
    'Naples': '나폴리', 'Napoli': '나폴리', 'Bologna': '볼로냐', 'Verona': '베로나',
    'Dresden': '드레스덴', 'Munich': '뮌헨', 'München': '뮌헨', 'Hamburg': '함부르크',
    'Cologne': '쾰른', 'Köln': '쾰른', 'Leipzig': '라이프치히', 'Potsdam': '포츠담'
  };
  // 도시명(원문) → 한글 별칭. 표에 없으면 '' (표 키는 대소문자 무시 + 부분 일치 허용)
  function _cityKoAlias(city) {
    var raw = String(city || '').split(',')[0].trim().toLowerCase();
    if (!raw) return '';
    var keys = Object.keys(_CITY_KO_ALIAS);
    for (var i = 0; i < keys.length; i++) {
      var k = keys[i].toLowerCase();
      if (k === raw || raw.indexOf(k) >= 0 || k.indexOf(raw) >= 0) return _CITY_KO_ALIAS[keys[i]];
    }
    return '';
  }
  // ★ (2026-07-23) 도시 칩 라벨 — 한글 별칭 우선. 영문 원문은 길이 편차가 커서(San Quirico d'Orcia
  //   vs Siena) 칩 높이가 제각각이 되던 원인. 별칭 없으면 영문 짧은 이름.
  function _cityLabelShort(raw) {
    return _cityKoAlias(raw) || _displayCityShort(raw) || '';
  }
  var _cityDateCache = null; // 렌더당 1회만 계산 (좌표 매칭이 무거워 매 칩마다 돌지 않게)
  function _cityDateCacheReset() { _cityDateCache = null; }
  function _cityDateInfo(city) {
    var ckey = _normCityKey(city) || String(city || '');
    if (!_cityDateCache) _cityDateCache = {};
    if (_cityDateCache[ckey] !== undefined) return _cityDateCache[ckey];
    var out = _cityDateInfoCalc(city);
    _cityDateCache[ckey] = out;
    return out;
  }
  function _cityDateInfoCalc(city) {
    var stay = _cityStayRange(city);
    if (stay) {
      var sh = _cityStayHit(city) || {};
      return { text: stay, kind: 'stay', s0: sh.start_date || '', e0: sh.end_date || sh.start_date || '' };
    }
    if (!city) return { text: '', kind: '' };
    var nc = _normCityKey(city);
    if (!nc) return { text: '', kind: '' };
    var j = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var md2 = function(ds) {
      var m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(String(ds || ''));
      return m ? (+m[2]) + '/' + (+m[3]) : '';
    };
    var pack = function(min, max) {
      if (!min) return null;
      var s = md2(min), e = md2(max);
      return { text: (e && e !== s) ? (s + '~' + e) : s, kind: 'daytrip', s0: min, e0: max || min };
    };
    var isSched = function(it) {
      return it && it.type === '일정' && it.date && /^\d{4}-\d{2}-\d{2}$/.test(String(it.date));
    };

    // 1) 좌표 매칭 — 해당 도시 스팟들의 중심점에서 15km 이내 일정
    var cx = 0, cy = 0, cn = 0;
    for (var s = 0; s < j.length; s++) {
      var sp = j[s];
      if (!sp || sp.type !== '스팟') continue;
      if (typeof sp.lat !== 'number' || typeof sp.lng !== 'number') continue;
      var sn = _normCityKey(sp.city || '');
      if (!sn) continue;
      if (!(sn === nc || sn.indexOf(nc) >= 0 || nc.indexOf(sn) >= 0)) continue;
      cx += sp.lat; cy += sp.lng; cn++;
    }
    if (cn) {
      var ctr = { lat: cx / cn, lng: cy / cn };
      var gmin = '', gmax = '';
      for (var g = 0; g < j.length; g++) {
        var gi = j[g];
        if (!isSched(gi)) continue;
        if (typeof gi.lat !== 'number' || typeof gi.lng !== 'number') continue;
        if (_haversineKm(ctr, { lat: gi.lat, lng: gi.lng }) > 15) continue;
        var gd = String(gi.date);
        if (!gmin || gd < gmin) gmin = gd;
        if (!gmax || gd > gmax) gmax = gd;
      }
      var geoHit = pack(gmin, gmax);
      if (geoHit) return geoHit;
    }

    // 2) 기존 문자열 매칭 (일정의 city 필드)
    var min = '', max = '';
    for (var i = 0; i < j.length; i++) {
      var it = j[i];
      if (!isSched(it)) continue;
      var n = _normCityKey(it.city || '');
      if (!n) continue;
      if (!(n === nc || n.indexOf(nc) >= 0 || nc.indexOf(n) >= 0)) continue;
      var d = String(it.date);
      if (!min || d < min) min = d;
      if (!max || d > max) max = d;
    }
    var strHit = pack(min, max);
    if (strHit) return strHit;

    // 3) 한↔영 별칭 — 일정 제목/설명에 한글 도시명이 들어있으면 그 날짜 사용
    var ko = _cityKoAlias(city);
    if (ko) {
      var kmin = '', kmax = '';
      for (var k = 0; k < j.length; k++) {
        var ki = j[k];
        if (!isSched(ki)) continue;
        var hay = String(ki.title || '') + ' ' + String(ki.description || '') + ' ' + String(ki.city || '');
        if (hay.indexOf(ko) < 0) continue;
        var kd = String(ki.date);
        if (!kmin || kd < kmin) kmin = kd;
        if (!kmax || kd > kmax) kmax = kd;
      }
      var koHit = pack(kmin, kmax);
      if (koHit) return koHit;
    }
    return { text: '', kind: '' };
  }

  // 도시별로 다시 sub-group (한 국가 안에서)
  function _groupSouvenirsByCity(items) {
    var groups = {};
    var keys = [];
    items.forEach(function(it) {
      var key = String(it.city || '미지정');
      if (!groups[key]) {
        groups[key] = { city: key, rank: _souvenirCityRank(key), items: [] };
        keys.push(key);
      }
      groups[key].items.push(it);
    });
    // 여행 순서대로 정렬 — citiesData 순서 우선, 그 외는 알파벳/가나다
    keys.sort(function(a, b) {
      var ra = groups[a].rank, rb = groups[b].rank;
      if (ra !== rb) return ra - rb;
      return a.localeCompare(b, 'ko');
    });
    // 각 도시 그룹 안에서 카테고리 정렬
    keys.forEach(function(k) {
      groups[k].items.sort(function(a, b) {
        var ra = _souvenirCatRank(a.title), rb = _souvenirCatRank(b.title);
        if (ra !== rb) return ra - rb;
        return String(a.title || '').localeCompare(String(b.title || ''), 'ko');
      });
    });
    return keys.map(function(k) { return groups[k]; });
  }

  function renderJourneySouvenir() {
    var container = document.getElementById('journey-souvenir-list');
    if (!container) return;
    _trvFxWarm(); // € 금액 원화 병기용 환율 (도착하면 카드 재렌더)

    if (!isSeedTrip()) {
      var fbItems = journeyData.filter(function(d){ return d.type === '기념품'; });
      if (fbItems.length === 0) { container.innerHTML = '<div class="text-center py-6 text-sm text-slate-400">기념품을 추가해봐!</div>'; return; }
      var svBtn = document.getElementById('sv-photo-fill-btn');
      if (svBtn && !svBtn.getAttribute('data-running')) {
        var noImg = fbItems.filter(function(d){ return d._id && !d.photo_url && !d.photo_none; }).length;
        svBtn.style.display = noImg ? '' : 'none';
        svBtn.innerHTML = '<span class="material-symbols-outlined">image</span> 이미지 채우기 (' + noImg + ')';
      }
      var groupsFb = _groupSouvenirsByCountry(fbItems);
      container.innerHTML = '<div class="sv-grid">' +
        groupsFb.map(function(g) {
          return _svCountryBlockHtml(g, function(item) {
            var realIdx = journeyData.indexOf(item);
            var checked = item.status === '완료';
            return svRowSt(item, checked,
              'toggleSouvenir(' + realIdx + ',' + !checked + ')',
              'deleteJourneyRow(' + realIdx + ')',
              'editJourneyItem(' + realIdx + ')',
              'fbInlineEdit(this,' + realIdx + ',\'%FIELD%\',\'기념품\')',
              'svPartEdit(this,' + realIdx + ',\'%PART%\',\'fb\')', realIdx, 'fb');
          });
        }).join('') +
      '</div>';
      return;
    }
    var data = getSouvenirData();
    if (data.length === 0) { container.innerHTML = '<div class="text-center py-6 text-sm text-slate-400">기념품을 추가해봐!</div>'; return; }
    var groupsSeed = _groupSouvenirsByCountry(data);
    container.innerHTML = '<div class="sv-grid">' +
      groupsSeed.map(function(g) {
        return _svCountryBlockHtml(g, function(item) {
          var origIdx = data.indexOf(item);
          return svRowSt(item, item.checked,
            'toggleSouvenirLocal(' + origIdx + ')',
            'deleteSouvenirLocal(' + origIdx + ')',
            'openSouvenirEditModal(' + origIdx + ')',
            'souvenirInlineEdit(this,' + origIdx + ',\'%FIELD%\')',
            'svPartEdit(this,' + origIdx + ',\'%PART%\',\'seed\')', origIdx, 'seed');
        });
      }).join('') +
    '</div>';
  }

