  window._enrichCanadaDailyLog = async function() {
    var tripName = '2027 캐나다 여행';
    var trip = (tripsData || []).find(function(t){ return t.name === tripName; });
    if (!trip) { alert('"' + tripName + '" trip을 못 찾았어. 먼저 _migrateAtlasTrip("canada-2027") 실행해줘.'); return; }

    // 기존 일정·도시·숙소 조회
    var existing = (journeyData || []).filter(function(d){ return d.trip_id === trip._id && d.type === '일정'; });
    var allCities = (citiesData || []).filter(function(c){ return c.trip_id === trip._id; });
    var allLodging = (journeyData || []).filter(function(d){ return d.trip_id === trip._id && d.type === '숙소'; });
    // Mont-Tremblant 도시·숙소 제거 대상
    var tremblantCities = allCities.filter(function(c){ return /tremblant|몽트랑블랑/i.test(c.name || ''); });
    var tremblantLodging = allLodging.filter(function(d){ return /tremblant|몽트랑블랑/i.test((d.city || '') + ' ' + (d.title || '')); });

    var msg = '"' + tripName + '" 전체 재구성\n\n' +
      '• 새 날짜: 2027-09-24 ~ 2027-10-03 (10일)\n' +
      '• KE073 + AC063 1순위 항공편 매칭\n' +
      '• Mont-Tremblant 1박 제거\n\n' +
      '• 기존 일정 ' + existing.length + '개 삭제\n' +
      '• 새 시간 슬롯 ' + _CA_DETAILED_LOG.length + '개 추가 (10일)\n' +
      '• Mont-Tremblant 도시 ' + tremblantCities.length + '개 제거\n' +
      '• Mont-Tremblant 숙소 ' + tremblantLodging.length + '개 제거\n' +
      '• Trip 날짜 → 2027-09-24 ~ 2027-10-03\n\n진행할까?';
    if (!confirm(msg)) return;

    try {
      // 1. 기존 일정 삭제
      var deleted = 0;
      for (var di = 0; di < existing.length; di++) {
        try { await fbDelete('journey', existing[di]._id); deleted++; } catch(e) {}
      }
      journeyData = (journeyData || []).filter(function(d){
        return !(d.trip_id === trip._id && d.type === '일정');
      });

      // 1-b. Mont-Tremblant 도시·숙소 삭제
      var citiesDel = 0, lodgeDel = 0;
      for (var ci = 0; ci < tremblantCities.length; ci++) {
        try { await fbDelete('trip_cities', tremblantCities[ci]._id); citiesDel++; } catch(e) {}
      }
      for (var li = 0; li < tremblantLodging.length; li++) {
        try { await fbDelete('journey', tremblantLodging[li]._id); lodgeDel++; } catch(e) {}
      }
      citiesData = (citiesData || []).filter(function(c){
        return !(c.trip_id === trip._id && /tremblant|몽트랑블랑/i.test(c.name || ''));
      });
      journeyData = (journeyData || []).filter(function(d){
        return !(d.trip_id === trip._id && d.type === '숙소' && /tremblant|몽트랑블랑/i.test((d.city || '') + ' ' + (d.title || '')));
      });

      // 1-c. Trip 날짜 업데이트
      try {
        await fbUpdate('trips', trip._id, { start_date: '2027-09-24', end_date: '2027-10-03' });
        trip.start_date = '2027-09-24';
        trip.end_date = '2027-10-03';
      } catch(e) { console.warn('[CanadaEnrich] trip 날짜 갱신 실패:', e); }

      // 2. 새 detailed entries 추가
      var added = 0;
      for (var ai = 0; ai < _CA_DETAILED_LOG.length; ai++) {
        var slot = _CA_DETAILED_LOG[ai];
        try {
          var saved = await fbAdd('journey', {
            trip_id: trip._id, type: '일정',
            date: slot.date, time: slot.time, end_time: slot.end_time,
            city: slot.city, title: slot.title, description: slot.description,
          });
          journeyData.push(saved);
          added++;
        } catch(e) { console.warn('[CanadaEnrich] add 실패:', e); }
      }

      // 3. 스냅샷 갱신
      try {
        localStorage.setItem('atelier_snapshot_journey', JSON.stringify({ data: journeyData, ts: new Date().toISOString() }));
        localStorage.setItem('atelier_snapshot_trip_cities', JSON.stringify({ data: citiesData, ts: new Date().toISOString() }));
        localStorage.setItem('atelier_snapshot_trips', JSON.stringify({ data: tripsData, ts: new Date().toISOString() }));
      } catch(e) { console.warn('[CanadaEnrich] snapshot 갱신 실패:', e.message); }

      alert('✅ 캐나다 재구성 완료\n\n' +
        '· 일정 삭제: ' + deleted + '개 · 새 슬롯: ' + added + '개\n' +
        '· Mont-Tremblant 도시 ' + citiesDel + ' · 숙소 ' + lodgeDel + ' 제거\n' +
        '· Trip 날짜: 2027-09-24 ~ 2027-10-03\n\n페이지 새로고침 후 확인.');

      if (currentTripId === trip._id) {
        renderCityCards();
        renderDayView();
        renderJourneyLodging();
        renderJourneyFlights();
      } else {
        selectTrip(trip._id);
      }
    } catch (e) {
      console.error('[CanadaEnrich] 실패:', e);
      alert('재구성 중 에러: ' + e.message);
    }
  };

  window._migrateAtlasTrip = async function(atlasId) {
    if (!window.ATLAS_DATA || !window.ATLAS_DATA.TRIPS) {
      alert('ATLAS_DATA가 로드되지 않았어요. Atlas 페이지 한 번 방문 후 다시 시도해줘.');
      return;
    }
    var atlas = window.ATLAS_DATA.TRIPS.find(function(t){ return t.id === atlasId; });
    if (!atlas) { alert('Atlas trip 못 찾음: ' + atlasId); return; }
    var newTripName = _ATLAS_TRIP_NAME[atlasId] || atlas.title;

    // 이미 마이그레이션됐는지 체크
    var existing = (tripsData || []).find(function(t){ return t.name === newTripName; });
    if (existing) {
      if (!confirm('"' + newTripName + '"는 이미 존재해. 그래도 다시 마이그레이션할까? (중복 데이터 생성됨)')) return;
    }

    // 카운트 계산 + 확인 다이얼로그
    var cities = _atlasGroupCities(atlas);
    var itinCount = atlas.itinerary.length;
    var lodgingCount = (atlas.lodging || []).length;
    var souvenirs = _ATLAS_SOUVENIRS[atlasId] || [];
    var msg = newTripName + ' 마이그레이션 시작?\n\n' +
      '· 도시: ' + cities.length + '개\n' +
      '· 일정: ' + itinCount + '일\n' +
      '· 숙소: ' + lodgingCount + '개\n' +
      '· 기념품: ' + souvenirs.length + '개\n\n' +
      '(비행기·기차·교통은 제외 — 사용자가 직접 추가)';
    if (!confirm(msg)) return;

    var startDate = _atlasDate(atlas.itinerary[0].date, atlas.year);
    var endDate = _atlasDate(atlas.itinerary[atlas.itinerary.length - 1].date, atlas.year);

    try {
      // 1. trips
      var tripObj = { name: newTripName, start_date: startDate, end_date: endDate };
      var savedTrip = await fbAdd('trips', tripObj);
      var tripId = savedTrip._id;
      tripsData.push(savedTrip);
      console.log('[Migrate] trip 생성:', newTripName, tripId);

      // 2. trip_cities
      for (var ci = 0; ci < cities.length; ci++) {
        var c = cities[ci];
        await fbAdd('trip_cities', {
          trip_id: tripId, name: c.name,
          start_date: c.start_date, end_date: c.end_date,
          nights: c.nights, desc: '', transit_guide: '', order: c.order,
        });
      }
      console.log('[Migrate] cities 생성:', cities.length);

      // 3. journey 일정 (itinerary)
      var itinAdded = 0;
      for (var ii = 0; ii < atlas.itinerary.length; ii++) {
        var d = atlas.itinerary[ii];
        var date = _atlasDate(d.date, atlas.year);
        var stayParsed = _atlasParseStay(d.stay);
        if (!date) continue;
        // <i> 태그 제거, 마침표는 보존
        var cleanActivity = String(d.activity || '').replace(/<\/?i>/g, '').trim();
        await fbAdd('journey', {
          trip_id: tripId, type: '일정', date: date,
          city: stayParsed.city || '',
          title: cleanActivity.substring(0, 80),
          description: cleanActivity.length > 80 ? cleanActivity : '',
        });
        itinAdded++;
      }
      console.log('[Migrate] 일정 생성:', itinAdded);

      // 4. journey 숙소 (lodging)
      // Atlas lodging 항목 → 첫 등장일을 check-in으로 매핑
      var cityCheckin = {};
      cities.forEach(function(c){ cityCheckin[c.name] = c; });
      var lodgeAdded = 0;
      for (var li = 0; li < (atlas.lodging || []).length; li++) {
        var lg = atlas.lodging[li];
        var info = cityCheckin[lg.name];
        if (!info) continue;
        // 가격 (예: "20 만 / 박" or "13 만") → 원화 숫자 추출
        var priceNum = parseInt(String(lg.price || '').replace(/[^0-9]/g,'')) || 0;
        priceNum = priceNum * 10000; // 만원 → 원
        var perNight = /\/\s*박/.test(lg.price);
        var totalPrice = perNight ? priceNum * lg.nights : priceNum;
        await fbAdd('journey', {
          trip_id: tripId, type: '숙소',
          city: lg.name,
          title: lg.name + ' ' + lg.type,
          date: info.start_date, checkout_date: info.end_date,
          checkin: '15:00', checkout: '11:00',
          amount: totalPrice,
          cancel: '가능',
          payment_status: '결제 예정',
          notes: lg.type + (perNight ? ' · ' + lg.nights + '박' : ''),
        });
        lodgeAdded++;
      }
      console.log('[Migrate] 숙소 생성:', lodgeAdded);

      // 5. journey 기념품
      var soufAdded = 0;
      for (var si = 0; si < souvenirs.length; si++) {
        var sv = souvenirs[si];
        await fbAdd('journey', {
          trip_id: tripId, type: '기념품',
          city: sv.city,
          title: sv.title, description: sv.description,
          amount: sv.amount,
          status: '예정',
        });
        soufAdded++;
      }
      console.log('[Migrate] 기념품 생성:', soufAdded);

      // ★ localStorage 스냅샷 갱신 (새로고침 후에도 새 trip 보이게)
      //   원인: fbAdd는 Firestore에만 쓰고 snapshot 갱신은 fbRead 시점에만 일어남
      //   → 마이그레이션 직후 새로고침하면 옛 스냅샷(2개)으로 잠깐 보였다가 fbRead 후 4개로 갱신됨
      //   → 사용자가 그 사이에 새 trip 못 찾는 문제 해결을 위해 즉시 스냅샷 갱신
      try {
        localStorage.setItem('atelier_snapshot_trips', JSON.stringify({
          data: tripsData, ts: new Date().toISOString()
        }));
        console.log('[Migrate] trips 스냅샷 갱신:', tripsData.length, '개');
      } catch(e) {
        // QuotaExceeded 같은 에러 — 사용자 데이터는 Firestore에 있으니 안전
        console.warn('[Migrate] 스냅샷 갱신 실패 (Firestore에는 정상 저장됨):', e.message);
      }

      alert('✅ ' + newTripName + ' 마이그레이션 완료\n\n' +
        '· trip 1개\n· 도시 ' + cities.length + '개\n· 일정 ' + itinAdded + '개\n' +
        '· 숙소 ' + lodgeAdded + '개\n· 기념품 ' + soufAdded + '개\n\n' +
        '드롭다운에서 "' + newTripName + '" 선택해서 확인해줘.');

      // 새 trip으로 즉시 전환
      selectTrip(tripId);
    } catch (e) {
      console.error('[Migrate] 실패:', e);
      alert('마이그레이션 중 에러 발생: ' + e.message + '\n\n콘솔 확인.');
    }
  };

  async function saveTripEntry() {
    var obj = {
      name: document.getElementById('trip-name').value,
      start_date: document.getElementById('trip-start').value,
      end_date: document.getElementById('trip-end').value,
      // imageUrl is managed via dashboard upload, not modal
    };
    if (!obj.name) return alert('여행 이름을 입력해줘!');
    var editId = document.getElementById('trip-modal').dataset.editId;
    try {
      if (editId) {
        await fbUpdate('trips', editId, obj);
        var t = tripsData.find(function(t){ return t._id === editId; });
        if (t) Object.assign(t, obj);
        delete document.getElementById('trip-modal').dataset.editId;
        document.getElementById('trip-modal-title').textContent = '여행 추가';
        closeTripModal();
        selectTrip(editId);
      } else {
        var saved = await fbAdd('trips', obj);
        tripsData.push(saved);
        closeTripModal();
        selectTrip(saved._id);
      }
    } catch(err) { alert('저장에 실패했어요.'); }
  }

