  // ===== PLANNER → MATRIX SYNC =====
  const PLANNER_TO_MATRIX = {
    '영어': 'english',
    '글쓰기': 'writing',
    '스터디': 'ai_study',
    '업무': 'work',
    '개인': 'personal',
    '연차': 'leave',
    '생일': 'personal',
  };

  // 매트릭스 필드 → 캘린더 카테고리 역매핑
  // ★ 첫 매핑 우선 (2026-07-14): '생일'→'personal'이 '개인'을 덮어써서
  //   personal 셀 저장 시 '생일' 카테고리 복제 이벤트가 증식하던 버그 수정.
  var MATRIX_TO_PLANNER = {};
  Object.keys(PLANNER_TO_MATRIX).forEach(function(k){
    var f = PLANNER_TO_MATRIX[k];
    if (!MATRIX_TO_PLANNER[f]) MATRIX_TO_PLANNER[f] = k;
  });

  var _MATRIX_FIELDS = ['date','day','work','leave','personal','writing','serial1','english','ai_study','workingout'];

  // ★ 공용 (2026-07-15): 특정 날짜의 매트릭스 매핑 칸 "기대값" = 그 날짜에 걸친
  //   캘린더 일정 제목들의 join. 벌크 동기화(loadPlanner/loadMatrix)와 동일 규칙
  //   (연차 '1.0 ' prefix + 주말/공휴일 스킵, 다일 일정 포함) — 구현 불일치로
  //   저장할 때와 로드할 때 값이 달라지던 문제의 근원 제거.
  function computeMatrixCell(dateStr, fieldIdx) {
    var vals = [];
    (plannerData || []).forEach(function(r) {
      if (!r || !r[0] || !r[1]) return;
      var cat = (r[2] || '').trim();
      var f = PLANNER_TO_MATRIX[cat];
      if (cat === '글쓰기' && _isPublishingEvent(r[1], r[4])) f = 'serial1';
      if (!f || _MATRIX_FIELDS.indexOf(f) !== fieldIdx) return;
      var end = r[5] || r[0];
      if (dateStr < r[0] || dateStr > end) return;
      var v = r[1];
      if (cat === '연차') {
        var d = new Date(dateStr + 'T00:00:00');
        var hol = getKoreanHolidays(d.getFullYear());
        if (d.getDay() === 0 || d.getDay() === 6 || hol[dateStr]) return;
        v = '1.0 ' + r[1];
      }
      vals.push(v);
    });
    return vals.join(', ');
  }

  async function syncMatrixToPlanner(matrixRow) {
    var date = matrixRow[0];
    if (!date) return;
    // ★ 안전화 (2026-07-15):
    //   ① 작품 일정(work_id/phase 마커)은 절대 건드리지 않음 — 매트릭스 셀 저장이
    //      연재 이벤트 제목을 덮어쓰거나 지우던 사고 차단
    //   ② 셀 값이 '캘린더에서 파생된 기대값'과 같으면 스킵 — 다른 셀만 고쳐도
    //      전 필드가 재동기화되며 "A, B" joined 문자열이 이벤트로 역류하던 증식 차단
    //   ③ 다일 일정은 기간 전체로 매칭 (시작일만 비교해 중간 날짜에 복제 생성되던 버그)
    var isWorkEvt = function(r) { var n = (r[4] || '') + ''; return n.indexOf('work_id:') >= 0 || n.indexOf('phase:') >= 0; };
    for (var fi = 2; fi < _MATRIX_FIELDS.length; fi++) {
      var val = (matrixRow[fi] || '').toString().trim();
      var catName = MATRIX_TO_PLANNER[_MATRIX_FIELDS[fi]];
      if (!catName) continue;
      if (val === computeMatrixCell(date, fi)) continue;  // ② 파생값 그대로면 변경 아님
      // 해당 날짜(기간 포함)+카테고리의 일반(비작품) 일정만 후보로
      var candidates = plannerData.filter(function(r) {
        if (!r || r[2] !== catName || isWorkEvt(r)) return false;
        var end = r[5] || r[0];
        return date >= r[0] && date <= end;
      });
      // ★ 다일 일정 보호: 이 날짜에 '시작'하는 일정만 수정/삭제 대상.
      //   기간 중간 날짜의 셀 편집으로 5일짜리 일정이 통째 개명/삭제되던 버그 방지.
      var sameDay = candidates.filter(function(r) { return r[0] === date; });
      if (val) {
        var color = CAT_COLOR[catName] || 'slate';
        if (sameDay.length > 0) {
          var target = sameDay[0];
          if (target[1] !== val) {
            target[1] = val;
            var pid = target[7];
            if (pid) try { await fbUpdate('planner', pid, { title: val }); } catch(e) {}
          }
        } else if (candidates.length > 0) {
          // 다일 일정이 걸쳐 있을 뿐 — 개명도 신규 생성도 하지 않음 (no-op)
        } else {
          var newRow = [date, val, catName, color, '', '', '0'];
          try {
            var saved = await fbAdd('planner', rowToObj('planner', newRow));
            plannerData.push(newRow.concat([saved._id]));
          } catch(e) {}
        }
      } else {
        // 빈칸 = 이 날짜에서 시작하는 '단일' 일정만 삭제 (다일 일정·작품 일정 보호)
        var delTargets = sameDay.filter(function(r) { return !r[5] || r[5] === r[0]; });
        for (var ci = 0; ci < delTargets.length; ci++) {
          var pid2 = delTargets[ci][7];
          if (pid2) try { await fbDelete('planner', pid2); } catch(e) {}
        }
        if (delTargets.length) {
          var delSet = new Set(delTargets);
          plannerData = plannerData.filter(function(r) { return !delSet.has(r); });
        }
      }
    }
  }

  function _isPublishingEvent(title, notes) {
    if ((notes || '').indexOf('phase:publishing') >= 0) return true;
    return /^\d+화\s*\(/.test(title || '');
  }

  async function syncPlannerToMatrix(plannerRow) {
    if (!plannerRow) return;
    var startDate = plannerRow[0];
    var endDate = plannerRow[5] || startDate;
    var category = plannerRow[2];
    var title = plannerRow[1];
    var notes = plannerRow[4] || '';
    // 글쓰기 카테고리 중 연재 이벤트는 serial1 칸으로
    var matrixField = PLANNER_TO_MATRIX[category];
    if (category === '글쓰기' && _isPublishingEvent(title, notes)) {
      matrixField = 'serial1';
    }
    if (!startDate || !matrixField) return;

    var fieldIdx = _MATRIX_FIELDS.indexOf(matrixField);
    if (fieldIdx <= 0) return;

    // 시작일~종료일 모든 날짜에 대해 매트릭스 동기화
    // ★ (2026-07-15) 제목 단독 덮어쓰기 → computeMatrixCell(그 날짜 전체 일정 join)로 통일.
    //   벌크 동기화와 같은 규칙이라 로드할 때마다 값이 되돌아가던 불일치 제거.
    var cur = new Date(startDate + 'T00:00:00');
    var end = new Date(endDate + 'T00:00:00');
    var days = ['일','월','화','수','목','금','토'];

    try {
      while (cur <= end) {
        var dateStr = cur.getFullYear() + '-' + String(cur.getMonth()+1).padStart(2,'0') + '-' + String(cur.getDate()).padStart(2,'0');
        var cellVal = computeMatrixCell(dateStr, fieldIdx);
        var existing = matrixData.find(function(r){ return r[0] === dateStr; });
        if (existing) {
          if (existing[fieldIdx] !== cellVal) {
            existing[fieldIdx] = cellVal;
            var existId = existing[10] || existing[9];
            if (existId) await fbUpdate('matrix', existId, rowToObj('matrix', existing));
          }
        } else if (cellVal) {
          var dayName = days[cur.getDay()];
          var newRow = [dateStr, dayName, '', '', '', '', '', '', '', ''];
          newRow[fieldIdx] = cellVal;
          var saved = await fbAdd('matrix', rowToObj('matrix', newRow));
          matrixData.push(newRow.concat([saved._id]));
        }
        cur.setDate(cur.getDate() + 1);
      }
    } catch(err) {
      console.error('Matrix sync error:', err);
    }
  }


  // ===== INCOME GOALS =====
  let incomeGoals = [];
  let editingGoalIndex = null;

  async function loadIncomeGoals() {
    try {
      const docs = await fbRead('income_goals');
      incomeGoals = docs;
      renderIncomeGoals();
    } catch(err) { console.error('Goals load error:', err); }
  }

  function renderIncomeGoals() {
    var el = document.getElementById('income-goals-list');
    if (!el) return;
    if (incomeGoals.length === 0) {
      el.innerHTML = '<div class="text-xs text-slate-400 text-center py-4">목표를 추가해봐!</div>';
      return;
    }
    var qMap = {'Q1':['1월','2월','3월'],'Q2':['4월','5월','6월'],'Q3':['7월','8월','9월'],'Q4':['10월','11월','12월']};
    el.innerHTML = incomeGoals.map(function(g, i) {
      var amt = parseFloat((g.amount||'0').toString().replace(/,/g,''))||0;
      var series = g.series||'';
      var quarter = g.quarter||'';

      // 시리즈 + 분기 기준으로 달성액 계산
      var achieved = incomeData.reduce(function(s, r) {
        var catMatch = !series || (r[2]||'') === series;
        var qMatch = !quarter || (qMap[quarter] && qMap[quarter].includes(r[0]));
        if (catMatch && qMatch) {
          return s + (parseFloat((r[4]||'0').toString().replace(/,/g,''))||0);
        }
        return s;
      }, 0);

      var pct = amt > 0 ? Math.min(Math.round((achieved/amt)*100), 100) : 0;
      var pctColor = pct >= 100 ? 'bg-teal-500' : pct >= 70 ? 'bg-indigo-500' : pct >= 30 ? 'bg-blue-400' : 'bg-slate-300';
      var pctTextColor = pct >= 100 ? 'text-teal-600' : pct >= 70 ? 'text-indigo-600' : 'text-slate-500';
      var subtitle = [series, quarter].filter(Boolean).join(' · ') || '전체';

      return '<div class="bg-white rounded-xl p-4 border border-slate-100 shadow-sm group">' +
        '<div class="flex items-start justify-between mb-2">' +
        '<div class="flex-1">' +
        '<div class="flex items-center gap-2 mb-0.5">' +
        (series ? '<span class="text-[9px] font-black uppercase px-2 py-0.5 bg-indigo-50 text-indigo-600 border border-indigo-100 rounded-full">' + series + '</span>' : '') +
        (quarter ? '<span class="text-[9px] font-black uppercase px-2 py-0.5 bg-slate-100 text-slate-500 border border-slate-200 rounded-full">' + quarter + '</span>' : '') +
        '</div>' +
        '<p class="text-sm font-bold text-slate-800">' + (g.title||'') + '</p>' +
        '<p class="text-[10px] text-slate-400 font-medium mt-0.5">목표 ₩' + amt.toLocaleString('ko-KR') + '</p>' +
        '</div>' +
        '<div class="flex gap-1 opacity-0 group-hover:opacity-100 transition-all shrink-0 ml-2">' +
        '<button onclick="editIncomeGoal(' + i + ')" class="p-1 hover:bg-indigo-100 rounded-lg text-slate-300 hover:text-indigo-600"><span class="material-symbols-outlined text-sm">edit</span></button>' +
        '<button onclick="deleteIncomeGoal(' + i + ')" class="p-1 hover:bg-rose-100 rounded-lg text-slate-300 hover:text-rose-500"><span class="material-symbols-outlined text-sm">delete</span></button>' +
        '</div></div>' +
        '<div class="flex items-center gap-3 mt-3">' +
        '<div class="flex-1 h-2.5 bg-slate-100 rounded-full overflow-hidden">' +
        '<div class="h-full ' + pctColor + ' rounded-full transition-all" style="width:' + pct + '%"></div></div>' +
        '<span class="text-xs font-black ' + pctTextColor + ' shrink-0 w-10 text-right">' + pct + '%</span>' +
        '</div>' +
        '<div class="flex justify-between mt-1.5">' +
        '<p class="text-[10px] text-slate-400">달성 ₩' + achieved.toLocaleString('ko-KR') + '</p>' +
        '<p class="text-[10px] text-slate-400">잔여 ₩' + Math.max(0, amt-achieved).toLocaleString('ko-KR') + '</p>' +
        '</div>' +
        '</div>';
    }).join('');
  }

  function openIncomeGoalModal(idx) {
    editingGoalIndex = (idx !== undefined) ? idx : null;
    document.getElementById('income-goal-modal-title').textContent = editingGoalIndex !== null ? '목표 수정' : '목표 추가';

    // Populate series dropdown from categories
    var seriesSel = document.getElementById('ig-series');
    seriesSel.innerHTML = '<option value="">— 시리즈 선택 —</option>';
    incomeCategories.forEach(function(c) {
      seriesSel.innerHTML += '<option value="' + c.name + '">' + c.name + '</option>';
    });

    if (editingGoalIndex !== null) {
      var g = incomeGoals[editingGoalIndex];
      document.getElementById('ig-series').value = g.series||'';
      document.getElementById('ig-title').value = g.title||'';
      document.getElementById('ig-amount').value = g.amount ? Number(g.amount).toLocaleString('ko-KR') : '';
      document.getElementById('ig-quarter').value = g.quarter||'';
    } else {
      document.getElementById('ig-series').value = '';
      document.getElementById('ig-title').value = '';
      document.getElementById('ig-amount').value = '';
      document.getElementById('ig-quarter').value = '';
    }
    document.getElementById('income-goal-modal').style.cssText = 'display:flex!important';
  }

  function closeIncomeGoalModal() {
    document.getElementById('income-goal-modal').style.cssText = 'display:none!important';
    editingGoalIndex = null;
  }

  async function saveIncomeGoal() {
    var btn = document.getElementById('income-goal-save-btn');
    btn.textContent = '저장 중...'; btn.disabled = true;
    var obj = {
      series: document.getElementById('ig-series').value,
      title: document.getElementById('ig-title').value,
      amount: document.getElementById('ig-amount').value.replace(/,/g,''),
      quarter: document.getElementById('ig-quarter').value,
    };
    try {
      if (editingGoalIndex !== null) {
        await fbUpdate('income_goals', incomeGoals[editingGoalIndex]._id, obj);
        Object.assign(incomeGoals[editingGoalIndex], obj);
      } else {
        var saved = await fbAdd('income_goals', obj);
        incomeGoals.push(saved);
      }
      renderIncomeGoals();
      closeIncomeGoalModal();
    } catch(err) { alert('저장에 실패했어요.'); }
    finally { btn.textContent = '저장'; btn.disabled = false; }
  }

  function editIncomeGoal(i) { openIncomeGoalModal(i); }

  async function deleteIncomeGoal(i) {
    try {
      await fbDelete('income_goals', incomeGoals[i]._id);
      incomeGoals.splice(i, 1);
      renderIncomeGoals();
    } catch(err) { alert('삭제에 실패했어요.'); }
  }

  // ===== SERIES BREAKDOWN =====
  function renderIncomeByCategory() {
    var el = document.getElementById('income-by-series');
    if (!el || incomeData.length === 0) {
      if (el) el.innerHTML = '<div class="text-xs text-slate-400 col-span-full text-center py-4">항목을 추가하면 자동으로 집계돼!</div>';
      return;
    }
    var cats = {};
    var monthSet = new Set();
    incomeData.forEach(function(r) {
      var cat = r[2] || '기타';
      var amt = parseFloat((r[4]||'0').toString().replace(/,/g,''))||0;
      if (!cats[cat]) cats[cat] = { total: 0, count: 0 };
      cats[cat].total += amt;
      cats[cat].count++;
      if (r[0]) monthSet.add(r[0]);
    });
    var months = monthSet.size || 1;
    var maxTotal = Math.max(...Object.values(cats).map(function(c){ return c.total; }), 1);

    el.innerHTML = Object.entries(cats).sort(function(a,b){ return b[1].total - a[1].total; }).map(function(entry) {
      var name = entry[0], data = entry[1];
      var pct = Math.round((data.total / maxTotal) * 100);
      var avg = Math.round(data.total / months);
      return '<div class="bg-slate-50 rounded-2xl p-5 group hover:bg-slate-100/60 transition-colors">' +
        '<div class="flex items-center justify-between mb-3">' +
        '<span class="text-xs font-bold text-slate-600 uppercase tracking-widest font-headline">' + name + '</span>' +
        '<span class="text-[10px] bg-indigo-100/80 text-indigo-600 px-2 py-0.5 rounded-full font-bold">' + data.count + '건</span>' +
        '</div>' +
        '<p class="text-2xl font-black text-slate-900 font-headline tracking-tight">₩' + data.total.toLocaleString('ko-KR') + '</p>' +
        '<p class="text-[10px] text-slate-400 font-medium mt-1">월 평균 ₩' + avg.toLocaleString('ko-KR') + '</p>' +
        '<div class="mt-4 h-1.5 bg-slate-200/60 rounded-full overflow-hidden">' +
        '<div class="h-full bg-gradient-to-r from-indigo-500 to-indigo-400 rounded-full transition-all" style="width:' + pct + '%"></div></div>' +
        '</div>';
    }).join('');
  }

