  // ── Travel/Travel Budget 통합 탭 ──
  // ═══ Travel 공통 탭바 (2026-07-22): 4개 탭에 흩어져 있던 복붙 탭바를 단일 렌더러로 ═══
  window._travelTabsHtml = function(active){
    var tabs = [
      ['schedule', 'route', '일정'],
      ['places', 'push_pin', '스팟'],
      ['flight', 'flight', '항공'],
      ['budget', 'payments', '예산'],
      ['checklist', 'checklist', '체크리스트'],
      ['atlas', 'public', 'Atlas']
    ];
    return '<nav class="trav-tabs">' + tabs.map(function(t){
      return '<button onclick="switchTravelTab(\'' + t[0] + '\')" class="trav-tab' + (t[0] === active ? ' trav-tab-active' : '') + '" data-tab="' + t[0] + '">' +
        '<span class="material-symbols-outlined">' + t[1] + '</span>' + t[2] + '</button>';
    }).join('') + '</nav>';
  };
  function renderTravelChrome(){
    document.querySelectorAll('[data-travel-tabs]').forEach(function(slot){
      slot.innerHTML = window._travelTabsHtml(slot.getAttribute('data-travel-tabs'));
    });
  }
  try { renderTravelChrome(); } catch(e) { console.warn('travel chrome', e); }

  // ═══ Travel 섹션 접기/펼치기 + Overview 스냅샷 밴드 (2026-07-22 Phase C) ═══
  window.trvToggleSec = function(secId, forceCollapsed) {
    var sec = document.getElementById(secId);
    if (!sec) return;
    var collapsed = (forceCollapsed === undefined) ? sec.getAttribute('data-collapsed') !== '1' : forceCollapsed;
    sec.setAttribute('data-collapsed', collapsed ? '1' : '0');
    Array.prototype.forEach.call(sec.children, function(ch) {
      if (ch.classList && ch.classList.contains('trv-sec-head')) return;
      if (collapsed) {
        // 원래 보이던 것만 접었다 기억 (recs처럼 원래 숨김이던 요소는 건드리지 않음)
        if (ch.style.display !== 'none') { ch.setAttribute('data-trv-hidden', '1'); ch.style.display = 'none'; }
      } else if (ch.getAttribute('data-trv-hidden') === '1') {
        ch.style.display = ''; ch.removeAttribute('data-trv-hidden');
      }
    });
    var chev = document.getElementById(secId + '-chev');
    if (chev) chev.textContent = collapsed ? 'expand_more' : 'expand_less';
    try {
      var m = JSON.parse(localStorage.getItem('trv_collapsed') || '{}');
      m[secId] = collapsed;
      localStorage.setItem('trv_collapsed', JSON.stringify(m));
    } catch(e) {}
  };
  window.trvRestoreCollapsed = function() {
    try {
      var m = JSON.parse(localStorage.getItem('trv_collapsed') || '{}');
      Object.keys(m).forEach(function(k) { if (m[k] && (window._trvLedgerIds || []).indexOf(k) < 0) window.trvToggleSec(k, true); });
    } catch(e) {}
  };

  // ═══ Records 장부 패널 (2026-07-22): 항공/숙소/이동/렌트/기념품 탭 전환 ═══
  window._trvLedgerIds = ['trv-flights', 'trv-lodging', 'trv-transport', 'trv-rental', 'trv-souvenir'];
  var _TRV_LEDGER_LABEL = { 'trv-flights': 'Flights', 'trv-lodging': 'Lodging', 'trv-transport': 'Transit', 'trv-rental': 'Rental', 'trv-souvenir': 'Souvenir' };
  window.trvLedgerShow = function(secId) {
    try { localStorage.setItem('trv_ledger_tab', secId); } catch(e) {}
    window.renderLedgerTabs();
  };
  window.renderLedgerTabs = function() {
    var nav = document.getElementById('trv-ledger-tabs');
    if (!nav) return;
    var active = 'trv-flights';
    try { active = localStorage.getItem('trv_ledger_tab') || 'trv-flights'; } catch(e) {}
    if (window._trvLedgerIds.indexOf(active) < 0) active = 'trv-flights';
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var domCnt = function(id) { var c = document.getElementById(id); return c ? c.children.length : 0; };
    var counts = {
      'trv-flights': Math.max(jd.filter(function(d) { return d.type === '항공편'; }).length, domCnt('journey-flight-list')),
      'trv-lodging': domCnt('journey-lodging-list'),
      'trv-transport': Math.max(jd.filter(function(d) { return d.type === '이동수단'; }).length, domCnt('journey-transport-list')),
      'trv-rental': domCnt('journey-rental-list'),
      'trv-souvenir': jd.filter(function(d) { return d.type === '기념품'; }).length
    };
    nav.innerHTML = window._trvLedgerIds.map(function(id) {
      return '<button class="trv-ltab' + (id === active ? ' is-active' : '') + '" onclick="trvLedgerShow(\'' + id + '\')">' +
        _TRV_LEDGER_LABEL[id] + '<span class="cnt">' + (counts[id] || 0) + '</span></button>';
    }).join('');
    window._trvLedgerIds.forEach(function(id) {
      var sec = document.getElementById(id);
      if (!sec) return;
      sec.style.display = (id === active) ? '' : 'none';
      if (id === active && sec.getAttribute('data-collapsed') === '1') window.trvToggleSec(id, false);
    });
  };

  // ═══ Places 스팟 저장소 (2026-07-22 Phase D) — POI pool → 일정 배치 ═══
  var PLACE_CATS = ['명소', '미술관·전시', '맛집', '카페·디저트', '쇼핑', '자연·전망', '기타'];
  var PLACE_CAT_ICONS = { '명소': 'attractions', '미술관·전시': 'museum', '맛집': 'restaurant',
    '카페·디저트': 'local_cafe', '쇼핑': 'shopping_bag', '자연·전망': 'landscape', '기타': 'place' };
  var _placeFilter = '전체';
  var _placeCountry = '전체';
  var _placeCity = '전체'; // ★ (2026-07-23) 국가 아래 도시 단계 (3단 필터: 국가 AND 도시 AND 카테고리)

  // 스팟 city → 국가 유추: "도시, 국가" 자체 표기 우선, 없으면 trip_cities 매칭
  function _placeCountryOf(city) {
    var raw = String(city || '').trim();
    if (!raw) return '기타';
    // "시에나 이탈리아" 같은 지역+국가 혼합은 마지막 단어만 국가로 (중복 탭 방지)
    var tail = function(s) { var toks = String(s).trim().split(/\s+/); return toks[toks.length - 1] || '기타'; };
    var parts = raw.split(',');
    if (parts.length > 1 && parts[parts.length - 1].trim()) return tail(parts[parts.length - 1]);
    var key = _normCityKey(raw);
    var cd = (typeof citiesData !== 'undefined' && citiesData) ? citiesData : [];
    for (var i = 0; i < cd.length; i++) {
      var nm = String(cd[i].name || '');
      if (_normCityKey(nm) === key) {
        var ps = nm.split(',');
        if (ps.length > 1 && ps[ps.length - 1].trim()) return tail(ps[ps.length - 1]);
        return '기타';
      }
    }
    return '기타';
  }

  // ★ (2026-07-23) 여행 순서(citiesData = start_date 순) 기준 국가 등장 순서
  function _placeCountryTripOrder() {
    var out = [], seen = {};
    var cd = (typeof citiesData !== 'undefined' && citiesData) ? citiesData : [];
    for (var i = 0; i < cd.length; i++) {
      var c = _placeCountryOf(cd[i].name || '');
      if (!c || c === '기타' || seen[c]) continue;
      seen[c] = true; out.push(c);
    }
    return out;
  }

  // 탭 정렬 랭크 — 여행 순서 우선, 트립에 없는 값은 뒤(가나다), '기타/미지정'은 항상 맨 뒤
  function _placeTabRank(name, tripOrder) {
    if (name === '기타' || name === '미지정') return 99999;
    var i = tripOrder.indexOf(name);
    return i >= 0 ? i : 9000;
  }

  // onclick 인자용 이스케이프 — 도시명의 아포스트로피(d'Orcia) 대응
  function _spotArg(s) {
    return String(s == null ? '' : s).replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/"/g, '&quot;');
  }

  // 스팟 city → Stops 도시 이미지 재사용 (journey-city-images.js)
  function _placeCityImg(city) {
    if (typeof journeyCityImageGet !== 'function') return null;
    var key = _normCityKey(city);
    if (!key) return null;
    var cd = (typeof citiesData !== 'undefined' && citiesData) ? citiesData : [];
    for (var i = 0; i < cd.length; i++) {
      if (_normCityKey(cd[i].name || '') === key) return journeyCityImageGet(String(cd[i]._id || ('idx-' + i)));
    }
    return null;
  }

  // ═══ ★ (2026-07-23) 스팟 대표 사진 (Google Places Photos) ═══
  //   findPlaceFromQuery → photos[0].getUrl(640px), 실패 시 textSearch 폴백. 항상 cb(url|null).
  function _placePhotoFor(query, cb) {
    try {
      if (!query || typeof google === 'undefined' || !google.maps || !google.maps.places) { cb(null); return; }
      var svc = new google.maps.places.PlacesService(document.createElement('div'));
      svc.findPlaceFromQuery({ query: query, fields: ['photos', 'place_id'] }, function(results, status) {
        try {
          if (status === google.maps.places.PlacesServiceStatus.OK && results && results[0] &&
              results[0].photos && results[0].photos.length) {
            cb(results[0].photos[0].getUrl({ maxWidth: 640 })); return;
          }
          svc.textSearch({ query: query }, function(r2, s2) {
            try {
              if (s2 === google.maps.places.PlacesServiceStatus.OK && r2 && r2[0] &&
                  r2[0].photos && r2[0].photos.length) {
                cb(r2[0].photos[0].getUrl({ maxWidth: 640 }));
              } else cb(null);
            } catch(e) { cb(null); }
          });
        } catch(e) { cb(null); }
      });
    } catch(e) { cb(null); }
  }
  window._placePhotoFor = _placePhotoFor;

  // ═══ ★ (2026-07-23) 스팟 구글 평점 파이프라인 ═══
  //   findPlaceFromQuery(place_id) → getDetails(rating/user_ratings_total/price_level).
  //   항상 cb({pid,rating,count,price_level}|null). price_level은 미제공 시 -1 (0=무료를 살리기 위해).
  function _placeRatingFor(query, cb) {
    try {
      if (!query || typeof google === 'undefined' || !google.maps || !google.maps.places) { cb(null); return; }
      var svc = new google.maps.places.PlacesService(document.createElement('div'));
      svc.findPlaceFromQuery({ query: query, fields: ['place_id'] }, function(results, status) {
        try {
          if (status !== google.maps.places.PlacesServiceStatus.OK || !results || !results[0] || !results[0].place_id) { cb(null); return; }
          var pid = results[0].place_id;
          svc.getDetails({ placeId: pid, fields: ['rating', 'user_ratings_total', 'price_level'] }, function(place, s2) {
            try {
              if (s2 !== google.maps.places.PlacesServiceStatus.OK || !place) { cb(null); return; }
              cb({ pid: pid,
                   rating: (typeof place.rating === 'number' ? place.rating : 0),
                   count: (typeof place.user_ratings_total === 'number' ? place.user_ratings_total : 0),
                   price_level: (typeof place.price_level === 'number' ? place.price_level : -1) });
            } catch(e) { cb(null); }
          });
        } catch(e) { cb(null); }
      });
    } catch(e) { cb(null); }
  }
  window._placeRatingFor = _placeRatingFor;

  function _spotEsc(s) {
    return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;')
      .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  }

  // 리뷰 수 한국식 축약 — 1만 이상 'X.X만', 미만은 그대로
  function _spotCountKo(n) {
    var v = Number(n) || 0;
    if (v < 10000) return String(v);
    var man = Math.round(v / 1000) / 10;
    return (man % 1 === 0 ? String(man) : man.toFixed(1)) + '만';
  }

  // 추천 정렬 점수 = 평점 × log10(리뷰수+1)
  function _spotScore(p) {
    var r = Number(p && p.g_rating) || 0;
    if (!r) return 0;
    var c = Number(p && p.g_count) || 0;
    return r * (Math.log(c + 1) / Math.LN10);
  }

  // 카드/패널용 평점 조각 — 평점 없으면 빈 문자열
  function _spotRatingHtml(p, big) {
    var r = Number(p && p.g_rating) || 0;
    if (!r) return '';
    var c = Number(p && p.g_count) || 0;
    return '<span class="spot-rating' + (big ? ' is-big' : '') + '">★ ' + r.toFixed(1) +
      (c ? ' <i>· ' + _spotCountKo(c) + '</i>' : '') + '</span>';
  }

  // ═══ ★ (2026-07-23) 스팟 가격 정보 — price_adult/price_note(수동) + price_level/g_price_level(구글 0~4) ═══
  // 0~4 정수만 인정, 없으면 -1 (0=무료를 살리기 위해 falsy 판정 대신 -1 사용)
  function _spotPriceLevelOf(p) {
    if (!p) return -1;
    var raw = (typeof p.price_level === 'number' || typeof p.price_level === 'string') ? p.price_level : p.g_price_level;
    var v = (typeof raw === 'string' && /^[0-4]$/.test(raw.trim())) ? parseInt(raw, 10) : raw;
    if (typeof v !== 'number' || !isFinite(v) || v < 0 || v > 4) return -1;
    return Math.round(v);
  }

  function _spotPriceLevelStr(lvl) {
    if (lvl < 0) return '';
    if (lvl === 0) return '무료';
    return new Array(lvl + 1).join('€');
  }

  // 가격대 기호는 맛집·카페처럼 1인 단가 감이 필요한 카테고리에만
  function _spotPriceLevelFor(p) {
    var cat = String((p && p.category) || '');
    if (cat !== '맛집' && cat !== '카페·디저트') return '';
    return _spotPriceLevelStr(_spotPriceLevelOf(p));
  }

  // € → ₩ 한 건 ('₩24,000', 환율 미로드면 '')
  function _spotKrwOf(eur) {
    var s = '';
    try { if (typeof window.fmtKrwFromEur === 'function') s = window.fmtKrwFromEur(eur) || ''; } catch(e) { s = ''; }
    return s.replace(/^≈\s*/, '');
  }

  // 문자열 안의 €금액을 모두 찾아 원화 병기 — "€18~25" → "€18~25 (≈₩24,000~33,000)"
  function _spotPriceHtml(str) {
    var s = String(str == null ? '' : str);
    if (!s) return '';
    var out = s.replace(/€\s?(\d+(?:[.,]\d+)?)(\s*[~\-–—]\s*€?\s*(\d+(?:[.,]\d+)?))?/g,
      function(m, a, r2, b) {
        var ka = _spotKrwOf(a);
        if (!ka) return m;
        var kb = b ? _spotKrwOf(b).replace(/^₩/, '') : ''; // 범위는 ₩ 한 번만
        return m + ' (≈' + ka + (kb ? '~' + kb : '') + ')';
      });
    return _spotEsc(out);
  }
  window._spotPriceHtml = _spotPriceHtml;

  // ═══ ★ (2026-07-23) € 원화 병기 Travel 공용 헬퍼 (스팟 전용 → 전역 승격) ═══
  // 원화 줄만 필요할 때 — "5~10" / "€5~10" → "≈₩8,000~16,000" (환율 미로드면 '')
  function _eurKrwOnly(str) {
    var s = String(str == null ? '' : str);
    var m = s.match(/(\d+(?:[.,]\d+)?)(?:\s*[~\-–—]\s*€?\s*(\d+(?:[.,]\d+)?))?/);
    if (!m) return '';
    var ka = _spotKrwOf(m[1]);
    if (!ka) return '';
    var kb = m[2] ? _spotKrwOf(m[2]).replace(/^₩/, '') : '';
    return '≈' + ka + (kb ? '~' + kb : '');
  }
  window._eurKrwOnly = _eurKrwOnly;

  // 숙소·교통·렌트·항공 카드 금액 — €면 원화 병기, 숫자만이면 기존 ₩ 포맷, 그 외는 원문 유지
  function _trvAmtHtml(amount) {
    var raw = String(amount == null ? '' : amount).trim();
    if (!raw) return '—';
    if (raw.indexOf('€') >= 0) return _spotPriceHtml(raw);
    if (/^[0-9][0-9.,]*$/.test(raw)) return '₩' + Number(raw.replace(/[^0-9.]/g, '')).toLocaleString('ko-KR');
    return _spotEsc(raw);
  }
  window._trvAmtHtml = _trvAmtHtml;

  // 환율 워밍업 — 비동기로 도착하면 € 표기가 있는 Records 카드들을 한 번 다시 그림
  var _trvFxWarmDone = false;
  function _trvFxWarm() {
    if (_trvFxWarmDone) return;
    _trvFxWarmDone = true;
    try {
      if (typeof getFxEurKrw !== 'function') return;
      var sync = true;
      getFxEurKrw(function(rate) {
        if (!rate || sync) return;
        ['renderJourneySouvenir', 'renderJourneyTransport', 'renderJourneyRental',
         'renderJourneyLodging', 'renderJourneyFlights'].forEach(function(fn) {
          try { if (typeof window[fn] === 'function') window[fn](); } catch(e) {}
        });
      });
      sync = false;
    } catch(e) {}
  }

  // 카드용 미니 한 줄 — "€€ · 🎫 €18 (≈₩24,000)"
  function _spotPriceMini(p) {
    var bits = [];
    var lvl = _spotPriceLevelFor(p);
    var adult = String((p && p.price_adult) || '').trim();
    if (lvl) bits.push('<b>' + _spotEsc(lvl) + '</b>');
    if (adult) bits.push('🎫 ' + _spotPriceHtml(adult));
    if (!bits.length) return '';
    return '<div class="spot-price">' + bits.join(' · ') + '</div>';
  }

  // 드로어용 전체 블록 — 입장료 + 부가 요금 메모 + 구글 가격대
  function _spotPriceBlock(p) {
    var rows = '';
    var adult = String((p && p.price_adult) || '').trim();
    var note = String((p && p.price_note) || '').trim();
    var lvl = _spotPriceLevelFor(p);
    if (adult) rows += '<div class="spot-dw-price-main">🎫 입장료 ' + _spotPriceHtml(adult) + '</div>';
    if (note) rows += '<div class="spot-dw-price-note">' + _spotPriceHtml(note) + '</div>';
    if (lvl) rows += '<div class="spot-dw-price-lvl">' + _spotEsc(lvl) + ' <i>구글 가격대</i></div>';
    if (!rows) return '';
    return '<div class="spot-dw-price">' + rows + '</div>';
  }

  // TOP 추천 이유 한 줄 — description 첫 문장 + 평점 요약
  function _spotWhyLine(p) {
    var d = String((p && p.description) || '').replace(/\s+/g, ' ').trim();
    var first = '';
    if (d) {
      var parts = d.split(/[.!?。\n]/);
      for (var i = 0; i < parts.length; i++) { if (parts[i].trim()) { first = parts[i].trim(); break; } }
      if (first.length > 46) first = first.slice(0, 46) + '…';
    }
    var r = Number(p && p.g_rating) || 0, c = Number(p && p.g_count) || 0;
    var rt = r ? ('★' + r.toFixed(1) + (c ? '(' + _spotCountKo(c) + ')' : '')) : '';
    if (first && rt) return first + ' · ' + rt;
    return first || rt;
  }

  // ── 스팟 ↔ 일정 제목 매칭: 이모지·괄호 제거 후 (a) 라틴 4자+ 상호 포함 (b) 한글 핵심 토큰 4자+ 포함
  function _spotNormTitle(s) {
    var t = String(s == null ? '' : s);
    t = t.replace(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2B00}-\u{2BFF}️→←⇄]/gu, ' ');
    t = t.replace(/\([^)]*\)/g, ' ').replace(/\[[^\]]*\]/g, ' ');
    t = t.replace(/[^0-9a-zA-Z가-힣\s]/g, ' ');
    return t.replace(/\s+/g, ' ').trim().toLowerCase();
  }

  function _spotSig(title) {
    var n = _spotNormTitle(title);
    var latin = n.replace(/[^a-z0-9]+/g, '');
    var kor = n.replace(/[^가-힣]/g, '');
    var toks = [];
    var parts = n.split(/[^가-힣]+/);
    for (var i = 0; i < parts.length; i++) { if (parts[i].length >= 4) toks.push(parts[i]); }
    if (kor.length >= 4 && toks.indexOf(kor) < 0) toks.push(kor);
    return { n: n, latin: latin, kor: kor, toks: toks };
  }

  function _spotSigMatch(a, b) {
    if (!a || !b || !a.n || !b.n) return false;
    if (a.n === b.n) return true;
    if (a.latin.length >= 4 && b.latin.length >= 4 &&
        (a.latin.indexOf(b.latin) >= 0 || b.latin.indexOf(a.latin) >= 0)) return true;
    var i;
    for (i = 0; i < a.toks.length; i++) { if (b.kor.indexOf(a.toks[i]) >= 0) return true; }
    for (i = 0; i < b.toks.length; i++) { if (a.kor.indexOf(b.toks[i]) >= 0) return true; }
    return false;
  }

  // 일정(type='일정') 제목 시그니처 목록 — 렌더 1회당 한 번만 계산
  function _spotSchedSigs() {
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var dayOf = {};
    try {
      var dm = getDayMap();
      for (var d = 0; d < dm.length; d++) dayOf[dm[d].date] = dm[d].day;
    } catch(e) {}
    var out = [];
    for (var i = 0; i < jd.length; i++) {
      var it = jd[i];
      if (!it || it.type !== '일정' || !it.title) continue;
      var sig = _spotSig(it.title);
      if (!sig.n) continue;
      out.push({ sig: sig, date: it.date || '', day: dayOf[it.date] || 0 });
    }
    return out;
  }

  function _spotSchedHit(p, sigs) {
    if (!sigs || !sigs.length) return null;
    var s = _spotSig((p && p.title) || '');
    if (!s.n) return null;
    for (var i = 0; i < sigs.length; i++) { if (_spotSigMatch(s, sigs[i].sig)) return sigs[i]; }
    return null;
  }

  // ═══ ★ (2026-07-23) 이미 일정에 있는 스팟 → 배치 버튼을 비활성 라벨로 ═══
  function _spotDayNoOf(date) {
    if (!date) return 0;
    try {
      var dm = getDayMap();
      for (var i = 0; i < dm.length; i++) { if (dm[i].date === date) return dm[i].day; }
    } catch(e) {}
    return 0;
  }

  function _spotSchedLabel(day, date) {
    var d = date ? String(date).slice(5).replace('-', '/') : '';
    if (day && d) return '📅 ' + day + '일차(' + d + ') 일정에 있음';
    if (day) return '📅 ' + day + '일차 일정에 있음';
    if (d) return '📅 ' + d + ' 일정에 있음';
    return '📅 일정에 있음';
  }

  // 일정 제목 매칭(hit) 또는 저장소에서 배치(status='planned') → 라벨, 아니면 ''
  function _spotPlacedLabel(p, hit) {
    if (hit) return _spotSchedLabel(hit.day, hit.date);
    if (p && p.status === 'planned' && p.placed_date) return _spotSchedLabel(_spotDayNoOf(p.placed_date), p.placed_date);
    return '';
  }

  // 카드/드로어 공용 하단 액션 — hostId를 주면 그 컨테이너에 배치 폼을 그림 (드로어용)
  function _spotFootHtml(p, idx, hit, hostId) {
    var arg = idx + (hostId ? (", '" + hostId + "'") : '');
    var lbl = _spotPlacedLabel(p, hit);
    if (lbl) {
      return '<div class="spot-foot-row">' +
        '<button class="spot-assign-btn is-done" disabled>' + lbl + '</button>' +
        '<button class="spot-readd" onclick="openPlaceAssign(' + arg + ')" title="일정에 다시 배치">' +
          '<span class="material-symbols-outlined">event_repeat</span></button>' +
      '</div>';
    }
    return '<button class="spot-assign-btn" onclick="openPlaceAssign(' + arg + ')">' +
      '<span class="material-symbols-outlined">add</span>일정에 배치</button>';
  }

  window.togglePlaceAdd = function() {
    var f = document.getElementById('place-add-form');
    if (!f) return;
    var show = f.style.display === 'none';
    f.style.display = show ? '' : 'none';
    if (show) {
      var sel = document.getElementById('place-add-cat');
      if (sel && !sel.options.length) sel.innerHTML = PLACE_CATS.map(function(c) { return '<option>' + c + '</option>'; }).join('');
      var nmEl = document.getElementById('place-add-name');
      nmEl.focus();
      // ★ (2026-07-23) 장소 자동완성 (고르면 좌표 함께 저장 → 지도 회색 핀)
      if (typeof attachPlaceAutocomplete === 'function') attachPlaceAutocomplete(nmEl, (document.getElementById('place-add-city').value || '').trim());
    }
  };

  window.savePlaceInline = async function() {
    var name = (document.getElementById('place-add-name').value || '').trim();
    if (!name) { alert('장소 이름을 입력해줘!'); return; }
    var obj = {
      trip_id: currentTripId, type: '스팟', title: name,
      city: (document.getElementById('place-add-city').value || '').trim(),
      category: document.getElementById('place-add-cat').value || '기타',
      reservation: !!document.getElementById('place-add-reserve').checked,
      indoor: !!document.getElementById('place-add-indoor').checked,
      closed: (document.getElementById('place-add-closed').value || '').trim(),
      description: (document.getElementById('place-add-memo').value || '').trim(),
      status: 'pool'
    };
    var nmEl2 = document.getElementById('place-add-name');
    applyPickedCoords(obj, nmEl2); // ★ 자동완성 좌표
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      ['place-add-name', 'place-add-city', 'place-add-closed', 'place-add-memo'].forEach(function(id) { document.getElementById(id).value = ''; });
      document.getElementById('place-add-reserve').checked = false;
      document.getElementById('place-add-indoor').checked = false;
      // 폼은 남아있으므로 지난 좌표가 다음 입력에 승계되지 않게 초기화
      if (nmEl2) { delete nmEl2.dataset.plat; delete nmEl2.dataset.plng; delete nmEl2.dataset.paddr; }
      window.renderPlaces();
      if (typeof renderDayPinsMap === 'function') renderDayPinsMap();
      // ★ (2026-07-23) 대표 사진 비동기 채움 — 성공 시 photo_url 저장 + 카드 갱신 (실패해도 무시)
      try {
        _placePhotoFor((obj.title + ' ' + (obj.city || '')).trim(), function(url) {
          if (!url || !saved || !saved._id) return;
          fbUpdate('journey', saved._id, { photo_url: url }).then(function() {
            saved.photo_url = url;
            try { window.renderPlaces(); } catch(e) {}
          }).catch(function() {});
        });
      } catch(e) {}
      // ★ (2026-07-23) 구글 평점도 함께 (g_pid/g_rating/g_count)
      try {
        _placeRatingFor((obj.title + ' ' + (obj.city || '')).trim(), function(rt) {
          if (!rt || !saved || !saved._id) return;
          var upd = { g_pid: rt.pid, g_rating: rt.rating, g_count: rt.count };
          if (rt.price_level >= 0) upd.g_price_level = rt.price_level;
          fbUpdate('journey', saved._id, upd).then(function() {
            saved.g_pid = rt.pid; saved.g_rating = rt.rating; saved.g_count = rt.count;
            if (rt.price_level >= 0) saved.g_price_level = rt.price_level;
            try { window.renderPlaces(); } catch(e) {}
          }).catch(function() {});
        });
      } catch(e) {}
    } catch(e) { alert('저장 실패'); }
  };

  // ★ (2026-07-23) 기존 스팟 일괄 사진 채우기 — 600ms 간격 순차, 버튼에 진행 표시
  // ★ (2026-07-24) 유료 API 일괄 실행 전 예상 비용 고지.
  //   실측: 2026-07-23 스팟 일괄 채우기 2,376회 → ₩5,393 (효율 단가 약 ₩2.3/회).
  //   한도를 낮게 걸면 작업 도중 막혀서 더 불편하므로, 막는 대신 '미리 보여주고 확인받는' 쪽으로.
  var GMAPS_KRW_PER_CALL = 2.3;
  function _gmapsCostHint(calls) {
    var won = Math.round(calls * GMAPS_KRW_PER_CALL / 10) * 10;
    return calls.toLocaleString('ko-KR') + '회 · 약 ₩' + won.toLocaleString('ko-KR');
  }
  function _confirmGmapsSpend(what, calls) {
    if (!calls) return true;
    return confirm(what + '\n\n구글 지도 API를 ' + _gmapsCostHint(calls) + ' 사용해요.\n(7/23 실측 단가 기준 추정치)\n\n진행할까요?');
  }

  window.fillPlacePhotos = function() {
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var targets = jd.filter(function(d) { return d.type === '스팟' && !d.photo_url && d._id; });
    var btn = document.getElementById('places-photo-fill-btn');
    if (!targets.length) {
      if (btn) btn.style.display = 'none';
      return;
    }
    if (btn && btn.getAttribute('data-running')) return; // 중복 실행 방지
    if (!_confirmGmapsSpend('스팟 ' + targets.length + '곳에 사진을 채웁니다.', targets.length)) return;
    if (btn) { btn.setAttribute('data-running', '1'); btn.disabled = true; }
    var ok = 0;
    function step(i) {
      if (i >= targets.length) {
        if (btn) { btn.removeAttribute('data-running'); btn.disabled = false; }
        try { window.renderPlaces(); } catch(e) {}
        if (typeof showSyncToast === 'function') showSyncToast('📷 스팟 사진 ' + ok + '/' + targets.length + '건 채웠어!');
        return;
      }
      if (btn) btn.innerHTML = '<span class="material-symbols-outlined">photo_camera</span> ' + (i + 1) + '/' + targets.length + ' 처리 중…';
      var p = targets[i];
      _placePhotoFor(((p.title || '') + ' ' + (p.city || '')).trim(), function(url) {
        if (url) {
          ok++;
          fbUpdate('journey', p._id, { photo_url: url }).then(function() {
            p.photo_url = url;
            try { window.renderPlaces(); } catch(e) {}
          }).catch(function() {});
        }
        setTimeout(function() { step(i + 1); }, 600);
      });
    }
    step(0);
  };

  // ★ (2026-07-23) 기존 스팟 일괄 평점 채우기 — 600ms 간격 순차, 버튼에 진행 표시
  window.fillPlaceRatings = function() {
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var targets = jd.filter(function(d) { return d.type === '스팟' && !d.g_pid && d._id; });
    var btn = document.getElementById('places-rating-fill-btn');
    if (!targets.length) {
      if (btn) btn.style.display = 'none';
      return;
    }
    if (btn && btn.getAttribute('data-running')) return; // 중복 실행 방지
    if (!_confirmGmapsSpend('스팟 ' + targets.length + '곳에 평점을 채웁니다.', targets.length * 2)) return;
    if (btn) { btn.setAttribute('data-running', '1'); btn.disabled = true; }
    var ok = 0;
    function step(i) {
      if (i >= targets.length) {
        if (btn) { btn.removeAttribute('data-running'); btn.disabled = false; }
        try { window.renderPlaces(); } catch(e) {}
        if (typeof showSyncToast === 'function') showSyncToast('★ 스팟 평점 ' + ok + '/' + targets.length + '건 채웠어!');
        return;
      }
      if (btn) btn.innerHTML = '<span class="material-symbols-outlined">star</span> ' + (i + 1) + '/' + targets.length + ' 처리 중…';
      var p = targets[i];
      _placeRatingFor(((p.title || '') + ' ' + (p.city || '')).trim(), function(rt) {
        if (rt) {
          ok++;
          var upd = { g_pid: rt.pid, g_rating: rt.rating, g_count: rt.count };
          if (rt.price_level >= 0) upd.g_price_level = rt.price_level;
          p.g_pid = rt.pid; p.g_rating = rt.rating; p.g_count = rt.count;
          if (rt.price_level >= 0) p.g_price_level = rt.price_level;
          fbUpdate('journey', p._id, upd).catch(function() {});
        }
        setTimeout(function() { step(i + 1); }, 600);
      });
    }
    step(0);
  };

  window.setPlaceFilter = function(f) { _placeFilter = f; window.renderPlaces(); };
  // 국가를 바꾸면 도시 선택은 '전체'로 리셋 (국가 밖 도시가 남아 빈 화면이 되는 것 방지)
  window.setPlaceCountry = function(c) { _placeCountry = c; _placeCity = '전체'; window.renderPlaces(); };
  window.setPlaceCity = function(c) { _placeCity = c; window.renderPlaces(); };

  var _spotFxWarm = false; // € 가격 원화 병기용 환율 워밍업 1회

  window.renderPlaces = function() {
    var grid = document.getElementById('place-grid');
    var filtersEl = document.getElementById('place-filters');
    var countryEl = document.getElementById('place-country-tabs');
    var cityEl = document.getElementById('place-city-tabs');
    var cntEl = document.getElementById('places-count');
    if (!grid) return;
    _cityDateCacheReset(); // 도시 날짜(좌표 매칭 포함) 캐시는 렌더 단위로만 재사용
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var places = jd.filter(function(d) { return d.type === '스팟'; });
    // 환율은 최초 1회만 요청 — 도착하면 재렌더 (캐시 hit로 동기 호출되는 경우는 재렌더 생략)
    if (!_spotFxWarm) {
      _spotFxWarm = true;
      try {
        if (typeof window.getFxEurKrw === 'function') {
          var fxSync = true;
          window.getFxEurKrw(function(rate) {
            if (rate && !fxSync) { try { window.renderPlaces(); } catch(e) {} }
          });
          fxSync = false;
        }
      } catch(e) {}
    }
    var placed = places.filter(function(p) { return p.status === 'planned'; }).length;
    if (cntEl) cntEl.textContent = places.length ? places.length + '곳 · 배치 ' + placed : '';
    // ★ (2026-07-24) 히어로 우측 스탯 — 일정 탭(Budget/Spent/Remaining)과 같은 자리·크기
    var _cityN = {};
    places.forEach(function(p) { var k = _normCityKey(p.city || ''); if (k) _cityN[k] = 1; });
    var _setStat = function(id, v) { var el = document.getElementById(id); if (el) el.textContent = v; };
    _setStat('places-mini-total', places.length ? String(places.length) : '—');
    _setStat('places-mini-sched', places.length ? String(placed) : '—');
    _setStat('places-mini-cities', places.length ? String(Object.keys(_cityN).length) : '—');
    // 📷 사진 채우기 버튼 (photo_url 없는 스팟 수) — 일괄 실행 중엔 진행 표시 유지
    var fillBtn = document.getElementById('places-photo-fill-btn');
    if (fillBtn && !fillBtn.getAttribute('data-running')) {
      var noPhoto = places.filter(function(p) { return !p.photo_url && p._id; }).length;
      fillBtn.style.display = noPhoto ? '' : 'none';
      fillBtn.innerHTML = '<span class="material-symbols-outlined">photo_camera</span> 사진 채우기 (' + noPhoto + ')';
      fillBtn.title = '사진 없는 스팟에 Google Places 대표 사진을 채워요 — 예상 ' + _gmapsCostHint(noPhoto);
    }
    // ★ 평점 채우기 버튼 (g_pid 없는 스팟 수)
    var rateBtn = document.getElementById('places-rating-fill-btn');
    if (rateBtn && !rateBtn.getAttribute('data-running')) {
      var noRate = places.filter(function(p) { return !p.g_pid && p._id; }).length;
      rateBtn.style.display = noRate ? '' : 'none';
      rateBtn.innerHTML = '<span class="material-symbols-outlined">star</span> 평점 채우기 (' + noRate + ')';
      rateBtn.title = '평점 없는 스팟에 Google 평점·리뷰 수를 채워요 — 예상 ' + _gmapsCostHint(noRate * 2);
    }
    // 국가 세그먼트 탭 (스팟 있는 국가만 동적 생성)
    // ★ (2026-07-23) 정렬 = 실제 여행 순서(citiesData start_date 순) → 트립 밖 국가 → '기타' 맨 뒤
    var tripOrder = _placeCountryTripOrder();
    if (countryEl) {
      var countries = []; var seenC = {};
      places.forEach(function(p) {
        var c = _placeCountryOf(p.city);
        if (!seenC[c]) { seenC[c] = true; countries.push(c); }
      });
      countries.sort(function(a, b) {
        var ra = _placeTabRank(a, tripOrder), rb = _placeTabRank(b, tripOrder);
        if (ra !== rb) return ra - rb;
        return String(a).localeCompare(String(b), 'ko');
      });
      if (_placeCountry !== '전체' && countries.indexOf(_placeCountry) < 0) { _placeCountry = '전체'; _placeCity = '전체'; }
      countryEl.style.display = countries.length > 1 ? '' : 'none';
      countryEl.innerHTML = ['전체'].concat(countries).map(function(c) {
        return '<button class="spot-ctab' + (c === _placeCountry ? ' is-active' : '') +
          '" onclick="setPlaceCountry(\'' + _spotArg(c) + '\')">' + _spotEsc(c) + '</button>';
      }).join('');
    }
    // ★ (2026-07-23) 도시 칩 줄 — 선택 국가의 도시만, 여행 순서대로, 각 칩에 스팟 수
    var cityScope = places.filter(function(p) {
      return _placeCountry === '전체' || _placeCountryOf(p.city) === _placeCountry;
    });
    var cityMap = {}, cityKeys = [];
    cityScope.forEach(function(p) {
      var rawCity = String(p.city || '').trim();
      var ck = _normCityKey(rawCity) || '미지정';
      if (!cityMap[ck]) {
        cityMap[ck] = { label: _cityLabelShort(rawCity) || '미지정', n: 0, rank: _souvenirCityRank(rawCity),
          dt: (typeof _cityDateInfo === 'function' ? _cityDateInfo(rawCity) : { text: '', kind: '' }) };
        cityKeys.push(ck);
      }
      cityMap[ck].n++;
    });
    cityKeys.sort(function(a, b) {
      var ra = (a === '미지정') ? 99999 : cityMap[a].rank;
      var rb = (b === '미지정') ? 99999 : cityMap[b].rank;
      if (ra !== rb) return ra - rb;
      return cityMap[a].label.localeCompare(cityMap[b].label, 'ko');
    });
    if (_placeCity !== '전체' && !cityMap[_placeCity]) _placeCity = '전체';
    if (cityEl) {
      cityEl.style.display = cityKeys.length > 1 ? '' : 'none';
      // ★ (2026-07-23) 도시 칩 재편 — 칩마다 날짜를 달다 보니 ① 이름 길이에 따라 날짜가
      //   윗줄/아랫줄로 튀어 높이가 제각각이고 ② 오르차 계곡 7개 도시가 같은 '10/8~10/12'를
      //   7번 반복해 노이즈였다. → 체류 구간별로 묶어서 날짜는 줄 왼쪽에 한 번만,
      //   칩은 [이름 + 개수] 한 줄 고정. 구간과 다른 날짜만 칩에 따로 표시.
      var stayBands = [];   // [{ s0, e0, label, keys: [] }]
      // 날짜는 'YYYY-MM-DD' 문자열이라 Math.min/max를 그대로 쓰면 NaN이 된다 — 일수로 바꿔서 계산.
      // 겹치는 구간 중 '가장 많이 겹치는' 쪽에 붙인다. (체크아웃 당일 하루만 걸치는 이전 도시보다
      //  실제로 머무는 도시가 맞으므로 — 10/8 오르차 근교가 베를린에 붙던 문제)
      var dayNo = function(d) { var t = Date.parse(String(d) + 'T00:00:00Z'); return isNaN(t) ? null : Math.round(t / 86400000); };
      var bandOf = function(s0, e0) {
        if (!s0) return null;
        var aS = dayNo(s0), aE = dayNo(e0 || s0);
        if (aS === null) return null;
        if (aE === null || aE < aS) aE = aS;
        var best = null, bestOv = 0;
        for (var b = 0; b < stayBands.length; b++) {
          var bd = stayBands[b];
          var bS = dayNo(bd.s0), bE = dayNo(bd.e0);
          if (bS === null) continue;
          if (bE === null || bE < bS) bE = bS;
          var ov = Math.min(aE, bE) - Math.max(aS, bS) + 1;
          if (ov > bestOv) { bestOv = ov; best = bd; }
        }
        return best;
      };
      // 1) 숙박 도시로 구간 뼈대를 먼저 만든다 (여행 순서 = 시작일 순)
      cityKeys.forEach(function(k) {
        var dt = cityMap[k].dt || {};
        if (dt.kind !== 'stay' || !dt.s0) return;
        var exist = null;
        for (var b = 0; b < stayBands.length; b++) {
          if (stayBands[b].s0 === dt.s0 && stayBands[b].e0 === (dt.e0 || dt.s0)) { exist = stayBands[b]; break; }
        }
        if (!exist) { exist = { s0: dt.s0, e0: dt.e0 || dt.s0, label: dt.text, keys: [] }; stayBands.push(exist); }
        exist.keys.push(k);
      });
      stayBands.sort(function(a, b) { return a.s0.localeCompare(b.s0); });
      // 2) 당일치기 도시는 날짜가 겹치는 숙박 구간에 붙인다
      var loose = [];
      cityKeys.forEach(function(k) {
        var dt = cityMap[k].dt || {};
        if (dt.kind === 'stay' && dt.s0) return;
        var bd = dt.s0 ? bandOf(dt.s0, dt.e0) : null;
        if (bd) bd.keys.push(k); else loose.push(k);
      });
      if (loose.length) stayBands.push({ s0: '', e0: '', label: '', keys: loose });

      var chipHtml = function(k, bandLabel) {
        var dt = cityMap[k].dt || { text: '', kind: '' };
        var isTrip = (dt.kind === 'daytrip');
        // 구간 날짜와 똑같으면 칩에서는 생략 (같은 날짜 반복 제거)
        var showDate = dt.text && dt.text !== bandLabel;
        var tip = _spotEsc(cityMap[k].label) +
          (dt.text ? ' · ' + (isTrip ? '당일치기 ' : '숙박 ') + dt.text : '');
        return '<button class="spot-citytab' + (k === _placeCity ? ' is-active' : '') +
          (isTrip ? ' is-daytrip' : ' is-stay') +
          '" onclick="setPlaceCity(\'' + _spotArg(k) + '\')" title="' + tip + '"><b>' +
          _spotEsc(cityMap[k].label) + '</b>' +
          (showDate ? '<em>' + dt.text + '</em>' : '') +
          '<i>' + cityMap[k].n + '</i></button>';
      };
      cityEl.innerHTML =
        '<div class="spot-citygrp">' +
          '<span class="scg-date is-all">ALL</span>' +
          '<div class="scg-chips">' +
            '<button class="spot-citytab is-stay' + (_placeCity === '전체' ? ' is-active' : '') +
              '" onclick="setPlaceCity(\'전체\')"><b>전체</b><i>' + cityScope.length + '</i></button>' +
          '</div>' +
        '</div>' +
        stayBands.map(function(bd) {
          if (!bd.keys.length) return '';
          return '<div class="spot-citygrp">' +
            '<span class="scg-date">' + (bd.label || '날짜 미정') + '</span>' +
            '<div class="scg-chips">' + bd.keys.map(function(k) { return chipHtml(k, bd.label); }).join('') + '</div>' +
          '</div>';
        }).join('');
    }
    // 카테고리 텍스트 탭 (전체/카테고리/실내만 — 국가 탭과 AND 조합)
    if (filtersEl) {
      var cats = ['전체'].concat(PLACE_CATS).concat(['☔ 실내만']);
      filtersEl.innerHTML = cats.map(function(c) {
        return '<button class="spot-cattab' + (c === _placeFilter ? ' is-active' : '') +
          '" onclick="setPlaceFilter(\'' + c + '\')">' + c + '</button>';
      }).join('');
    }
    var list = places.filter(function(p) {
      if (_placeCountry !== '전체' && _placeCountryOf(p.city) !== _placeCountry) return false;
      if (_placeCity !== '전체' && (_normCityKey(p.city) || '미지정') !== _placeCity) return false;
      if (_placeFilter === '전체') return true;
      if (_placeFilter === '☔ 실내만') return p.indoor === true;
      return p.category === _placeFilter;
    });
    if (!list.length) {
      grid.innerHTML = '<div class="col-span-full text-center text-slate-400 text-xs py-8">' +
        (places.length ? '이 필터에 해당하는 스팟이 없어요' : '아직 스팟이 없어요 — 가고 싶은 곳을 먼저 모아두고, 일정에 배치해봐!') + '</div>';
      return;
    }
    // ★ (2026-07-23) 추천 순위 — 점수(평점×log10(리뷰수+1)) 내림차순, 평점 없는 스팟은 뒤(기존 순서 유지)
    var deco = list.map(function(p, i) { return { p: p, i: i, s: _spotScore(p) }; });
    deco.sort(function(a, b) { return (b.s - a.s) || (a.i - b.i); });
    list = deco.map(function(d) { return d.p; });
    // ★ (2026-07-23) 카테고리별 TOP 1~5 — 전역 TOP 대신 카테고리 안에서 점수 상위 5
    //   현재 필터와 무관하게 전체 스팟 기준으로 계산 (탭을 옮겨도 순위가 흔들리지 않게)
    var byCat = {};
    places.forEach(function(p, i) {
      var s = _spotScore(p);
      if (s <= 0) return;
      var c = p.category || '기타';
      if (!byCat[c]) byCat[c] = [];
      byCat[c].push({ p: p, i: i, s: s });
    });
    var topPs = [], topInfo = [];
    Object.keys(byCat).forEach(function(c) {
      var arr = byCat[c];
      arr.sort(function(a, b) { return (b.s - a.s) || (a.i - b.i); });
      arr.slice(0, 5).forEach(function(d, k) {
        topPs.push(d.p);
        topInfo.push({ rank: k + 1, cat: c });
      });
    });
    // ★ "일정에 있음" 배지용 일정 제목 시그니처 (렌더당 1회)
    var schedSigs = _spotSchedSigs();
    grid.innerHTML = list.map(function(p) {
      var idx = journeyData.indexOf(p);
      var catIco = PLACE_CAT_ICONS[p.category] || 'place';
      var cityShort = _displayCityShort(p.city || '');
      var cityBadge = cityShort ? '<div class="spot-city-badge">' + String(cityShort).replace(/</g, '&lt;') + '</div>' : '';
      // ★ (2026-07-23) 이미지 우선순위: photo_url(Places 대표 사진) → 도시 이미지 → 그라디언트 플레이스홀더
      //   photo는 <img> 오버레이로 얹어 onerror 시 display:none → 아래 레이어(도시/플레이스홀더)로 폴백
      var img = _placeCityImg(p.city);
      var photoImg = p.photo_url
        ? '<img class="spot-photo" src="' + String(p.photo_url).replace(/"/g, '&quot;') + '" alt="" loading="lazy" onerror="this.style.display=\'none\'">'
        : '';
      var imgHtml = img
        ? '<div class="spot-img" style="background-image:url(\'' + img + '\')">' + photoImg + cityBadge + '</div>'
        : '<div class="spot-img spot-img-ph"><span class="material-symbols-outlined">' + catIco + '</span>' + photoImg + cityBadge + '</div>';
      var chips = '<span class="spot-chip"><span class="material-symbols-outlined">' + catIco + '</span>' + (p.category || '기타') + '</span>';
      if (isReservationItem(p)) chips += '<span class="spot-chip is-reserve">🎫 예약 필수</span>';
      if (p.indoor === true) chips += '<span class="spot-chip is-indoor">🏠 실내</span>';
      if (p.closed) chips += '<span class="spot-chip is-closed">⛔ ' + String(p.closed).replace(/</g, '&lt;') + ' 휴무</span>';
      // ★ (2026-07-23) 일정 중복은 칩 대신 하단 비활성 버튼으로 (정보 이전)
      var hit = _spotSchedHit(p, schedSigs);
      var memo = p.description
        ? '<p class="spot-desc is-clickable">' + String(p.description).replace(/</g, '&lt;') + '</p>'
        : '';
      // ★ 카테고리별 TOP 배지 + 추천 이유 미니 라인
      var ti = topPs.indexOf(p);
      var isTop = ti >= 0;
      var topHtml = '';
      if (isTop) {
        var why = _spotWhyLine(p);
        topHtml = '<div class="spot-top-badge" title="' + _spotEsc(topInfo[ti].cat) + ' 카테고리 ' + topInfo[ti].rank + '위">★ TOP ' + topInfo[ti].rank + '</div>' +
          (why ? '<div class="spot-top-why">' + _spotEsc(why) + '</div>' : '');
      }
      var rateHtml = _spotRatingHtml(p, false);
      var priceHtml = _spotPriceMini(p);
      var moreHtml = '<button class="spot-more" onclick="event.stopPropagation();openSpotDrawer(' + idx + ')">자세히</button>';
      var foot = _spotFootHtml(p, idx, hit, null);
      return '<div class="spot-card' + (isTop ? ' is-top' : '') + '" onclick="openSpotDrawer(' + idx + ')">' + imgHtml +
        '<div class="spot-body">' +
          topHtml +
          '<div class="spot-title-row">' +
            '<h4 class="spot-title">' + _trvMapsLink(p.title || '', p.city || '') + '</h4>' +
            '<button class="spot-del" onclick="event.stopPropagation();deletePlace(' + idx + ')" title="삭제"><span class="material-symbols-outlined">delete</span></button>' +
          '</div>' +
          '<div class="spot-chips">' + chips + '</div>' +
          rateHtml +
          priceHtml +
          memo +
          moreHtml +
          '<div class="spot-foot" onclick="event.stopPropagation()"><div class="spot-foot-inner" id="place-assign-' + idx + '">' + foot + '</div></div>' +
        '</div>' +
      '</div>';
    }).join('');
  };

  // g_pid로 리뷰·영업시간·웹사이트 지연 로드 → 트림해서 g_details로 캐시 (재펼침 시 재호출 없음)
  function _placeDetailsFetch(p, cb) {
    try {
      if (!p || !p.g_pid || typeof google === 'undefined' || !google.maps || !google.maps.places) { cb(null); return; }
      var svc = new google.maps.places.PlacesService(document.createElement('div'));
      svc.getDetails({ placeId: p.g_pid, fields: ['reviews', 'opening_hours', 'website'] }, function(place, status) {
        try {
          if (status !== google.maps.places.PlacesServiceStatus.OK || !place) { cb(null); return; }
          var revs = [], src = place.reviews || [];
          for (var i = 0; i < src.length && revs.length < 3; i++) {
            var t = String(src[i].text || '').replace(/\s+/g, ' ').trim();
            if (!t) continue;
            revs.push({ n: String(src[i].author_name || '익명').slice(0, 24),
                        r: Number(src[i].rating) || 0,
                        t: t.length > 160 ? t.slice(0, 160) + '…' : t });
          }
          var hrs = (place.opening_hours && place.opening_hours.weekday_text)
            ? place.opening_hours.weekday_text.slice(0, 7) : [];
          var det = { reviews: revs, hours: hrs, web: String(place.website || '').slice(0, 300),
                      fetched: new Date().toISOString().slice(0, 10) };
          p.g_details = det;
          if (p._id) { try { fbUpdate('journey', p._id, { g_details: det }).catch(function() {}); } catch(e) {} }
          cb(det);
        } catch(e) { cb(null); }
      });
    } catch(e) { cb(null); }
  }

  function _spotDetailBody(g) {
    var out = '';
    var hrs = (g && g.hours) || [];
    if (hrs.length) {
      var todayIdx = (new Date().getDay() + 6) % 7; // weekday_text는 월요일 시작
      var line = hrs[todayIdx] || '';
      if (line) out += '<div class="spot-detail-hours">🕒 오늘 · ' + _spotEsc(line) + '</div>';
    }
    if (g && g.web) {
      out += '<div class="spot-detail-web"><a href="' + _spotEsc(g.web) + '" target="_blank" rel="noopener">🔗 공식 웹사이트</a></div>';
    }
    var revs = (g && g.reviews) || [];
    if (revs.length) {
      out += '<div class="spot-detail-revs">' + revs.map(function(r) {
        return '<div class="spot-rev">' +
          '<div class="spot-rev-top"><b>' + _spotEsc(r.n) + '</b>' +
            (r.r ? '<span class="spot-rev-star">★ ' + (Number(r.r) || 0).toFixed(1) + '</span>' : '') + '</div>' +
          '<p>' + _spotEsc(r.t) + '</p></div>';
      }).join('') + '</div>';
    }
    if (!out) out = '<div class="spot-detail-note">추가 정보가 없어.</div>';
    return out;
  }

  // ═══════════════════════════════════════════════════════════════════════
  //  ★ (2026-07-23) 스팟 상세 드로어 — body 직속 우측 슬라이드 패널
  //    기존 인라인 풀폭 패널(.spot-detail) 대체: 그리드를 깨지 않고 닫기 버튼이 항상 같은 자리.
  //    데이터는 기존 _placeDetailsFetch/g_details 캐시를 그대로 재사용.
  // ═══════════════════════════════════════════════════════════════════════
  var _spotDrawerIdx = -1;
  var _spotDrawerBound = false;

  function _spotDrawerEnsure() {
    var el = document.getElementById('spot-drawer');
    if (el) return el;
    var bd = document.createElement('div');
    bd.id = 'spot-drawer-backdrop';
    bd.className = 'spot-drawer-backdrop';
    bd.onclick = function() { window.closeSpotDrawer(); };
    document.body.appendChild(bd);
    el = document.createElement('aside');
    el.id = 'spot-drawer';
    el.className = 'spot-drawer';
    el.setAttribute('role', 'dialog');
    el.setAttribute('aria-modal', 'true');
    document.body.appendChild(el);
    if (!_spotDrawerBound) {
      _spotDrawerBound = true;
      document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && _spotDrawerIdx >= 0) { e.preventDefault(); window.closeSpotDrawer(); }
      });
    }
    return el;
  }

  function _spotMapsHref(p) {
    var nm = String((p && p.title) || '').replace(/<[^>]+>/g, '').trim();
    var q = nm + ((p && p.city) ? (', ' + p.city) : '');
    return 'https://www.google.com/maps/search/?api=1&query=' + encodeURIComponent(q);
  }

  function _spotDrawerHtml(p, idx, g, loading) {
    var catIco = PLACE_CAT_ICONS[p.category] || 'place';
    var head = '<div class="spot-dw-head">' +
      '<h3 class="spot-dw-title">' + _spotEsc(p.title || '') + '</h3>' +
      '<button class="spot-dw-close" onclick="closeSpotDrawer()" title="닫기" aria-label="닫기">✕</button>' +
    '</div>';
    var photo = p.photo_url
      ? '<img class="spot-dw-photo" src="' + String(p.photo_url).replace(/"/g, '&quot;') + '" alt="" onerror="this.style.display=\'none\'">'
      : '';
    var chips = '<span class="spot-chip"><span class="material-symbols-outlined">' + catIco + '</span>' + _spotEsc(p.category || '기타') + '</span>';
    var cityShort = _displayCityShort(p.city || '');
    if (cityShort) chips = '<span class="spot-chip is-city">📍 ' + _spotEsc(cityShort) + '</span>' + chips;
    if (isReservationItem(p)) chips += '<span class="spot-chip is-reserve">🎫 예약 필수</span>';
    if (p.indoor === true) chips += '<span class="spot-chip is-indoor">🏠 실내</span>';
    if (p.closed) chips += '<span class="spot-chip is-closed">⛔ ' + _spotEsc(p.closed) + ' 휴무</span>';
    var meta = '<div class="spot-dw-meta">' +
      (_spotRatingHtml(p, true) || '<span class="spot-detail-norate">평점 정보 없음</span>') +
      '<div class="spot-chips">' + chips + '</div>' +
    '</div>';
    var desc = p.description ? '<p class="spot-dw-desc">' + _spotEsc(p.description) + '</p>' : '';
    var body;
    if (loading) {
      body = '<div class="spot-dw-loading"><span class="spot-dw-spin"></span>구글 리뷰·영업시간 불러오는 중…</div>';
    } else if (g) {
      body = _spotDetailBody(g);
    } else if (!p.g_pid) {
      body = '<div class="spot-detail-note">구글 상세 정보가 아직 없어 — 헤더의 "★ 평점 채우기"를 먼저 눌러줘.</div>';
    } else {
      body = '<div class="spot-detail-note">상세 정보를 못 불러왔어 (구글 응답 없음).</div>';
    }
    var scroll = '<div class="spot-dw-scroll">' + photo + meta + desc + _spotPriceBlock(p) + body + '</div>';
    var hit = _spotSchedHit(p, _spotSchedSigs());
    var actions = '<div class="spot-dw-actions">' +
      '<div class="spot-dw-assign" id="spot-drawer-assign">' + _spotFootHtml(p, idx, hit, 'spot-drawer-assign') + '</div>' +
      '<a class="spot-dw-maps" href="' + _spotEsc(_spotMapsHref(p)) + '" target="_blank" rel="noopener">' +
        '<span class="material-symbols-outlined">place</span>구글맵 열기</a>' +
    '</div>';
    return head + scroll + actions;
  }

  window.openSpotDrawer = function(idx) {
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var p = jd[idx];
    if (!p) return;
    var el = _spotDrawerEnsure();
    _spotDrawerIdx = idx;
    var g = p.g_details;
    if (g && typeof g === 'string') { try { g = JSON.parse(g); } catch(e) { g = null; } }
    var needFetch = !g && !!p.g_pid;
    el.innerHTML = _spotDrawerHtml(p, idx, g, needFetch);
    var bd = document.getElementById('spot-drawer-backdrop');
    if (bd) bd.classList.add('is-open');
    try { document.body.classList.add('spot-drawer-lock'); } catch(e) {}
    // 다음 프레임에 클래스 부여 → transform 트랜지션이 실제로 재생됨
    setTimeout(function() { el.classList.add('is-open'); }, 10);
    if (!needFetch) return;
    _placeDetailsFetch(p, function(res) {
      if (_spotDrawerIdx !== idx) return;
      var el2 = document.getElementById('spot-drawer');
      if (!el2) return;
      el2.innerHTML = _spotDrawerHtml(p, idx, res, false);
    });
  };

  window.closeSpotDrawer = function() {
    var el = document.getElementById('spot-drawer');
    var bd = document.getElementById('spot-drawer-backdrop');
    _spotDrawerIdx = -1;
    if (el) el.classList.remove('is-open');
    if (bd) bd.classList.remove('is-open');
    try { document.body.classList.remove('spot-drawer-lock'); } catch(e) {}
  };

  // 드로어가 열려있는 스팟이면 내용 갱신 (배치 직후 등)
  function _spotDrawerRefresh() {
    if (_spotDrawerIdx < 0) return;
    var idx = _spotDrawerIdx;
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var p = jd[idx];
    var el = document.getElementById('spot-drawer');
    if (!el || !p) { window.closeSpotDrawer(); return; }
    var g = p.g_details;
    if (g && typeof g === 'string') { try { g = JSON.parse(g); } catch(e) { g = null; } }
    el.innerHTML = _spotDrawerHtml(p, idx, g, false);
  }

  // 하위 호환 — 예전 인라인 패널 호출부가 남아있어도 드로어를 연다
  window.togglePlaceDetail = function(idx) { window.openSpotDrawer(idx); };

  // ═══ ★ (2026-07-23) 배치 추천 — 우회거리 최소 일차 + 60분+ 빈 시간 탐색 ═══
  function _spotMin(t) {
    var m = /^(\d{1,2}):(\d{2})/.exec(String(t || '').trim());
    if (!m) return -1;
    return parseInt(m[1], 10) * 60 + parseInt(m[2], 10);
  }
  function _spotHHMM(min) {
    var h = Math.floor(min / 60), m = min % 60;
    return (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m;
  }
  function _spotShortTitle(t) {
    var s = String(t || '').replace(/<[^>]+>/g, '').trim();
    try { if (typeof _cleanPOITitle === 'function') s = _cleanPOITitle(s) || s; } catch(e) {}
    return s.length > 12 ? s.slice(0, 12) + '…' : s;
  }
  // 자유 일정 = 예약·고정이 아니고 이동/체크인류 키워드도 아닌 일정
  function _spotFreeItem(items) {
    for (var i = 0; i < items.length; i++) {
      var it = items[i];
      if (it.reservation === true || it.pinned === true) continue;
      if (/체크인|체크아웃|공항|이동|출발|도착|기차|비행|버스|렌트|픽업|숙소|짐 /i.test(it.title || '')) continue;
      return it;
    }
    return null;
  }

  function _spotAssignRec(p) {
    var dayMap = [];
    try { dayMap = getDayMap(); } catch(e) {}
    if (!p || !dayMap.length) return null;
    var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    var hasCo = (typeof p.lat === 'number' && typeof p.lng === 'number');
    var pCity = _normCityKey(p.city || '');
    var WD = ['일', '월', '화', '수', '목', '금', '토'];
    var cands = [];
    for (var i = 0; i < dayMap.length; i++) {
      var d = dayMap[i];
      // 휴무 요일 충돌 제외
      if (p.closed) {
        try {
          var wd = WD[new Date(d.date + 'T00:00:00').getDay()];
          if (String(p.closed).indexOf(wd) >= 0) continue;
        } catch(e) {}
      }
      var items = [];
      for (var j = 0; j < jd.length; j++) {
        if (jd[j].type === '일정' && jd[j].date === d.date) items.push(jd[j]);
      }
      items.sort(function(a, b) { return String(a.time || '~').localeCompare(String(b.time || '~')); });
      // 근접 판정: 좌표 30km 이내 또는 도시명 매칭
      var minD = Infinity, k;
      if (hasCo) {
        for (k = 0; k < items.length; k++) {
          if (typeof items[k].lat === 'number' && typeof items[k].lng === 'number') {
            var dd = _haversineKm(p, items[k]);
            if (dd < minD) minD = dd;
          }
        }
      }
      var near = isFinite(minD) && minD <= 30;
      if (!near && pCity) {
        if (_normCityKey(d.cityName || '') === pCity) near = true;
        else {
          for (k = 0; k < items.length; k++) {
            if (_normCityKey(items[k].city || '') === pCity) { near = true; break; }
          }
        }
      }
      if (!near) continue;
      // 우회거리 = min over 연속 일정쌍(a,b) [dist(a,스팟)+dist(스팟,b)−dist(a,b)]
      var detour = Infinity, pa = null, pb = null;
      if (hasCo) {
        for (k = 1; k < items.length; k++) {
          var a = items[k - 1], b = items[k];
          if (typeof a.lat !== 'number' || typeof a.lng !== 'number') continue;
          if (typeof b.lat !== 'number' || typeof b.lng !== 'number') continue;
          var v = _haversineKm(a, p) + _haversineKm(p, b) - _haversineKm(a, b);
          if (v < detour) { detour = v; pa = a; pb = b; }
        }
      }
      // 빈 시간: 연속 일정 사이 60분+ 구간 (종료시간 없으면 60분 소요 가정)
      var gap = null;
      for (k = 1; k < items.length; k++) {
        var s0 = _spotMin(items[k - 1].time), e0 = _spotMin(items[k - 1].end_time);
        var s1 = _spotMin(items[k].time);
        if (s0 < 0 || s1 < 0) continue;
        if (e0 < 0 || e0 < s0) e0 = s0 + 60;
        if (s1 - e0 >= 60) { gap = { s: e0, e: s1 }; break; }
      }
      cands.push({ date: d.date, day: d.day, items: items, minD: minD, detour: detour, pa: pa, pb: pb, gap: gap });
    }
    if (!cands.length) return null;
    cands.sort(function(a, b) {
      var ka = isFinite(a.detour) ? a.detour : (isFinite(a.minD) ? a.minD + 1000 : 2000);
      var kb = isFinite(b.detour) ? b.detour : (isFinite(b.minD) ? b.minD + 1000 : 2000);
      return (ka - kb) || (a.day - b.day);
    });
    return cands[0];
  }

  function _spotRecLine(rec) {
    if (!rec) return '';
    var head = rec.day + '일차(' + String(rec.date).slice(5).replace('-', '/') + ')';
    if (rec.gap) {
      var mid = (rec.pa && rec.pb)
        ? (' — ' + _spotEsc(_spotShortTitle(rec.pa.title)) + '↔' + _spotEsc(_spotShortTitle(rec.pb.title)) + ' 사이') : '';
      var dt = isFinite(rec.detour) ? (', 우회 +' + (Math.round(rec.detour * 10) / 10) + 'km') : '';
      return '<div class="spot-rec">🎯 추천: ' + head + mid + dt + ', ' +
        _spotHHMM(rec.gap.s) + '~' + _spotHHMM(rec.gap.e) + ' 여유</div>';
    }
    var free = _spotFreeItem(rec.items);
    return '<div class="spot-rec is-warn">⚠️ ' + head + '가 동선상 최적이지만 빈 시간이 없어 — ' +
      (free ? ('그 날 자유 일정(\'' + _spotEsc(_spotShortTitle(free.title)) + '\') 조정 추천')
            : '그 날 일정 조정이 필요해') + '</div>';
  }

  // hostId를 주면 그 컨테이너에 폼을 그림 (드로어) — 카드와 id가 겹치지 않게 uid를 분리
  window.openPlaceAssign = function(idx, hostId) {
    var uid = hostId ? (idx + '-d') : String(idx);
    var wrap = document.getElementById(hostId || ('place-assign-' + idx));
    if (!wrap) return;
    var dayMap = getDayMap();
    if (!dayMap.length) { alert('먼저 Stops에 도시/날짜를 추가해줘!'); return; }
    // ★ (2026-07-23) 배치 추천 — 최적 일차 preselect + 빈 시간 시작시각 프리필
    var rec = null;
    try { rec = _spotAssignRec(journeyData[idx]); } catch(e) { rec = null; }
    var opts = dayMap.map(function(e) {
      return '<option value="' + e.date + '"' + (rec && rec.date === e.date ? ' selected' : '') + '>' +
        e.day + '일차 · ' + e.date.slice(5).replace('-', '/') + ' · ' + (e.cityName || '') + '</option>';
    }).join('');
    var timeVal = (rec && rec.gap) ? _spotHHMM(rec.gap.s) : '';
    wrap.innerHTML = _spotRecLine(rec) +
      '<div class="spot-assign-row">' +
      '<select id="place-assign-day-' + uid + '">' + opts + '</select>' +
      '<input id="place-assign-time-' + uid + '" type="text" placeholder="10:00" value="' + timeVal + '"/>' +
      '<button class="spot-assign-go" onclick="confirmPlaceAssign(' + idx + ", '" + uid + '\')">배치</button>' +
    '</div>';
  };

  window.confirmPlaceAssign = async function(idx, uid) {
    var p = journeyData[idx];
    if (!p) return;
    if (uid == null || uid === '') uid = String(idx);
    var date = (document.getElementById('place-assign-day-' + uid) || {}).value;
    var time = ((document.getElementById('place-assign-time-' + uid) || {}).value || '').trim();
    if (!date) return;
    // 휴무 요일 충돌 사전 경고
    if (p.closed) {
      try {
        var wd = ['일', '월', '화', '수', '목', '금', '토'][new Date(date + 'T00:00:00').getDay()];
        if (String(p.closed).indexOf(wd) >= 0 && !confirm('⚠️ 이 날은 ' + wd + '요일 — "' + p.title + '" 정기휴무(' + p.closed + ')와 겹쳐!\n그래도 배치할까?')) return;
      } catch(e) {}
    }
    var obj = {
      trip_id: currentTripId, type: '일정', date: date, time: time, end_time: '',
      city: p.city || '', title: p.title || '', description: p.description || '',
      reservation: p.reservation === true || isReservationItem(p), indoor: p.indoor === true, closed: p.closed || ''
    };
    // ★ (2026-07-23) 스팟에 좌표가 있으면 일정으로 승계 → 지도 핀 + 이동시간
    if (typeof p.lat === 'number' && typeof p.lng === 'number') { obj.lat = p.lat; obj.lng = p.lng; }
    if (p.address) obj.address = p.address;
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      if (p._id) { try { await fbUpdate('journey', p._id, { status: 'planned', placed_date: date }); } catch(e) {} }
      p.status = 'planned'; p.placed_date = date;
      window.renderPlaces();
      try { _spotDrawerRefresh(); } catch(e) {}
      renderDayView();
      if (typeof showSyncToast === 'function') showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> "' + p.title + '" → ' + date.slice(5).replace('-', '/') + ' 일정에 배치!');
    } catch(e) { alert('배치 실패'); }
  };

  window.deletePlace = async function(idx) {
    var p = journeyData[idx];
    if (!p || !confirm('"' + (p.title || '') + '" 스팟을 삭제할까?')) return;
    try {
      if (p._id) await fbDelete('journey', p._id);
      journeyData.splice(idx, 1);
      try { window.closeSpotDrawer(); } catch(e) {} // splice로 인덱스가 밀리므로 드로어는 닫음
      window.renderPlaces();
    } catch(e) { alert('삭제 실패'); }
  };

  // ═══ (2026-07-23) 장부 첨부파일 (Wanderlog 예약&첨부 이식) ═══
  var TRV_ATTACH_MAX = 10 * 1024 * 1024;

  function _trvAttachEsc(s) {
    return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/"/g, '&quot;');
  }

  function _trvAttachFind(docId) {
    var arr = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
    for (var i = 0; i < arr.length; i++) { if (arr[i]._id === docId) return arr[i]; }
    return null;
  }

  function _trvAttachRerender(type) {
    if (type === '항공편') renderJourneyFlights();
    else if (type === '숙소') renderJourneyLodging();
    else if (type === '이동수단') renderJourneyTransport();
    else if (type === '렌트카') renderJourneyRental();
  }

  // 카드 하단 첨부 행 HTML (Firebase 문서만 — seed 항목은 빈 문자열)
  window.trvAttachRowHtml = function(item) {
    if (!item || !item._id) return '';
    var docId = String(item._id).replace(/['"\\<>]/g, '');
    var atts = item.attachments || [];
    var chips = atts.map(function(a, i) {
      var url = _trvAttachEsc(String(a.url || '').replace(/'/g, '%27'));
      var name = _trvAttachEsc(a.name || '파일');
      return '<span class="j-attach-chip" title="' + name + '" onclick="event.stopPropagation();window.open(\'' + url + '\',\'_blank\')">' +
        '📎 <span class="nm">' + name + '</span>' +
        '<span class="j-attach-del" title="삭제" onclick="event.stopPropagation();trvAttachDelete(\'' + docId + '\',' + i + ')">×</span></span>';
    }).join('');
    return '<div class="j-attach-row" id="trv-attach-' + docId + '" onclick="event.stopPropagation()">' + chips +
      '<button type="button" class="j-attach-add" onclick="event.stopPropagation();trvAttachPick(\'' + docId + '\')">+ 첨부</button></div>';
  };

  // blob 업로드 → journey.attachments push + 메모리 동기화
  function _trvAttachUploadBlob(docId, blob, name, ctype) {
    var item = _trvAttachFind(docId);
    if (!item) return Promise.reject(new Error('journey 문서를 찾을 수 없음: ' + docId));
    if (!window.storage) return Promise.reject(new Error('storage 미초기화'));
    var safeName = String(name || 'file').replace(/[\/\\#?%\[\]]/g, '_');
    var path = 'trips/' + (item.trip_id || currentTripId || 'unknown') + '/attach/' + docId + '/' + Date.now() + '_' + safeName;
    var mime = ctype || blob.type || 'application/octet-stream';
    return window.storage.ref(path).put(blob, { contentType: mime }).then(function(snap) {
      return snap.ref.getDownloadURL();
    }).then(function(url) {
      var entry = { name: String(name || safeName), url: url, ctype: mime, size: blob.size || 0, ts: new Date().toISOString() };
      var atts = (item.attachments || []).concat([entry]);
      return fbUpdate('journey', docId, { attachments: atts }).then(function() {
        item.attachments = atts;
        return entry;
      });
    });
  }

  window.trvAttachPick = function(docId) {
    var item = _trvAttachFind(docId);
    if (!item) { alert('항목을 찾을 수 없어요.'); return; }
    var input = document.createElement('input');
    input.type = 'file';
    input.accept = 'application/pdf,image/*';
    input.style.display = 'none';
    document.body.appendChild(input);
    input.onchange = function() {
      var file = input.files && input.files[0];
      if (input.parentNode) input.parentNode.removeChild(input);
      if (!file) return;
      if (file.size > TRV_ATTACH_MAX) { alert('10MB 이하 파일만 첨부할 수 있어요.'); return; }
      var row = document.getElementById('trv-attach-' + docId);
      if (row) row.insertAdjacentHTML('beforeend', '<span class="j-attach-uploading">업로드 중…</span>');
      _trvAttachUploadBlob(docId, file, file.name, file.type).then(function() {
        if (typeof showSyncToast === 'function') showSyncToast('<span class="material-symbols-outlined text-sm mr-1">attach_file</span> 첨부 완료');
        _trvAttachRerender(item.type);
      }).catch(function(err) {
        console.error('[trvAttach] 업로드 실패:', err);
        alert('첨부 업로드에 실패했어요.');
        _trvAttachRerender(item.type);
      });
    };
    input.click();
  };

  window.trvAttachDelete = function(docId, idx) {
    var item = _trvAttachFind(docId);
    if (!item || !item.attachments || !item.attachments[idx]) return;
    var att = item.attachments[idx];
    if (!confirm('"' + (att.name || '첨부') + '" 첨부를 삭제할까요?')) return;
    var atts = item.attachments.slice();
    atts.splice(idx, 1);
    fbUpdate('journey', docId, { attachments: atts }).then(function() {
      item.attachments = atts;
      // Storage 원본 삭제는 best-effort
      try { window.storage.refFromURL(att.url).delete().catch(function() {}); } catch (e) {}
      _trvAttachRerender(item.type);
    }).catch(function(err) {
      console.error('[trvAttach] 삭제 실패:', err);
      alert('첨부 삭제에 실패했어요.');
    });
  };

  // 예약 스캔 원본(base64)을 첨부로 자동 업로드 — 실패해도 문서 저장은 유지
  window.trvAttachScanImage = function(docId, b64, ctype) {
    try {
      if (!docId || !b64) return Promise.resolve(null);
      var bin = atob(b64);
      var bytes = new Uint8Array(bin.length);
      for (var i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      var blob = new Blob([bytes], { type: ctype || 'image/jpeg' });
      var ext = ctype === 'application/pdf' ? '.pdf' : (ctype === 'image/png' ? '.png' : '.jpg');
      var name = 'scan_' + new Date().toISOString().slice(0, 10) + ext;
      return _trvAttachUploadBlob(docId, blob, name, ctype || 'image/jpeg').then(function(entry) {
        var item = _trvAttachFind(docId);
        if (item) _trvAttachRerender(item.type);
        return entry;
      }).catch(function(err) {
        console.warn('[trvAttach] 스캔 이미지 첨부 실패 (문서는 저장됨):', err);
        return null;
      });
    } catch (e) {
      console.warn('[trvAttach] 스캔 이미지 첨부 실패 (문서는 저장됨):', e);
      return Promise.resolve(null);
    }
  };

  // 스캔→폼 자동입력 경로: 저장 시 소비되는 첨부 대기열
  window._trvPendingScanAttach = null;
  window.trvConsumeScanAttach = function(docId) {
    var p = window._trvPendingScanAttach;
    window._trvPendingScanAttach = null;
    if (!p || !docId) return;
    window.trvAttachScanImage(docId, p.b64, p.ctype);
  };

  // ═══ (2026-07-23) Wanderlog 이식 1단계: 장소 자동완성 + Day-Pins 지도 + 좌표 소급 ═══
  // 입력 시점에 좌표(lat/lng)를 심으면 지도 핀·스팟 간 이동시간(getTravelTime)이 전부 살아난다

  // ── ① 장소 자동완성 (Google Places 우선 — 이미 로드된 키 재사용, 실패 시 Photon 무료 폴백) ──
  var _acBox = null, _acToken = 0;
  function _acHide() { if (_acBox) { _acBox.remove(); _acBox = null; } }
  function _cityBias(cityName) {
    var c = (citiesData || []).find(function(x){ return x.name === cityName && typeof x.lat === 'number'; });
    if (!c) c = (citiesData || []).find(function(x){ return typeof x.lat === 'number'; });
    return c ? { lat: c.lat, lng: c.lng } : null;
  }
  function attachPlaceAutocomplete(inputEl, cityName) {
    if (!inputEl || inputEl._acAttached) return;
    inputEl._acAttached = true;
    inputEl.setAttribute('autocomplete', 'off');
    var debounce = null;
    inputEl.addEventListener('input', function() {
      // 직접 타이핑 시작 = 이전에 고른 장소의 좌표 무효화
      delete inputEl.dataset.plat; delete inputEl.dataset.plng; delete inputEl.dataset.paddr;
      var q = inputEl.value.trim();
      clearTimeout(debounce);
      if (q.length < 2) { _acHide(); return; }
      debounce = setTimeout(function(){ _acSearch(inputEl, q, cityName); }, 280);
    });
    inputEl.addEventListener('blur', function() { setTimeout(_acHide, 250); });
    inputEl.addEventListener('keydown', function(e) { if (e.key === 'Escape') _acHide(); });
  }
  window.attachPlaceAutocomplete = attachPlaceAutocomplete;

  async function _acSearch(inputEl, q, cityName) {
    var token = ++_acToken;
    var bias = _cityBias(cityName);
    var results = await _acGoogle(q, bias);
    if (!results || !results.length) results = await _acPhoton(q, bias);
    if (token !== _acToken || document.activeElement !== inputEl) return; // 오래된 응답/포커스 이탈
    _acRender(inputEl, results || []);
  }

  function _acGoogle(q, bias) {
    return new Promise(function(resolve) {
      try {
        if (typeof google === 'undefined' || !google.maps || !google.maps.places) { resolve(null); return; }
        var svc = new google.maps.places.AutocompleteService();
        var req = { input: q, language: 'ko' };
        if (bias) { req.location = new google.maps.LatLng(bias.lat, bias.lng); req.radius = 40000; }
        svc.getPlacePredictions(req, function(preds, status) {
          if (status !== 'OK' || !preds || !preds.length) { resolve(null); return; }
          resolve(preds.slice(0, 5).map(function(p) {
            return { name: p.structured_formatting ? p.structured_formatting.main_text : p.description,
                     addr: p.structured_formatting ? (p.structured_formatting.secondary_text || '') : '',
                     placeId: p.place_id, src: 'google' };
          }));
        });
      } catch(e) { resolve(null); }
    });
  }

  async function _acPhoton(q, bias) {
    try {
      var url = 'https://photon.komoot.io/api/?limit=5&q=' + encodeURIComponent(q) +
        (bias ? '&lat=' + bias.lat + '&lon=' + bias.lng : '');
      var r = await fetch(url);
      var j = await r.json();
      if (!j || !j.features) return null;
      return j.features.map(function(f) {
        var p = f.properties || {};
        var addr = [p.street, p.district, p.city, p.country].filter(Boolean).join(', ');
        return { name: p.name || q, addr: addr,
                 lat: f.geometry.coordinates[1], lng: f.geometry.coordinates[0], src: 'photon' };
      });
    } catch(e) { return null; }
  }

  function _acRender(inputEl, results) {
    _acHide();
    if (!results.length) return;
    var r = inputEl.getBoundingClientRect();
    _acBox = document.createElement('div');
    _acBox.className = 'plc-ac';
    _acBox.style.left = r.left + 'px';
    _acBox.style.top = (r.bottom + 4) + 'px';
    _acBox.style.width = Math.max(r.width, 240) + 'px';
    results.forEach(function(res) {
      var item = document.createElement('div');
      item.className = 'plc-ac-item';
      item.innerHTML = '<div class="plc-ac-name"></div>' + (res.addr ? '<div class="plc-ac-addr"></div>' : '');
      item.querySelector('.plc-ac-name').textContent = res.name;
      if (res.addr) item.querySelector('.plc-ac-addr').textContent = res.addr;
      // mousedown: blur보다 먼저 실행돼 클릭이 씹히지 않게
      item.addEventListener('mousedown', function(e) { e.preventDefault(); _acPick(inputEl, res); });
      _acBox.appendChild(item);
    });
    document.body.appendChild(_acBox);
  }

  async function _acPick(inputEl, res) {
    _acHide();
    inputEl.value = res.name;
    var coord = null;
    if (res.src === 'google' && res.placeId) coord = await _acGoogleDetails(res.placeId);
    if (!coord && typeof res.lat === 'number') coord = { lat: res.lat, lng: res.lng, addr: res.addr };
    if (coord) {
      inputEl.dataset.plat = coord.lat; inputEl.dataset.plng = coord.lng;
      inputEl.dataset.paddr = coord.addr || res.addr || '';
    }
    inputEl.focus();
  }

  function _acGoogleDetails(placeId) {
    return new Promise(function(resolve) {
      try {
        var svc = new google.maps.places.PlacesService(document.createElement('div'));
        svc.getDetails({ placeId: placeId, fields: ['geometry', 'formatted_address'] }, function(place, status) {
          if (status === 'OK' && place && place.geometry && place.geometry.location) {
            resolve({ lat: place.geometry.location.lat(), lng: place.geometry.location.lng(), addr: place.formatted_address || '' });
          } else resolve(null);
        });
      } catch(e) { resolve(null); }
    });
  }

  // 자동완성으로 고른 좌표를 input dataset에서 꺼내 저장 객체에 붙이기 (저장 경로 공용)
  function applyPickedCoords(obj, inputEl) {
    if (!inputEl || !inputEl.dataset || !inputEl.dataset.plat) return;
    var la = parseFloat(inputEl.dataset.plat), ln = parseFloat(inputEl.dataset.plng);
    if (isNaN(la) || isNaN(ln)) return;
    obj.lat = la; obj.lng = ln;
    if (inputEl.dataset.paddr) obj.address = inputEl.dataset.paddr;
  }

  // ── ② 스팟 간 이동시간: Google DistanceMatrix 우선, 불가 시 직선거리 추정 폴백 ──
  function _travelBetween(a, b, cb) {
    getTravelTime(a.lat, a.lng, b.lat, b.lng, function(result) {
      if (result) {
        var icon = result.mode === 'walk' ? '🚶' : '🚇';
        cb(icon + ' ' + result.duration + ' · ' + result.distance);
        return;
      }
      var km = _haversineKm(a, b);
      if (!isFinite(km)) { cb(null); return; }
      var walkMin = Math.round(km / 4.5 * 60 * 1.3); // 직선→실보행 보정 1.3배
      cb(km <= 2.2
        ? ('🚶 ~' + walkMin + '분 · ' + km.toFixed(1) + 'km (직선 추정)')
        : ('🚇 ~' + Math.max(8, Math.round(km * 4 + 8)) + '분 · ' + km.toFixed(1) + 'km (추정)'));
    });
  }

  // ── ③ Day-Pins 지도: 일자별 색 핀(방문 순서 번호) + 저장소(pool) 회색 핀 ──
  var _dayPinsMap = null, _dayPinsLayer = null, _dayPinsFilter = 'all';
  var _dayPinsSig = '', _dayPinsFitW = 0, _dayPinsLastBounds = null; // 변경 감지 — 같은 데이터면 지도 뷰를 건드리지 않음
  var _DAY_COLORS = ['#7c3aed', '#0ea5e9', '#f59e0b', '#10b981', '#ef4444', '#ec4899', '#6366f1', '#14b8a6'];

  // ★ (2026-07-24) 지도 일차 칩 → Daily Log 패널 양방향 동기화.
  //   기존엔 패널 ‹ › → 지도 한 방향만 있어서, 지도에서 9일차를 눌러도 옆 패널은 1일차 그대로였다.
  //   currentDayIndex가 이미 같으면 재렌더를 건너뛰어(무한 루프 방지) 안전하다.
  window.setDayPinsFilter = function(f) {
    _dayPinsFilter = f;
    renderDayPinsMap();
    if (f === 'all' || f === 'pool') return;
    var d = parseInt(f, 10);
    if (!d) return;
    var dm = getDayMap(), idx = -1;
    for (var i = 0; i < dm.length; i++) { if (dm[i].day === d) { idx = i; break; } }
    if (idx < 0 || idx === currentDayIndex) return;
    currentDayIndex = idx;
    try { syncWeekChunkToCurrentDay(); } catch(e) {}
    try {
      if (_dlvIsSingleActive()) renderDayView();
      else if (typeof renderWeekView === 'function') renderWeekView();
    } catch(e) {}
  };

  function _dayPinsMissingCount() {
    return (journeyData || []).filter(function(d) {
      if (d.type === '숙소') return !(typeof d.lat === 'number' && typeof d.lng === 'number') && (d.title || d.name || '').trim();
      return (d.type === '일정' || d.type === '스팟') &&
             !(typeof d.lat === 'number' && typeof d.lng === 'number') &&
             (d.title || '').trim() && d.auto_sun == null;
    }).length;
  }

  // 이 날짜 밤을 커버하는 숙소 (동선 앵커·지도 🏨 핀용)
  function _lodgingForDate(dateStr) {
    return (journeyData || []).find(function(d) {
      return d.type === '숙소' && typeof d.lat === 'number' && typeof d.lng === 'number' && d.date &&
             d.date <= dateStr && (d.checkout_date ? dateStr < d.checkout_date : d.date === dateStr);
    }) || null;
  }

  function renderDayPinsMap() {
    var wrap = document.getElementById('daylog-map-wrap');
    var mount = document.getElementById('daylog-map');
    if (!wrap || !mount || typeof L === 'undefined') return;
    var dayMap = getDayMap();
    var dateToDay = {};
    dayMap.forEach(function(e){ dateToDay[e.date] = e.day; });
    var sched = [], pool = [];
    (journeyData || []).forEach(function(d) {
      if (typeof d.lat !== 'number' || typeof d.lng !== 'number') return;
      if (d.type === '일정' && dateToDay[d.date]) sched.push({ it: d, day: dateToDay[d.date] });
      else if (d.type === '스팟' && d.status !== 'planned') pool.push(d);
    });
    var hotels = (journeyData || []).filter(function(d){ return d.type === '숙소' && typeof d.lat === 'number' && typeof d.lng === 'number'; });
    var missing = _dayPinsMissingCount();
    if (!sched.length && !pool.length && !missing) { wrap.style.display = 'none'; return; }
    wrap.style.display = '';

    // ★ (2026-07-23) 변경 없으면 스킵 — 렌더마다 지도가 전체 뷰로 리셋되며 줌/애니메이션을 삼키던 근본 원인 제거
    var sig = _dayPinsFilter + '|' +
      sched.map(function(s){ return s.it._id + ':' + s.it.lat.toFixed(5) + ',' + s.it.lng.toFixed(5) + ':' + (s.it.time || '') + ':' + s.day; }).join(';') + '|' +
      pool.map(function(p){ return p._id + ':' + p.lat.toFixed(5) + ',' + p.lng.toFixed(5); }).join(';') + '|' +
      hotels.map(function(h){ return h._id + ':' + h.lat.toFixed(5); }).join(';') + '|' + missing;
    if (sig === _dayPinsSig && _dayPinsMap) {
      // 데이터 동일 → 뷰(줌·중심·팝업) 보존. 컨테이너 폭이 크게 바뀐 경우만 재맞춤
      var wNow = mount.clientWidth;
      if (wNow && Math.abs(wNow - _dayPinsFitW) > 40) {
        _dayPinsFitW = wNow;
        _dayPinsMap.invalidateSize();
        if (_dayPinsLastBounds) _dayPinsMap.fitBounds(_dayPinsLastBounds, { padding: [36, 36], maxZoom: 15 });
      }
      return;
    }
    _dayPinsSig = sig;
    window._dayPinsMarkers = {}; // 리스트 호버 → 핀 강조용 레지스트리 (journey _id → marker)

    // 필터 칩: 전체 / N일차… / 저장소
    var chips = document.getElementById('daylog-map-chips');
    if (chips) {
      var defs = [{ v: 'all', label: '전체' }];
      dayMap.forEach(function(e) {
        var cnt = sched.filter(function(s){ return s.day === e.day; }).length;
        if (cnt) defs.push({ v: String(e.day), label: e.day + '일차', color: _DAY_COLORS[(e.day - 1) % _DAY_COLORS.length] });
      });
      if (pool.length) defs.push({ v: 'pool', label: '저장소 ' + pool.length });
      chips.innerHTML = defs.map(function(d) {
        var on = _dayPinsFilter === d.v;
        var dot = d.color ? '<span style="display:inline-block;width:7px;height:7px;border-radius:50%;background:' + d.color + ';margin-right:4px"></span>' : '';
        return '<button onclick="setDayPinsFilter(\'' + d.v + '\')" class="px-2.5 py-1 rounded-full text-[11px] font-bold border transition-colors ' +
          (on ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-300 hover:text-indigo-600') + '">' + dot + d.label + '</button>';
      }).join('');
    }

    if (!_dayPinsMap) {
      // 줌 애니메이션 복원 (2026-07-23): 애니메이션을 삼키던 진범은 렌더마다 실행되던 fitBounds 리셋 — sig 스킵으로 제거됨
      // ★ (2026-07-23) 휠 줌은 클릭 후에만 — 트랙패드 스크롤 중 지도 위를 지나가며 줌되던 문제
      _dayPinsMap = L.map(mount, { zoomControl: true, scrollWheelZoom: false, attributionControl: true });
      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; OpenStreetMap &copy; CARTO', maxZoom: 19
      }).addTo(_dayPinsMap);
      _trvMapWheelGate(_dayPinsMap, mount);
      // 핀이 아직 없어도 죽지 않게 초기 뷰 부여 (첫 도시 좌표 or 세계 전도)
      var c0 = (citiesData || []).find(function(x){ return typeof x.lat === 'number'; });
      _dayPinsMap.setView(c0 ? [c0.lat, c0.lng] : [20, 0], c0 ? 11 : 2);
    }
    if (_dayPinsLayer) _dayPinsMap.removeLayer(_dayPinsLayer);
    _dayPinsLayer = L.layerGroup().addTo(_dayPinsMap);

    var latlngs = [];
    var seenPos = {}; // 동일 좌표 겹침 감지 → 살짝 벌려 표시
    var byDay = {};
    sched.forEach(function(s){ (byDay[s.day] = byDay[s.day] || []).push(s.it); });
    Object.keys(byDay).forEach(function(dayKey) {
      var day = parseInt(dayKey, 10);
      if (_dayPinsFilter !== 'all' && _dayPinsFilter !== String(day)) return;
      var color = _DAY_COLORS[(day - 1) % _DAY_COLORS.length];
      var items = byDay[dayKey].slice().sort(function(a, b){
        var t = (a.time || '').localeCompare(b.time || '');
        return t !== 0 ? t : ((a.order || 0) - (b.order || 0));
      });
      var line = [];
      items.forEach(function(it, i) {
        // 동일 좌표에 겹친 핀은 살짝 벌려서 번호가 다 보이게 (~70m)
        var la = it.lat, ln = it.lng;
        var pk = la.toFixed(4) + ',' + ln.toFixed(4);
        var dup = seenPos[pk] || 0; seenPos[pk] = dup + 1;
        if (dup) { la += 0.0006 * dup; ln += 0.0009 * dup; }
        latlngs.push([la, ln]); line.push([la, ln]);
        var icon = L.divIcon({ className: 'daylog-pin', html: '<div class="daylog-pin-inner" style="background:' + color + '">' + (i + 1) + '</div>', iconSize: [24, 24], iconAnchor: [12, 12] });
        var pop = '<strong>' + String(it.title || '').replace(/</g, '&lt;') + '</strong><br>' +
          '<span style="color:' + color + ';font-weight:700">' + day + '일차' + (it.time ? ' · ' + it.time : '') + '</span>' +
          '<br><a href="#" onclick="jumpToDay(' + (day - 1) + ');return false" style="color:#7c3aed;font-weight:700">일정 보기 →</a>';
        var mk = L.marker([la, ln], { icon: icon }).bindPopup(pop).addTo(_dayPinsLayer);
        // ★ 핀 클릭 한 번 = 그 지점으로 스르륵 비행 (Wanderlog식). stop()으로 잔여 애니메이션 정리 후 출발
        mk.on('click', function() { if (_dayPinsMap.getZoom() < 14) { _dayPinsMap.stop(); _dayPinsMap.flyTo(mk.getLatLng(), 15, { duration: 0.9 }); } });
        if (it._id) window._dayPinsMarkers[it._id] = mk;
      });
      // 하루만 선택하면 방문 순서 경로선 표시
      if (_dayPinsFilter === String(day) && line.length > 1) {
        L.polyline(line, { color: color, weight: 3, opacity: 0.8, dashArray: '5 7' }).addTo(_dayPinsLayer);
      }
    });
    if (_dayPinsFilter === 'all' || _dayPinsFilter === 'pool') {
      pool.forEach(function(p) {
        latlngs.push([p.lat, p.lng]);
        var icon = L.divIcon({ className: 'daylog-pin', html: '<div class="daylog-pin-pool"></div>', iconSize: [13, 13], iconAnchor: [7, 7] });
        var pop = '<strong>' + String(p.title || '').replace(/</g, '&lt;') + '</strong><br><span style="color:#94a3b8">저장소 (미배치)' + (p.category ? ' · ' + p.category : '') + '</span>';
        var pmk = L.marker([p.lat, p.lng], { icon: icon }).bindPopup(pop).addTo(_dayPinsLayer);
        pmk.on('click', function() { if (_dayPinsMap.getZoom() < 14) { _dayPinsMap.stop(); _dayPinsMap.flyTo(pmk.getLatLng(), 15, { duration: 0.9 }); } });
      });
    }

    // ★ 숙소 🏨 핀 — 전체 보기: 모든 숙소 / 일차 선택: 그 밤의 숙소만
    var showHotels = hotels;
    if (_dayPinsFilter === 'pool') showHotels = [];
    else if (_dayPinsFilter !== 'all') {
      var fDay = parseInt(_dayPinsFilter, 10);
      var fEntry = dayMap.filter(function(e){ return e.day === fDay; })[0];
      showHotels = fEntry ? hotels.filter(function(h){ return h.date && h.date <= fEntry.date && (h.checkout_date ? fEntry.date < h.checkout_date : h.date === fEntry.date); }) : [];
    }
    showHotels.forEach(function(h) {
      latlngs.push([h.lat, h.lng]);
      var hIcon = L.divIcon({ className: 'daylog-pin', html: '<div class="daylog-pin-hotel">🏨</div>', iconSize: [26, 26], iconAnchor: [13, 13] });
      var hPop = '<strong>' + String(h.title || h.name || '숙소').replace(/</g, '&lt;') + '</strong><br><span style="color:#0f172a;font-weight:700">숙소</span>' +
        (h.date ? ' · ' + h.date.slice(5).replace('-', '/') + '~' + String(h.checkout_date || '').slice(5).replace('-', '/') : '');
      L.marker([h.lat, h.lng], { icon: hIcon, zIndexOffset: 500 }).bindPopup(hPop).addTo(_dayPinsLayer);
    });

    var foot = document.getElementById('daylog-map-foot');
    if (foot && !_geoBusy) {
      foot.innerHTML = '<span>핀 ' + latlngs.length + '개 · 색 = 일차 · 회색 = 저장소 미배치</span>' +
        (missing ? '<button onclick="geocodeTripSpots()" class="px-2 py-0.5 rounded-md border border-indigo-200 text-indigo-600 font-bold hover:bg-indigo-50" style="font-size:10px">📍 좌표 없는 ' + missing + '곳 자동 찾기</button>' : '');
    }

    if (latlngs.length) {
      // 인천공항 등 원거리 핀이 있어도 여행 도시 인근 핀 위주로 화면 맞춤 (세계지도 줌아웃 방지)
      var nearRefs = (citiesData || []).filter(function(c){ return typeof c.lat === 'number'; });
      var focus = latlngs;
      if (nearRefs.length) {
        var near = latlngs.filter(function(p) {
          return nearRefs.some(function(c){ return _haversineKm({ lat: p[0], lng: p[1] }, c) <= 300; });
        });
        if (near.length) focus = near;
      }
      var bounds = L.latLngBounds(focus);
      var fitOpts = { padding: [36, 36], maxZoom: 15 };
      _dayPinsLastBounds = bounds;
      _dayPinsFitW = mount.clientWidth;
      _dayPinsMap.fitBounds(bounds, fitOpts);
      setTimeout(function() { if (_dayPinsMap) { _dayPinsMap.invalidateSize(); _dayPinsMap.fitBounds(bounds, fitOpts); _dayPinsFitW = mount.clientWidth; } }, 250);
    }
  }
  window.renderDayPinsMap = renderDayPinsMap;

  // ★ (2026-07-23) 리스트 → 지도 포커스 (Wanderlog식): 아이템 📍 → 그 핀으로 줌+팝업
  window.focusDayPin = function(jid, ev) {
    if (ev) { ev.stopPropagation(); ev.preventDefault(); }
    var it = (journeyData || []).find(function(d){ return d._id === jid; });
    if (!it || typeof it.lat !== 'number' || typeof it.lng !== 'number') return;
    var needRerender = !(window._dayPinsMarkers || {})[jid];
    if (needRerender) { _dayPinsFilter = 'all'; renderDayPinsMap(); } // 필터에 가려져 있으면 전체로
    var wrap = document.getElementById('daylog-map-wrap');
    if (wrap) wrap.scrollIntoView({ behavior: 'smooth', block: 'center' }); // 지도가 화면 한가운데 오도록
    // 재렌더 시 fitBounds 재시도(250ms)가 setView를 덮지 않게 이후에 실행
    setTimeout(function() {
      if (!_dayPinsMap) return;
      _dayPinsMap.stop();
      _dayPinsMap.flyTo([it.lat, it.lng], Math.max(_dayPinsMap.getZoom(), 15), { duration: 0.9 });
      var mk = (window._dayPinsMarkers || {})[jid];
      if (mk) {
        mk.openPopup();
        if (typeof _setPinHighlight === 'function') {
          _setPinHighlight(jid, true);
          setTimeout(function(){ _setPinHighlight(jid, false); }, 1800);
        }
      }
    }, needRerender ? 350 : 50);
  };

  // 일차 번호 클릭 → 그 날 핀+경로선으로 지도 전환
  window.focusDayOnMap = function(day, ev) {
    if (ev) { ev.stopPropagation(); }
    window.setDayPinsFilter(String(day));
    var wrap = document.getElementById('daylog-map-wrap');
    if (wrap) wrap.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  };

  // ★ (2026-07-23) 하루 안 동선 최적화 — 시간 슬롯은 유지, 방문 스팟만 가까운 순으로 재배치.
  //   예약·고정·이동류(체크인/공항/기차 등)는 자리를 지키고, 자유 일정만 움직인다. 적용 전 미리보기 confirm.
  window.optimizeDayRoute = async function(dateStr) {
    var items = (journeyData || []).filter(function(d) {
      return d.type === '일정' && d.date === dateStr &&
             typeof d.lat === 'number' && typeof d.lng === 'number' && d.time;
    });
    items.sort(function(a, b){ return (a.time || '').localeCompare(b.time || ''); });
    if (items.length < 3) { alert('좌표와 시간이 있는 일정이 3개 이상일 때 의미가 있어요.'); return; }
    var locked = items.map(function(it) {
      return it.reservation === true || it.pinned === true || it.auto_sun != null ||
             /체크인|체크아웃|공항|이동|출발|도착|기차|비행|ICE|짐 |일몰|일출|노을|sunset|sunrise/i.test(it.title || '');
    });
    var pool = [];
    items.forEach(function(it, i){ if (!locked[i]) pool.push(it); });
    if (pool.length < 2) { alert('재배치할 수 있는 자유 일정이 부족해요 (예약·고정·이동 일정은 자리를 지켜요).'); return; }

    // nearest-neighbor: 잠긴 슬롯 사이를 자유 일정으로 가까운 순 채우기
    // ★ 숙소가 있으면 그 밤의 숙소를 출발·복귀 기준점으로
    var hotel = (typeof _lodgingForDate === 'function') ? _lodgingForDate(dateStr) : null;
    var newSeq = items.slice();
    var cur = hotel;
    for (var i = 0; i < newSeq.length; i++) {
      if (locked[i]) { cur = items[i]; continue; }
      var bi = 0, bd = Infinity;
      for (var p = 0; p < pool.length; p++) {
        var d = cur ? _haversineKm(cur, pool[p]) : 0;
        if (d < bd) { bd = d; bi = p; }
      }
      newSeq[i] = pool.splice(bi, 1)[0];
      cur = newSeq[i];
    }
    function chainKm(arr) {
      var s = 0, prev = hotel;
      for (var c = 0; c < arr.length; c++) { if (prev) s += _haversineKm(prev, arr[c]); prev = arr[c]; }
      if (hotel && prev) s += _haversineKm(prev, hotel); // 마지막 → 숙소 복귀
      return s;
    }
    var before = chainKm(items), after = chainKm(newSeq);
    if (after >= before * 0.97) {
      if (typeof showSyncToast === 'function') showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 지금 순서가 이미 거의 최적! (총 ' + before.toFixed(1) + 'km)');
      else alert('지금 순서가 이미 거의 최적이야! (총 이동 ' + before.toFixed(1) + 'km)');
      return;
    }
    var pct = Math.round((1 - after / before) * 100);

    // 적용: 원래 시간 슬롯에 새 순서 아이템 배치, 소요시간은 각자 유지
    var applyRoute = async function() {
      function toMin(t){ var m = /^(\d{1,2}):(\d{2})/.exec(t || ''); return m ? (+m[1]) * 60 + (+m[2]) : null; }
      function toHHMM(min){ min = ((min % 1440) + 1440) % 1440; return ('0' + Math.floor(min / 60)).slice(-2) + ':' + ('0' + (min % 60)).slice(-2); }
      var slots = items.map(function(it){ return it.time; });
      // ★ 겹침 없는 타임라인 보장: 자유 일정 전부(이동한 것 + 제자리인 것)에
      //   ① 앞 일정 끝 이후 시작  ② 뒤 고정 일정 시작 전 종료(초과 시 방문시간 축소) 적용
      var cursorMin = null;
      var lockedStarts = []; // k 이후의 고정 일정 시작 시각들
      for (var li = 0; li < items.length; li++) { if (locked[li]) { var lm = toMin(items[li].time); if (lm != null) lockedStarts.push({ k: li, min: lm }); } }
      function nextLockedStart(k) {
        for (var q = 0; q < lockedStarts.length; q++) { if (lockedStarts[q].k > k) return lockedStarts[q].min; }
        return null;
      }
      for (var k = 0; k < newSeq.length; k++) {
        var it2 = newSeq[k];
        var s0 = toMin(it2.time), e0 = toMin(it2.end_time);
        var dur = (s0 != null && e0 != null && e0 > s0) ? (e0 - s0) : null;
        if (locked[k]) {
          // 고정 일정 — 시간 불변, 커서만 전진
          if (s0 != null) cursorMin = Math.max(cursorMin || 0, dur != null ? s0 + dur : s0);
          continue;
        }
        var moved = (it2._id !== items[k]._id);
        var nsMin = moved ? toMin(slots[k]) : s0;
        if (nsMin != null && cursorMin != null && nsMin < cursorMin) nsMin = cursorMin; // 앞 일정 끝으로 밀기
        var neMin = (dur != null && nsMin != null) ? nsMin + dur : null;
        var wall = nextLockedStart(k);
        if (neMin != null && wall != null && nsMin < wall && neMin > wall) neMin = wall; // 뒤 고정 일정 침범 시 방문시간 축소
        var ns = (nsMin != null) ? toHHMM(nsMin) : (moved ? slots[k] : it2.time);
        var ne = (neMin != null) ? toHHMM(neMin) : (moved ? '' : (it2.end_time || ''));
        var changed = (ns !== it2.time) || (ne !== (it2.end_time || ''));
        it2.time = ns; it2.end_time = ne;
        if (nsMin != null) cursorMin = Math.max(cursorMin || 0, neMin != null ? neMin : nsMin);
        if (changed && it2._id) { try { await fbUpdate('journey', it2._id, { time: ns, end_time: ne }); } catch(e) {} }
      }
      renderWeekView();
      if (typeof renderDayView === 'function') renderDayView();
      if (typeof showSyncToast === 'function') showSyncToast('<span class="material-symbols-outlined text-sm mr-1">route</span> 동선 최적화 적용 — ' + before.toFixed(1) + 'km → ' + after.toFixed(1) + 'km');
    };

    // 아뜰리에 스타일 미리보기 모달 (커스텀 확인창 재사용, 없으면 confirm 폴백)
    var listHtml = newSeq.map(function(it, n) {
      return '<li style="display:flex;align-items:center;gap:7px;padding:3.5px 0;font-size:12px;color:#334155;text-align:left">' +
        '<span style="width:18px;height:18px;border-radius:50%;background:#ede9fe;color:#6d28d9;font-size:10px;font-weight:800;display:inline-flex;align-items:center;justify-content:center;flex-shrink:0">' + (n + 1) + '</span>' +
        '<span style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + String(it.title || '').replace(/</g, '&lt;') + '</span>' +
        (locked[n] ? '<span style="font-size:9px;font-weight:700;color:#94a3b8;background:#f1f5f9;border-radius:6px;padding:1px 6px;flex-shrink:0">고정</span>' : '') +
      '</li>';
    }).join('');
    var html =
      '<span style="display:flex;align-items:baseline;gap:8px;justify-content:center;margin-bottom:10px">' +
        '<span style="font-size:13px;color:#94a3b8;text-decoration:line-through">' + before.toFixed(1) + 'km</span>' +
        '<span style="font-size:20px;font-weight:800;color:#7c3aed">' + after.toFixed(1) + 'km</span>' +
        '<span style="font-size:11px;font-weight:800;color:#059669;background:#ecfdf5;border-radius:99px;padding:2px 8px">-' + pct + '%</span>' +
      '</span>' +
      '<ol style="list-style:none;margin:0;padding:8px 12px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;max-height:230px;overflow-y:auto">' + listHtml + '</ol>' +
      '<span style="display:block;font-size:10px;color:#94a3b8;margin-top:8px">' + (hotel ? '🏨 ' + String(hotel.title || '숙소').replace(/</g, '&lt;').slice(0, 20) + ' 출발·복귀 기준 · ' : '') + '시간대는 유지 · 방문 순서만 변경 · 예약/이동/일몰 일정은 자리 고정</span>';
    if (typeof showConfirm === 'function' && document.getElementById('atl-confirm')) {
      showConfirm({ title: '동선 최적화', icon: '🧭', html: html, confirmText: '적용', onConfirm: function(){ applyRoute(); } });
    } else if (confirm('🧭 동선 최적화 — 총 이동 ' + before.toFixed(1) + 'km → ' + after.toFixed(1) + 'km (' + pct + '% 절감). 적용할까?')) {
      applyRoute();
    }
  };

  // ── ④ 좌표 소급: 기존 일정/스팟 좌표 자동 찾기 (도시 60km 검증으로 오매칭 차단) ──
  var _geoBusy = false;
  window.geocodeTripSpots = async function() {
    if (_geoBusy) return;
    _geoBusy = true;
    var foot = document.getElementById('daylog-map-foot');
    var dayMap = getDayMap();
    var dateToCity = {};
    dayMap.forEach(function(e){ dateToCity[e.date] = e.cityName; });
    // 검증 기준이 되는 도시 좌표부터 확보 (없으면 지오코드 후 Firestore에 1회 저장)
    if (foot) foot.innerHTML = '<span>📍 도시 기준 좌표 확보 중...</span>';
    for (var c0 = 0; c0 < (citiesData || []).length; c0++) {
      try { await ensureCityCoord(citiesData[c0]); } catch(e) {}
    }
    var targets = (journeyData || []).filter(function(d) {
      if (typeof d.lat === 'number' && typeof d.lng === 'number') return false;
      if (d.type === '숙소') return !!(d.title || d.name || '').trim();
      return (d.type === '일정' || d.type === '스팟') && (d.title || '').trim() && d.auto_sun == null;
    });
    var ok = 0, fail = [];
    for (var i = 0; i < targets.length; i++) {
      var it = targets[i];
      if (foot) foot.innerHTML = '<span>📍 좌표 찾는 중... ' + (i + 1) + '/' + targets.length + ' — ' + String(it.title || '').replace(/</g, '&lt;') + '</span>';
      // 검증 기준 도시: 아이템 city(한글일 수 있음) → 그 날짜의 Stops 도시 순으로 좌표 있는 쪽
      var cands = [(it.city || '').trim(), dateToCity[it.date] || ''].filter(Boolean);
      var cityRef = null;
      for (var ci2 = 0; ci2 < cands.length && !cityRef; ci2++) {
        var nm = cands[ci2];
        cityRef = (citiesData || []).find(function(c){ return c.name === nm && typeof c.lat === 'number'; });
        if (!cityRef && typeof _normCityKey === 'function') {
          var ck = _normCityKey(nm);
          cityRef = (citiesData || []).find(function(c) {
            if (typeof c.lat !== 'number') return false;
            var cn = _normCityKey(c.name || '');
            return ck && cn && (cn === ck || cn.indexOf(ck) >= 0 || ck.indexOf(cn) >= 0);
          });
        }
      }
      // 기준 좌표가 없으면: 아이템의 도시명을 직접 지오코딩해 기준으로 (저장소 스팟의 당일치기 도시 등)
      if (!cityRef && cands.length) {
        try {
          var cg = await geocodeCity(cands[0]);
          if (cg) cityRef = { name: cands[0], lat: cg.lat, lng: cg.lng };
        } catch(e) {}
      }
      if (!cityRef) cityRef = (citiesData || []).find(function(c){ return typeof c.lat === 'number'; }) || null;
      if (!cityRef) { fail.push(it.title); continue; }
      var geo = await _geocodePOI(it.title, cityRef.name, cityRef);
      if (geo && cityRef && _haversineKm(geo, cityRef) > 200) geo = null; // 당일치기 반경(200km) 밖 = 오매칭 (세부 한도는 _geocodePOI가 소스별로 적용)
      if (geo) {
        it.lat = geo.lat; it.lng = geo.lng;
        if (it._id) { try { await fbUpdate('journey', it._id, { lat: geo.lat, lng: geo.lng }); } catch(e) {} }
        ok++;
      } else fail.push(it.title);
      await new Promise(function(r){ setTimeout(r, 1400); }); // 구글 스로틀·Nominatim 예의
    }
    _geoBusy = false;
    renderDayPinsMap();
    if (typeof renderWeekView === 'function') renderWeekView();
    if (typeof renderDayView === 'function') renderDayView();
    alert('좌표 찾기 완료 — 성공 ' + ok + '곳' + (fail.length ? '\n못 찾음(' + fail.length + '): ' + fail.slice(0, 8).join(', ') + (fail.length > 8 ? ' 외' : '') : ''));
  };

  // 제목 정리: 이모지·★주석★·(괄호)·대시 뒤 설명 제거 — 지오코더가 읽을 수 있는 형태로
  function _cleanPOITitle(t) {
    var s = String(t || '');
    s = s.replace(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2B00}-\u{2BFF}️→←⇄]/gu, ' ');
    s = s.replace(/★[^★]*★/g, ' ');
    s = s.replace(/\([^)]*\)/g, ' ');
    s = s.split('—')[0].split('–')[0];
    return s.replace(/\s{2,}/g, ' ').trim();
  }

  function _googleGeo(q, isRetry) {
    return new Promise(function(resolve) {
      try {
        if (typeof google === 'undefined' || !google.maps || !google.maps.Geocoder) { resolve(null); return; }
        new google.maps.Geocoder().geocode({ address: q }, function(res, status) {
          if (status === 'OK' && res && res[0]) {
            var t = res[0].types || [];
            resolve({ lat: res[0].geometry.location.lat(), lng: res[0].geometry.location.lng(),
                      // 주(region)/국가 수준 결과 = 지명을 못 찾고 큰 행정구역만 잡은 약한 매칭
                      weak: t.indexOf('administrative_area_level_1') >= 0 || t.indexOf('country') >= 0 });
          } else if (status === 'OVER_QUERY_LIMIT' && !isRetry) {
            // 배치 실행 중 순간 폭주 스로틀 — 1.3초 쉬고 1회 재시도
            setTimeout(function(){ _googleGeo(q, true).then(resolve); }, 1300);
          } else resolve(null);
        });
      } catch(e) { resolve(null); }
    });
  }

  // 구글 Places 텍스트검색 — POI 이름(온천 광장·두오모 등)에 Geocoder보다 훨씬 강함
  function _googlePlaceSearch(q, bias, isRetry) {
    return new Promise(function(resolve) {
      try {
        if (typeof google === 'undefined' || !google.maps || !google.maps.places) { resolve(null); return; }
        var svc = new google.maps.places.PlacesService(document.createElement('div'));
        var req = { query: q };
        if (bias) { req.location = new google.maps.LatLng(bias.lat, bias.lng); req.radius = 50000; }
        svc.textSearch(req, function(res, status) {
          if (status === 'OK' && res && res[0] && res[0].geometry) {
            resolve({ lat: res[0].geometry.location.lat(), lng: res[0].geometry.location.lng() });
          } else if (status === 'OVER_QUERY_LIMIT' && !isRetry) {
            setTimeout(function(){ _googlePlaceSearch(q, bias, true).then(resolve); }, 1300);
          } else resolve(null);
        });
      } catch(e) { resolve(null); }
    });
  }

  async function _geocodePOI(title, cityName, cityRef) {
    var base = _cleanPOITitle(title);
    if (!base) return null;
    var latin = (base.match(/[A-Za-zÀ-ÿ][A-Za-zÀ-ÿ0-9@&'.\- ]{2,}/g) || []).join(' ').replace(/\s{2,}/g, ' ').trim();
    var bias = cityRef ? { lat: cityRef.lat, lng: cityRef.lng } : null;
    var LIM_G = 200, LIM_FREE = 60; // 구글 결과는 당일치기 반경(200km)까지 신뢰, 무료 소스는 60km 엄격

    // 0) Places 텍스트검색 (도시 바이어스) — POI 최강 소스
    var ps = await _googlePlaceSearch(base, bias);
    if (ps && (!cityRef || _haversineKm(ps, cityRef) <= LIM_G)) return ps;

    // ── 구글: 제목 단독 먼저 (제목 속 지명 — 몬탈치노·오르비에토 등 당일치기 대응),
    //    그다음 제목+숙박도시 (단독 검색이 애매할 때의 안전망)
    var gq = [];
    if (latin && latin.length >= 4 && latin !== base) gq.push({ q: latin, titleOnly: true });
    gq.push({ q: base, titleOnly: true });
    gq.push({ q: base + (cityName ? ', ' + cityName : ''), titleOnly: false });
    for (var g = 0; g < gq.length; g++) {
      var r = await _googleGeo(gq[g].q);
      if (!r) continue;
      if (gq[g].titleOnly && r.weak) continue; // "토스카나 저녁" → 토스카나 주(州) 같은 뭉툭한 결과 배제
      if (!cityRef || _haversineKm(r, cityRef) <= LIM_G) return { lat: r.lat, lng: r.lng };
    }

    // ── 무료 폴백 (Photon → Nominatim, 60km 엄격)
    var tries = [];
    if (latin && latin.length >= 4) tries.push(latin);
    if (tries.indexOf(base) < 0) tries.push(base);
    for (var t = 0; t < tries.length; t++) {
      var q = tries[t];
      try {
        var ph = await _acPhoton(q, bias);
        if (ph && ph.length) {
          for (var pi = 0; pi < ph.length; pi++) {
            var cand = { lat: ph[pi].lat, lng: ph[pi].lng };
            if (!cityRef || _haversineKm(cand, cityRef) <= LIM_FREE) return cand;
          }
        }
      } catch(e) {}
      try {
        var rr = await fetch('https://nominatim.openstreetmap.org/search?format=json&limit=1&q=' + encodeURIComponent(q + (cityName ? ', ' + cityName : '')), { headers: { 'Accept': 'application/json' } });
        var j = await rr.json();
        if (j && j[0]) {
          var nCand = { lat: parseFloat(j[0].lat), lng: parseFloat(j[0].lon) };
          if (!cityRef || _haversineKm(nCand, cityRef) <= LIM_FREE) return nCand;
        }
      } catch(e) {}
    }
    return null;
  }

  window.trvJumpSec = function(id) {
    var scrollTargetId = id;
    if (window._trvLedgerIds.indexOf(id) >= 0) {
      window.trvLedgerShow(id);          // 장부 항목이면 탭 전환 후
      scrollTargetId = 'trv-ledger';     // 패널 위치(항상 같은 자리)로 이동
    }
    var sec = document.getElementById(scrollTargetId);
    if (!sec) return;
    if (sec.getAttribute('data-collapsed') === '1') window.trvToggleSec(scrollTargetId, false);
    var top = sec.getBoundingClientRect().top + window.scrollY - 80;
    window.scrollTo({ top: Math.max(0, top), behavior: 'smooth' });
  };

  // Overview: 여행의 핵심 숫자 한눈에 + 칩 클릭 → 섹션 점프
  window.renderJourneyOverview = function() {
    var el = document.getElementById('journey-overview');
    if (!el) return;
    try {
      var jd = (typeof journeyData !== 'undefined' && journeyData) ? journeyData : [];
      var cities = (typeof citiesData !== 'undefined' && citiesData) ? citiesData : [];
      if (!cities.length && !jd.length) { el.style.display = 'none'; return; }
      var cnt = function(t) { return jd.filter(function(d) { return d.type === t; }).length; };
      var domCnt = function(id) { var c = document.getElementById(id); return c ? c.children.length : 0; };
      var nights = 0;
      cities.forEach(function(c) {
        if (c.start_date && c.end_date) nights += Math.max(0, Math.round((new Date(c.end_date + 'T00:00:00') - new Date(c.start_date + 'T00:00:00')) / 86400000));
      });
      var souvenirs = jd.filter(function(d) { return d.type === '기념품'; });
      var souvDone = souvenirs.filter(function(sv) { return sv.done || sv.purchased || sv.checked; }).length;
      var flights = Math.max(cnt('항공편'), domCnt('journey-flight-list'));
      var lodging = domCnt('journey-lodging-list');
      var transit = Math.max(cnt('이동수단'), domCnt('journey-transport-list'));
      var rental = domCnt('journey-rental-list');
      var rain = window._journeyRainDays || [];
      var chips = [
        ['Stops', cities.length + '개 도시', nights ? nights + '박' : '', 'trv-stops', ''],
        ['Flights', flights + '편', '', 'trv-flights', ''],
        ['Lodging', lodging + '곳', '', 'trv-lodging', ''],
        ['Transit', transit + '건', '', 'trv-transport', ''],
        ['Rental', rental + '건', '', 'trv-rental', ''],
        ['Souvenir', souvDone + '/' + souvenirs.length, '구매 완료', 'trv-souvenir', ''],
        rain.length
          ? ['Weather', '☔ 비 예보 ' + rain.length + '일', rain.slice(0, 2).join(' · '), 'trv-stops', 'warn']
          : ['Weather', '☀️ 예보 무난', '체류 기간 기준', 'trv-stops', '']
      ];
      el.innerHTML = chips.map(function(c) {
        return '<div class="trv-ov-chip' + (c[4] === 'warn' ? ' is-warn' : '') + '" onclick="trvJumpSec(\'' + c[3] + '\')" title="클릭하면 해당 섹션으로 이동">' +
          '<p class="trv-ov-l">' + c[0] + '</p><div class="trv-ov-v">' + c[1] + '</div>' +
          (c[2] ? '<div class="trv-ov-sub">' + c[2] + '</div>' : '') + '</div>';
      }).join('');
      el.style.display = 'grid';
    } catch(e) { console.warn('[overview]', e); }
  };

  // ★ (2026-07-23) 스팟 탭: Atlas와 같은 방식 — page-journey 안에서 일정 콘텐츠를 숨기고
  //   #travel-places-section만 풀폭 표시 (별도 페이지 아님)
  window.showTravelPlaces = function() {
    var sec = document.getElementById('travel-places-section');
    if (!sec) return;
    sec.style.display = 'block';
    try { renderTripTabs(); } catch(e) {}   // 여행 선택 드롭다운 라벨/옵션 채우기
    try { if (typeof window.renderPlaces === 'function') window.renderPlaces(); } catch(e) {}
    var titleEl = document.getElementById('page-title');
    if (titleEl) titleEl.textContent = 'Travel · Places';
  };
  window.hideTravelPlaces = function() {
    var sec = document.getElementById('travel-places-section');
    if (sec) sec.style.display = 'none';
    // page-content-wrap 복구 (journey 페이지)
    var page = document.getElementById('page-journey');
    if (page) {
      var contentWrap = page.querySelector('.page-content-wrap');
      if (contentWrap) contentWrap.style.display = '';
    }
  };

  // ═══════════════════════════════════════════════════════════════════════
  //  ★ (2026-07-23) 항공(Flight) 탭 — 외부 항공권 API 의존 없이 3축 구성
  //    1) Departure Prep : 현재 트립 항공편의 D-day + 시간순 준비 체크리스트
  //    2) Flight Profile : 전체 트립 누적 비행 통계 · 세계지도 궤적 · 연도별 차트
  //    3) Price Watch    : 관심 노선 등록 + 수기 가격 스냅샷 (SVG 라인 차트)
  // ═══════════════════════════════════════════════════════════════════════

