// localStorage 용량 정리 — 백업/스냅샷/캐시 등 비필수 데이터 삭제
function cleanupLocalStorageForSpace() {
  var deletedKeys = [];
  var totalFreedKB = 0;
  // 우선순위 1: 백업 (가장 큰 용량 차지, Firestore에 원본 있음)
  var backupKeys = [];
  for (var i = 0; i < localStorage.length; i++) {
    var k = localStorage.key(i);
    if (!k) continue;
    if (k.indexOf('atelier_backup_') === 0 ||
        k === 'atelier_trash' ||
        k.indexOf('atelier_snapshot_') === 0 ||
        k.indexOf('atelier_city_cache_') === 0 ||
        k.indexOf('atelier_news_cache_') === 0 ||
        k.indexOf('atelier_wx_') === 0) {
      backupKeys.push(k);
    }
  }
  backupKeys.forEach(function(k) {
    try {
      var size = (localStorage.getItem(k) || '').length;
      localStorage.removeItem(k);
      deletedKeys.push(k);
      totalFreedKB += Math.round(size / 1024);
    } catch(e){}
  });
  console.log('[Storage Cleanup] Deleted ' + deletedKeys.length + ' keys, freed ~' + totalFreedKB + ' KB');
  console.log('[Storage Cleanup] Deleted:', deletedKeys);
  return { count: deletedKeys.length, freedKB: totalFreedKB };
}

// localStorage 사용량 측정 (디버깅용)
function getLocalStorageSize() {
  var total = 0;
  for (var i = 0; i < localStorage.length; i++) {
    var k = localStorage.key(i);
    if (!k) continue;
    total += (k.length + (localStorage.getItem(k) || '').length) * 2; // UTF-16 = 2 bytes
  }
  return Math.round(total / 1024);
}

function saveInlineApiKey() {
  var input = document.getElementById('review-inline-apikey');
  var hint = document.getElementById('review-inline-apikey-hint');
  if (!input) { console.error('[ApiKey] inline input not found'); return; }
  var key = input.value.trim();
  console.log('[ApiKey] save attempt, length=' + key.length + ', starts=' + key.substring(0,7));
  console.log('[ApiKey] localStorage usage before save: ' + getLocalStorageSize() + ' KB');

  if (!key) {
    if (hint) { hint.textContent = '⚠ 키를 입력해주세요'; hint.className = 'text-[11px] text-rose-700 mt-2 px-1 font-bold'; }
    input.focus();
    return;
  }
  if (!key.startsWith('sk-ant-')) {
    if (hint) { hint.textContent = '⚠ 키 형식이 올바르지 않아요 — "sk-ant-"로 시작해야 함 (현재: "' + key.substring(0,10) + '...")'; hint.className = 'text-[11px] text-rose-700 mt-2 px-1 font-bold'; }
    return;
  }

  // 1) localStorage 즉시 저장 — quota 초과 시 자동 정리 후 재시도
  function trySave() {
    localStorage.setItem('atelier_anthropic_api_key', key);
    if (!localStorage.getItem('atelier_anthropic_model')) {
      localStorage.setItem('atelier_anthropic_model', 'claude-opus-4-7');
    }
  }
  try {
    trySave();
    console.log('[ApiKey] localStorage saved OK');
  } catch (e) {
    console.warn('[ApiKey] First attempt failed (quota):', e.message);
    console.log('[ApiKey] Running cleanup...');
    var result = cleanupLocalStorageForSpace();
    if (hint) {
      hint.textContent = '🧹 저장 공간 정리 중... (' + result.count + '개 항목, ~' + result.freedKB + 'KB 확보)';
      hint.className = 'text-[11px] text-amber-700 mt-2 px-1';
    }
    try {
      trySave();
      console.log('[ApiKey] localStorage saved OK after cleanup');
    } catch (e2) {
      console.error('[ApiKey] Still failing after cleanup:', e2);
      if (hint) {
        hint.textContent = '⚠ 저장 공간 부족 — 브라우저 데이터 정리가 필요해요. 콘솔(F12)에서 localStorage.clear() 실행 후 다시 시도해주세요.';
        hint.className = 'text-[11px] text-rose-700 mt-2 px-1 font-bold';
      }
      return;
    }
  }

  // 2) 즉시 UI 갱신 (Firestore 기다리지 말고)
  input.value = '';
  updateReviewApiKeyUI();
  updateAutoGenButton();
  if (typeof _updateTravelApiKeyBtn === 'function') _updateTravelApiKeyBtn();
  showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> API 키 저장 완료!');

  // 3) Firestore는 진짜 백그라운드 (실패해도 무방)
  syncApiKeyToFirestore()
    .then(function() { console.log('[ApiKey] Firestore synced OK'); })
    .catch(function(e) { console.warn('[ApiKey] Firestore sync failed (이 기기에는 저장됨):', e.message); });
}

function resetInlineApiKey() {
  if (!confirm('현재 저장된 API 키를 지우고 새로 입력할까요?\n(Firestore에서도 삭제됩니다)')) return;
  localStorage.removeItem('atelier_anthropic_api_key');
  syncApiKeyToFirestore().catch(function(){});
  updateReviewApiKeyUI();
  updateAutoGenButton();
}

// ===== Firestore <-> localStorage 동기화 =====
async function syncApiKeyToFirestore() {
  if (typeof db === 'undefined' && typeof window.db === 'undefined') return;
  var dbRef = (typeof db !== 'undefined') ? db : window.db;
  var key = localStorage.getItem('atelier_anthropic_api_key') || '';
  var model = localStorage.getItem('atelier_anthropic_model') || 'claude-opus-4-7';
  await dbRef.collection('atelier_settings').doc('api').set({
    apiKey: key,
    model: model,
    _updatedAt: firebase.firestore.FieldValue.serverTimestamp()
  }, { merge: true });
}

async function loadApiKeyFromFirestore() {
  try {
    if (typeof db === 'undefined' && typeof window.db === 'undefined') return;
    var dbRef = (typeof db !== 'undefined') ? db : window.db;
    var snap = await dbRef.collection('atelier_settings').doc('api').get();
    if (!snap.exists) return;
    var data = snap.data() || {};
    if (data.apiKey) localStorage.setItem('atelier_anthropic_api_key', data.apiKey);
    if (data.model)  localStorage.setItem('atelier_anthropic_model', data.model);
    // Refresh any open UI
    if (typeof updateReviewApiKeyUI === 'function') updateReviewApiKeyUI();
    if (typeof updateAutoGenButton === 'function') updateAutoGenButton();
    if (typeof _updateTravelApiKeyBtn === 'function') _updateTravelApiKeyBtn();
  } catch(e) { console.warn('[Settings] Firestore load failed:', e.message); }
}

// 페이지 로드 직후 1회 자동 동기화
(function() {
  function tryLoad() {
    if (typeof firebase === 'undefined' || (typeof db === 'undefined' && typeof window.db === 'undefined')) {
      setTimeout(tryLoad, 400);
      return;
    }
    loadApiKeyFromFirestore();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', tryLoad);
  } else {
    tryLoad();
  }
})();

