// ===== 트랜스크립트 붙여넣기 시 자동 전처리 =====
(function() {
  document.addEventListener('DOMContentLoaded', function() {
    var ta = document.getElementById('review-transcript');
    if (ta) {
      ta.addEventListener('paste', function(e) {
        e.preventDefault();
        var pasted = (e.clipboardData || window.clipboardData).getData('text');
        if (pasted) {
          var cleaned = cleanTranscript(pasted);
          // 커서 위치에 삽입
          var start = ta.selectionStart;
          var end = ta.selectionEnd;
          var before = ta.value.substring(0, start);
          var after = ta.value.substring(end);
          ta.value = before + cleaned + after;
          ta.selectionStart = ta.selectionEnd = start + cleaned.length;
        }
      });
    }
  });
})();

// ===== 트랜스크립트 전처리 =====
function cleanTranscript(rawText) {
  // MacWhisper 타임스탬프 형식 자동 제거
  var cleaned = rawText.replace(/\[\d{2}:\d{2}:\d{2}\.\d+\s*-->\s*\d{2}:\d{2}:\d{2}\.\d+\]\s*/g, '');
  // SRT 타임스탬프 형식 제거
  cleaned = cleaned.replace(/\d{2}:\d{2}:\d{2},\d+\s*-->\s*\d{2}:\d{2}:\d{2},\d+\s*/g, '');
  // SRT 시퀀스 번호 제거 (줄 시작의 단독 숫자)
  cleaned = cleaned.replace(/^\d+\s*$/gm, '');
  // 빈 줄 정리
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n').trim();
  return cleaned;
}

// ===== DRAG & DROP TRANSCRIPT FILE =====
function handleReviewFileDrop(files) {
  if (!files || files.length === 0) return;
  var file = files[0];

  // 확장자 검증 - 텍스트 기반 파일 허용
  var allowedExts = ['.txt', '.md', '.srt'];
  var fileName = file.name.toLowerCase();
  var validExt = allowedExts.some(function(ext) { return fileName.endsWith(ext); });
  if (!validExt) {
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 텍스트 파일만 업로드 가능해요 (.txt, .md, .srt)');
    return;
  }
  // 크기 검증 (10MB)
  if (file.size > 10 * 1024 * 1024) {
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 파일이 너무 커요 (10MB 이하만 가능)');
    return;
  }

  // 파일명에서 날짜 + 수업명 추출
  var baseName = file.name.replace(/\.(txt|md|srt)$/i, '');
  var dateMatch = baseName.match(/(\d{4})[-._]?(\d{2})[-._]?(\d{2})/);
  var extractedDate = '';
  var extractedTitle = '';

  if (dateMatch) {
    extractedDate = dateMatch[1] + '-' + dateMatch[2] + '-' + dateMatch[3];
    // 날짜 패턴 제거 후 수업명 추출
    extractedTitle = baseName.replace(/\d{4}[-._]?\d{2}[-._]?\d{2}/, '').replace(/^[-_.\s]+|[-_.\s]+$/g, '');
  } else {
    // 날짜 없으면 파일 수정 날짜 사용
    var lastMod = new Date(file.lastModified);
    extractedDate = lastMod.toISOString().split('T')[0];
    extractedTitle = baseName;
  }
  // 언더스코어 → 공백
  extractedTitle = extractedTitle.replace(/_/g, ' ').trim();

  // 파일 내용 읽기
  var reader = new FileReader();
  reader.onload = function(e) {
    var text = e.target.result;
    if (!text || !text.trim()) {
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 파일이 비어있어요');
      return;
    }

    // 타임스탬프 전처리 후 필드 채우기
    var cleanedText = cleanTranscript(text);
    document.getElementById('review-date').value = extractedDate;
    if (extractedTitle) document.getElementById('review-title').value = extractedTitle;
    document.getElementById('review-transcript').value = cleanedText;

    // 성공 피드백
    var dz = document.getElementById('review-dropzone');
    dz.classList.add('review-dz-success');
    setTimeout(function(){ dz.classList.remove('review-dz-success'); }, 1500);

    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 파일 로드 완료 · ' + extractedDate);

    // 1초 후 자동 생성 실행
    setTimeout(function() {
      var apiKey = localStorage.getItem('atelier_anthropic_api_key');
      if (apiKey) {
        autoGenerateReview();
      } else {
        showSyncToast('<span class="material-symbols-outlined text-sm mr-1">info</span> API 키를 설정하면 자동 생성이 시작됩니다');
        updateAutoGenButton();
      }
    }, 1000);
  };
  reader.onerror = function() {
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 파일을 읽을 수 없어요. 다시 시도해 주세요');
  };
  reader.readAsText(file, 'UTF-8');
}

var _manualReviewOpen = false;
function toggleManualReview() {
  _manualReviewOpen = !_manualReviewOpen;
  var section = document.getElementById('review-manual-section');
  var chevron = document.getElementById('review-manual-chevron');
  if (_manualReviewOpen) {
    section.style.display = 'block';
    section.style.maxHeight = '0px';
    section.style.opacity = '0';
    setTimeout(function(){ section.style.transition = 'max-height 0.3s ease, opacity 0.3s ease'; section.style.maxHeight = '600px'; section.style.opacity = '1'; }, 10);
    if (chevron) chevron.style.transform = 'rotate(90deg)';
  } else {
    section.style.transition = 'max-height 0.3s ease, opacity 0.2s ease';
    section.style.maxHeight = '0px';
    section.style.opacity = '0';
    setTimeout(function(){ section.style.display = 'none'; section.style.transition = ''; }, 300);
    if (chevron) chevron.style.transform = '';
  }
}

