  function closeVaultBulkModal() { document.getElementById('vault-bulk-modal').style.cssText = 'display:none!important'; }

  function previewVaultBulk() {
    var lines = document.getElementById('vault-bulk-input').value.split('\n').filter(function(l){ return l.trim(); });
    _vaultBulkParsed = [];
    var errors = [];
    var preview = document.getElementById('vault-bulk-preview');
    var errorEl = document.getElementById('vault-bulk-error');

    lines.forEach(function(line, i) {
      var parts = line.split('|').map(function(s){ return s.trim(); });
      if (parts.length < 2 || !parts[0] || !parts[1]) {
        errors.push((i+1) + '번째 줄: 영어와 한국어는 필수입니다');
        return;
      }
      var cat = (parts[2]||'work').toLowerCase();
      if (VALID_CATS.indexOf(cat) < 0) cat = 'work';
      _vaultBulkParsed.push({ english: parts[0], korean: parts[1], category: cat, context: parts[3]||'' });
    });

    if (errors.length) {
      errorEl.textContent = errors.join('\n');
      errorEl.style.display = 'block';
    } else { errorEl.style.display = 'none'; }

    if (_vaultBulkParsed.length) {
      var catStyle = VAULT_CAT_STYLE;
      preview.innerHTML = _vaultBulkParsed.map(function(d, i) {
        var cs = catStyle[d.category] || catStyle.work;
        return '<div class="p-3 rounded-xl bg-[#f3f4f5] flex items-start gap-3"><span class="text-xs font-bold text-[var(--lavender-deep)] shrink-0 mt-0.5">' + (i+1) + '</span><div class="flex-1 min-w-0"><span class="inline-block px-2 py-0.5 rounded text-[9px] font-bold uppercase mb-1" style="' + cs + '">' + d.category + '</span><p class="text-sm font-bold text-[#191c1d] truncate">' + d.english + '</p><p class="text-xs text-[#494454]">' + d.korean + '</p>' + (d.context ? '<p class="text-[10px] text-[#494454]/60 mt-1">' + d.context + '</p>' : '') + '</div></div>';
      }).join('');
      preview.style.display = 'block';
    }
  }

  async function saveVaultBulk() {
    if (!_vaultBulkParsed.length) { previewVaultBulk(); if (!_vaultBulkParsed.length) return; }
    var now = Date.now();
    for (var i = 0; i < _vaultBulkParsed.length; i++) {
      var d = _vaultBulkParsed[i];
      d.createdAt = new Date(now + i * 100).toISOString();
      d.updatedAt = d.createdAt;
      await fbAdd('vaultExpressions', d);
    }
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> ' + _vaultBulkParsed.length + '개 표현이 저장되었어요');
    closeVaultBulkModal();
    await loadVault();
  }

