  async function saveVaultAiResults() {
    var toSave = _vaultAiResults.filter(function(r){ return r._checked; });
    if (!toSave.length) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 저장할 표현을 선택해주세요'); return; }
    var now = Date.now();
    for (var i = 0; i < toSave.length; i++) {
      var d = { english: toSave[i].english, korean: toSave[i].korean, category: toSave[i].category || 'work', context: toSave[i].context || '', conversation: toSave[i].conversation || [], createdAt: new Date(now + i * 100).toISOString(), updatedAt: new Date(now + i * 100).toISOString() };
      await fbAdd('vaultExpressions', d);
    }
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> ' + toSave.length + '개 표현이 저장되었어요 ✨');
    closeVaultAiModal();
    await loadVault();
  }

  // ===== 전역 검색 =====
  var _searchTimeout = null;
  var _searchInput = null;
  var _searchResults = null;

  document.addEventListener('DOMContentLoaded', function() {
    _searchInput = document.getElementById('global-search-input');
    _searchResults = document.getElementById('global-search-results');
    if (!_searchInput) return;

    _searchInput.addEventListener('input', function() {
      clearTimeout(_searchTimeout);
      var q = this.value.trim().toLowerCase();
      if (q.length < 2) { _searchResults.style.display = 'none'; return; }
      _searchTimeout = setTimeout(function(){ performSearch(q); }, 200);
    });
    _searchInput.addEventListener('focus', function() {
      if (this.value.trim().length >= 2) performSearch(this.value.trim().toLowerCase());
    });
    document.addEventListener('click', function(e) {
      if (!e.target.closest('#global-search-input') && !e.target.closest('#global-search-results')) {
        if (_searchResults) _searchResults.style.display = 'none';
      }
    });
    document.addEventListener('keydown', function(e) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); _searchInput.focus(); _searchInput.select(); }
      if (e.key === 'Escape' && _searchResults) _searchResults.style.display = 'none';
    });
  });

  function performSearch(q) {
    var results = [];
    // 여행
    if (typeof tripsData !== 'undefined') tripsData.forEach(function(t) {
      if ((t.name||'').toLowerCase().indexOf(q) >= 0) results.push({cat:'여행',icon:'explore',title:t.name,sub:t.start_date||'',page:'journey'});
    });
    // 도시
    if (typeof citiesData !== 'undefined') citiesData.forEach(function(c) {
      if ((c.name||'').toLowerCase().indexOf(q) >= 0) results.push({cat:'도시',icon:'location_city',title:c.name,sub:c.start_date||'',page:'journey'});
    });
    // 여행 일정 (항공편/숙소/이동수단/기념품)
    if (typeof journeyData !== 'undefined') journeyData.forEach(function(j) {
      var text = ((j.title||'')+(j.description||'')+(j.city||'')).toLowerCase();
      if (text.indexOf(q) >= 0) results.push({cat:j.type||'여행',icon:j.type==='항공편'?'flight':j.type==='숙소'?'hotel':j.type==='이동수단'?'commute':'card_giftcard',title:j.title||j.description||'',sub:j.date||'',page:'journey'});
    });
    // 영어 수업
    if (typeof engSessionsData !== 'undefined') engSessionsData.forEach(function(s) {
      var text = ((s.title||'')+(s.subtitle||'')).toLowerCase();
      if (text.indexOf(q) >= 0) results.push({cat:'영어 수업',icon:'school',title:s.title,sub:s._id,page:'english'});
      // 표현 검색
      (s.expressions||[]).forEach(function(ex) {
        if (((ex.expr||'')+(ex.kr||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'영어 표현',icon:'chat',title:ex.expr,sub:ex.kr,page:'english'});
      });
      // 어휘 검색
      (s.vocabSets||[]).forEach(function(vs) { (vs.words||[]).forEach(function(w) {
        if (((w.word||'')+(w.mean||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'어휘',icon:'translate',title:w.word,sub:w.mean,page:'english'});
      }); });
    });
    // 현금 흐름
    if (typeof hubData !== 'undefined') hubData.forEach(function(r) {
      if (((r[2]||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'현금 흐름',icon:'payments',title:r[2],sub:r[0]||'',page:'finance-hub'});
    });
    // 캘린더
    if (typeof plannerData !== 'undefined') plannerData.forEach(function(r) {
      if (((r[1]||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'캘린더',icon:'event',title:r[1],sub:r[0]||'',page:'planner'});
    });

    // 50개 제한
    var limited = results.slice(0, 50);
    renderSearchResults(limited, results.length);
  }

  function renderSearchResults(results, totalCount) {
    if (results.length === 0) {
      _searchResults.innerHTML = '<div class="p-4 text-center text-sm text-slate-400">검색 결과가 없습니다</div>';
      _searchResults.style.display = 'block';
      return;
    }
    // 카테고리별 그룹화
    var groups = {};
    results.forEach(function(r) { if (!groups[r.cat]) groups[r.cat] = []; groups[r.cat].push(r); });
    var html = '';
    Object.keys(groups).forEach(function(cat) {
      html += '<div class="px-4 py-1.5 text-[9px] font-bold uppercase tracking-widest text-slate-400 bg-slate-50">' + cat + ' (' + groups[cat].length + ')</div>';
      groups[cat].forEach(function(r) {
        html += '<button onclick="searchNavigate(\'' + r.page + '\');document.getElementById(\'global-search-results\').style.display=\'none\';document.getElementById(\'global-search-input\').value=\'\';" class="w-full text-left px-4 py-2.5 flex items-center gap-3 hover:bg-indigo-50 transition-colors">' +
          '<span class="material-symbols-outlined text-indigo-400" style="font-size: var(--font-size-h2)">' + r.icon + '</span>' +
          '<div class="min-w-0 flex-1"><p class="text-sm font-medium text-slate-800 truncate">' + r.title + '</p><p class="text-[10px] text-slate-400 truncate">' + r.sub + '</p></div>' +
          '<span class="text-[9px] text-slate-300">' + r.page + '</span></button>';
      });
    });
    if (totalCount > 50) html += '<div class="px-4 py-2 text-center text-xs text-slate-400">외 ' + (totalCount - 50) + '개 더...</div>';
    _searchResults.innerHTML = html;
    _searchResults.style.display = 'block';
  }

  function searchNavigate(pageId) { navigate(pageId); }

